   ingredienti:[{nome:'Farina 00',qt:'280'},{nome:'Patate',qt:'200'},{nome:'Mozzarella',qt:'120'},{nome:'Rosmarino',qt:'5'},{nome:'Olio extra vergine di oliva',qt:'20'},{nome:'Lievito di birra fresco',qt:'5'}],
