ingredienti:[{nome:'Uova',qt:'4'},{nome:'Burro',qt:'20g'},{nome:'Prezzemolo',qt:'q.b.'},{nome:'Erba cipollina',qt:'q.b.'},{nome:'Dragoncello',qt:'q.b.'},{nome:'Sale e pepe',qt:'q.b.'}],
