ingredienti:[{nome:'Fagioli cannellini secchi',qt:'400g'},{nome:'Salsa di pomodoro',qt:'300ml'},{nome:'Aglio',qt:'3 spicchi'},{nome:'Salvia fresca',qt:'6 foglie'},{nome:'Olio extravergine',qt:'4 cucchiai'}],
