const PATOLOGIE_CUSTOM = [];
function getAllPatologie(){return [...PATOLOGIE_BASE,...PATOLOGIE_CUSTOM];}

const PATOLOGIE_EN = {"diabete":{"nome":"Type 2 Diabetes Mellitus","desc":"Low GI, rich in fiber, unsaturated fats. Blood glucose and body weight control.","note":"ESPEN 2023 · CHO 45-60% (low GI), fiber ≥25g/day, protein 1.0-1.2g/kg/day, saturated fat <10% of total energy. Monitor HbA1c."},"irc":{"nome":"Chronic Kidney Disease (stage 3-4)","desc":"Reduced protein (0.6-0.8g/kg), phosphorus <800mg, potassium <2000mg, sodium <2g/day.","note":"ESPEN 2021 · Protein 0.6-0.8g/kg/day · Phosphorus <800mg/day · Potassium <2000mg/day · Sodium <2g/day · Vegetable leaching (boil in plenty of water and drain)."},"dialisi":{"nome":"Dialysis (Hemodialysis / Peritoneal)","desc":"Increased protein to compensate for dialysis losses. Phosphorus <800mg, potassium <2000mg, controlled fluids.","note":"ESPEN 2021 · Protein 1.2-1.4g/kg/day · Energy 30-35 kcal/kg/day · K <2000mg/day · P <800mg/day · Fluids 500ml + residual diuresis."},"obesita":{"nome":"Obesity / Overweight","desc":"Moderate caloric deficit (-500/750 kcal), high nutrient density, increased protein.","note":"ESPEN 2022 · Deficit 500-750 kcal/day · Protein 1.2-1.5g/kg ideal weight/day · Fiber ≥30g/day · Limit simple sugars and saturated fats."},"dislipidemia":{"nome":"Dyslipidemia","desc":"Reduction of saturated fat and cholesterol. Omega-3, soluble fiber, phytosterols.","note":"ESC/EAS 2019 · Saturated fat <7% energy · Dietary cholesterol <200mg/day · Omega-3 ≥2g/day · Soluble fiber ≥10g/day · Phytosterols 2g/day."},"ipertensione":{"nome":"Arterial Hypertension","desc":"DASH-Mediterranean. Sodium <2g/day, rich in K, Ca, Mg. No added salt, no cured meats.","note":"ESH 2023 + DASH · Sodium <2g/day · Potassium ≥3.5g/day · Calcium ≥1000mg/day · Magnesium ≥300mg/day · Strictly avoid cured meats, canned foods, aged cheeses."},"celiachia":{"nome":"Celiac Disease / Gluten-Free","desc":"Completely gluten-free. Watch for cross-contamination. Replenish Fe, Ca, folate.","note":"AIC/ESPEN · Strict lifelong GF diet · Monitor Fe, Ca, folate, B12, vitamin D · Avoid cross-contamination · Prefer naturally GF grains."},"ibd":{"nome":"IBD - Crohn's / UC (remission)","desc":"Anti-inflammatory, easily digestible. Adapted to the remission phase.","note":"ECCO-ESPEN 2023 · In remission: low-residue Mediterranean diet · Omega-3 beneficial · Avoid pro-inflammatory foods · In flare-up: exclusive enteral nutrition."},"sarcopenia":{"nome":"Sarcopenia / Frail Elderly","desc":"High protein intake to prevent sarcopenia. Leucine, vitamin D, omega-3.","note":"ESPEN 2018 · Protein ≥1.2-1.5g/kg/day · Leucine ≥3g/meal · Vitamin D 800-1000 IU/day · Omega-3 · Resistance physical activity recommended."},"steatosi":{"nome":"Hepatic Steatosis (NAFLD/MASLD)","desc":"Moderate caloric restriction, elimination of fructose and alcohol, Mediterranean diet.","note":"EASL 2024 · Weight reduction 7-10% if overweight · Eliminate alcohol and added fructose · Mediterranean diet · Omega-3 EPA/DHA 2-4g/day · Vitamin E 800 IU/day (selected cases) · Caffeine allowed."},"cirrosi":{"nome":"Liver Cirrhosis","desc":"Increased energy intake, protein not restricted. Small frequent meals. Evening snack.","note":"EASL/ESPEN 2019 · Energy 35-40 kcal/kg/day · Protein 1.2-1.5g/kg/day (do not restrict) · 4-6 meals/day · CHO-based evening snack (50g CHO) · Na <2g/day if ascites · BCAA if encephalopathy."},"bpco":{"nome":"COPD (Chronic Obstructive Pulmonary Disease)","desc":"High caloric intake, limit excess CHO (increases CO2). Fats as energy source.","note":"ESPEN 2021 · Energy 30-40 kcal/kg/day · Protein 1.2-1.5g/kg/day · CHO not >50% to limit CO2 production · Fat 35-45% · Small, frequent meals · Vitamin D, calcium."},"calcolosi":{"nome":"Renal Stones (Calcium Oxalate)","desc":"Abundant hydration, adequate calcium, reduce oxalates, salt and animal protein.","note":"EAU 2022 · Fluids ≥2.5L/day (diuresis >2L) · Calcium 1000-1200mg/day (do not reduce) · Sodium <5g NaCl/day · Limited oxalates · Animal protein <0.8g/kg/day · Vitamin C <1000mg/day."},"gotta":{"nome":"Hyperuricemia / Gout","desc":"Reduced purines, zero alcohol, abundant hydration, fructose control.","note":"ACR/EULAR 2020 · Avoid red meat, organ meats, fatty fish, alcohol (especially beer) · Limit fructose · Low-fat dairy protective · Hydration ≥2L/day · Vitamin C useful."},"anemia":{"nome":"Iron-Deficiency Anemia","desc":"Heme and non-heme iron, vitamin C for absorption, avoid iron inhibitors with meals.","note":"WHO/LARN 2022 · Heme iron (meat) + non-heme (legumes, vegetables) · Vitamin C with meals increases absorption · Avoid tea/coffee/calcium with main meals · Adequate folate and B12."},"oncologia":{"nome":"Oncology / Cancer Cachexia","desc":"Prevent cachexia: high protein and caloric intake, omega-3, adapted nutrition.","note":"ESPEN 2021 · Energy 25-30 kcal/kg/day (cachexia: 30-35) · Protein 1.2-2.0g/kg/day · Omega-3 EPA 2g/day · Early nutritional support · ONS if intake <60% for >1 week."},"osteoporosi":{"nome":"Osteoporosis","desc":"Calcium, vitamin D, adequate protein. Limit alcohol, salt, excess caffeine.","note":"IOF 2021 · Calcium 1000-1200mg/day · Vitamin D 800-2000 IU/day · Protein 1.0-1.2g/kg/day · Limit alcohol and sodium · Vitamin K2 90-120µg/day · Weight-bearing physical activity."},"scompenso":{"nome":"Heart Failure","desc":"Sodium <2g/day, controlled fluids, small frequent meals. No added salt.","note":"ESC 2021 · Sodium <2g/day · Fluids 1.5-2L/day if edema · Energy 25-30 kcal/kg/day · Monitor K with diuretics · Daily weight."},"pancreatite":{"nome":"Chronic Pancreatitis","desc":"Limited fat, small frequent meals, no alcohol, pancreatic enzymes if insufficiency.","note":"AGA/ESPEN 2020 · Fat <40g/day in acute phase (then liberalize) · Zero alcohol · 5-6 small meals/day · If steatorrhea: pancreatic enzymes · Monitor vitamin D, B12, zinc."},"gravidanza":{"nome":"Pregnancy (2nd-3rd trimester)","desc":"Increased energy, folate, iron, calcium, iodine, DHA requirements.","note":"LARN 2023 · +350 kcal/day (2nd trim) / +460 kcal/day (3rd trim) · Folate 600µg/day · Iron 27mg/day · Calcium 1000mg/day · DHA 200mg/day extra · Iodine 220µg/day · Avoid risk foods."},"allattamento":{"nome":"Breastfeeding","desc":"Increased caloric needs, DHA, calcium, vitamin D, abundant hydration.","note":"LARN 2023 · +500 kcal/day · DHA 200mg/day extra · Calcium 1000mg/day · Vitamin D 1500 IU/day · Iodine 290µg/day · Fluids ≥2L/day · Limit caffeine <200mg/day."},"fenilchetonuria":{"nome":"Phenylketonuria (PKU)","desc":"Phenylalanine restriction. Very limited natural protein foods. Amino acid supplements without Phe.","note":"ACMG 2014 · Phenylalanine <300mg/day from natural foods · Phe-free amino acid supplements mandatory · Tyrosine supplemented · Monitor vitamin B12, D, selenium, zinc."},"hiv":{"nome":"HIV/AIDS","desc":"Prevent malnutrition and lean mass loss. Watch for drug-nutrient interactions.","note":"WHO/ESPEN · Energy 30-35 kcal/kg/day · Protein 1.2-1.5g/kg/day · Zinc, selenium, vitamin D, B12 · Watch antiretroviral interactions · Lipodystrophy: limit saturated fats."},"gastrectomia":{"nome":"Gastrectomy (partial/total)","desc":"Small frequent meals (6-8/day). Dumping syndrome: avoid simple sugars with meals.","note":"ESPEN 2021 · Split into 6-8 meals/day · Avoid fluids during meals · Supplement: parenteral B12, Fe, Ca, vitamin D, folate · Risk of dumping syndrome."},"diverticolite":{"nome":"Diverticulitis/Diverticulosis","desc":"Acute phase: liquid or low-residue diet. In remission: abundant fiber (25-35g/day).","note":"ACG 2015 · Acute phase: liquid or semi-liquid diet · Remission: fiber ≥25-35g/day · Nuts and seeds NOT contraindicated in remission (myth debunked) · Abundant hydration."},"chirurgia_bariatrica":{"nome":"Bariatric Surgery (bypass/sleeve)","desc":"Post-op: diet progression liquid → blended → soft → solid. Lifelong supplementation.","note":"IFSO 2022 · Phase 1 (0-2 wk): clear liquids · Phase 2 (2-4 wk): protein liquids · Phase 3 (1-3 months): blended/puréed · Phase 4 (3+ months): soft solids · Lifelong supplements: MVM, Fe, citrate Ca, B12, vitamin D."},"disfagia":{"nome":"Dysphagia (swallowing disorder)","desc":"Dietary therapy based on IDDSI levels (0-7). Modified texture: purée, blended, smooth.","note":"IDDSI 2019 · Classification: 0 (thin liquid) → 7 (regular solid) · Texture-modified diet · Avoid slippery, sticky, mixed-consistency foods · Thickeners if needed · Aspiration risk."},"malnutrizione":{"nome":"Undernutrition (Malnutrition by Deficiency)","desc":"High energy and protein content. ONS if intake insufficient. Refeeding syndrome: caution.","note":"ESPEN 2022 · Energy: 30-35 kcal/kg/day · Protein: 1.5-2.0g/kg/day · Watch for refeeding syndrome (hypophosphatemia) · ONS 2-3/day if needed · Monitor electrolytes."},"neoplasia":{"nome":"Neoplasms / Oncology Therapy","desc":"Prevent cachexia. Energy 25-35 kcal/kg, protein 1.2-1.5g/kg. Early ONS. Omega-3 EPA.","note":"ESPEN 2021 · Energy 25-35 kcal/kg/day · Protein 1.2-1.5g/kg/day (cachexia 2.0) · EPA 2g/day · ONS if intake <60% requirement for >1 week · Perioperative immunonutrition."},"allergia_latte":{"nome":"Cow's Milk Protein Allergy (CMPA)","desc":"Total elimination of milk and dairy. Replace calcium with fortified plant-based alternatives.","note":"EAACI 2019 · Eliminate casein, whey proteins, lactalbumin, lactoglobulin · Calcium target 1000-1200mg/day from alternative sources · Vitamin D 800-2000 IU/day · Lactose-free does not mean CMPA-free."},"ibs":{"nome":"Irritable Bowel Syndrome (IBS)","desc":"Low-FODMAP diet during symptomatic phases. Gradual reintroduction. Soluble fiber recommended.","note":"ACG 2021 · Low-FODMAP diet reduces symptoms in 70% of patients · Elimination phase 4-6 weeks · Gradual reintroduction to identify triggers · Psyllium useful for IBS-C."},"sindrome_metabolica":{"nome":"Metabolic Syndrome","desc":"Mediterranean diet + caloric deficit. 5-10% weight reduction. Physical exercise essential.","note":"IDF/AHA 2009 · Criteria: abdominal obesity + 2 of: glucose ≥100, TG ≥150, low HDL, BP ≥130/85 · Goal: -500 kcal/day, physical activity 150 min/week · Mediterranean pattern (PREDIMED)."},"pcos":{"nome":"Polycystic Ovary Syndrome (PCOS)","desc":"Low GI diet, reduction of insulin resistance. 5-10% weight loss improves hormonal symptoms.","note":"ESHRE 2023 · Insulin resistance present in 70-80% · Low GI + anti-inflammatory diet · Omega-3 useful · Myo-inositol 2g + D-chiro-inositol 200mg · Physical activity 150-300 min/week."},"hashimoto":{"nome":"Hashimoto's Thyroiditis / Hypothyroidism","desc":"Anti-inflammatory diet. Selenium and vitamin D important. Screening for associated celiac disease.","note":"ETA 2022 · Association with celiac disease (mandatory screening) · Selenium 55-200µg/day · Vitamin D target >40 ng/mL · Levothyroxine on an empty stomach 30-60 min before breakfast · Soy and calcium spaced 4h from the medication."},"ipe":{"nome":"Exocrine Pancreatic Insufficiency (EPI)","desc":"Small frequent meals, reduced fat. Mandatory PERT with every meal. Absolute no alcohol.","note":"UEG 2022 · PERT (Creon): 40,000-80,000 IU lipase per main meal, 20,000-40,000 per snack · Fat <40g/day if PERT inadequate · Supplement fat-soluble vitamins A,D,E,K · Absolute no alcohol."},"ictus":{"nome":"Post-Stroke / Neurological Rehabilitation","desc":"Prevent dysphagia and post-stroke malnutrition. Mediterranean pattern for recurrence prevention.","note":"ESPEN 2021 · Always assess swallowing · IDDSI-adapted texture if dysphagia · Energy 25-30 kcal/kg/day · Protein 1.2-1.5g/kg/day · Omega-3 (EPA+DHA) 1-2g/day · DASH/Mediterranean for recurrence prevention."},"gerd":{"nome":"GERD / Gastroesophageal Reflux","desc":"Anti-reflux diet: small frequent meals, avoid trigger foods. Weight loss if overweight.","note":"ACG 2022 · Avoid: chocolate, mint, alcohol, coffee, fatty foods, citrus, tomato, spicy foods · Small frequent meals (4-5/day) · Dinner at least 3h before bedtime · Raise head of bed 15-20cm · 10% weight loss significantly reduces symptoms."},"gastrite":{"nome":"Chronic Gastritis / Peptic Ulcer","desc":"Light diet, regular meals, avoid gastric irritants. H. pylori eradication if indicated.","note":"WCOG 2020 · Avoid: NSAIDs, alcohol, smoking, spicy foods, acidic foods · Regular meals (don't skip) · Cooking method: steaming, boiling, grilling (no frying) · Probiotics may support H. pylori eradication · Vitamin B12 if atrophic gastritis."},"stipsi":{"nome":"Chronic Functional Constipation","desc":"Increase fiber and hydration. Regular meal timing. Daily physical activity.","note":"ACG 2021 · Fiber ≥25-35g/day (gradual increase) · Water ≥1.5-2L/day · Probiotics (Lactobacillus, Bifidobacterium): moderate evidence · Prunes/aloe vera: possible benefit · Avoid very low-fiber diets."},"intolleranza_lattosio":{"nome":"Lactose Intolerance","desc":"Reduction/elimination of lactose. Many tolerate small amounts. Watch calcium intake.","note":"WGO 2013 · Individual threshold varies (many tolerate 12g/meal) · Aged cheeses (Parmigiano, Grana, Pecorino) practically lactose-free · Fermented yogurt better tolerated · Lactase enzyme available · Calcium: 1000-1200mg/day from alternative sources or supplements."},"artrite_reumatoide":{"nome":"Rheumatoid Arthritis","desc":"Mediterranean anti-inflammatory diet. Omega-3 useful. Weight management to reduce joint load.","note":"EULAR 2022 · Omega-3 (EPA+DHA) 2-3g/day (anti-inflammatory action) · Vitamin D: target >40 ng/mL · Mediterranean diet reduces DAS28 · Avoid overweight (worsens joint load) · Adequate folate if MTX · Natural anti-inflammatories: turmeric, ginger."},"fibromialgia":{"nome":"Fibromyalgia","desc":"Anti-inflammatory diet, attention to food sensitivity. Vitamin D and magnesium important.","note":"EULAR 2023 · No specific validated diet exists · Anti-inflammatory/Mediterranean diet: possible benefit · Vitamin D (frequent deficiency): target >40 ng/mL · Magnesium 300-400mg/day · Avoid excitotoxins (glutamate, aspartame in some cases) · Non-celiac gluten sensitivity: 3-month trial."},"parkinson":{"nome":"Parkinson's Disease","desc":"Manage dysphagia if present. Levodopa: watch protein at main meals. Constipation frequent.","note":"ESPEN 2021 · Levodopa: reduce protein at breakfast and lunch (consume during active hours) · Concentrated protein in the evening if needed · Constipation: fiber ≥30g/day, hydration ≥2L/day · Texture modification if dysphagia · Vitamin D and B12 · Antioxidants: colorful fruit and vegetables."},"ipertiroidismo":{"nome":"Hyperthyroidism","desc":"High caloric and protein needs. Calcium and vitamin D to prevent osteoporosis. Moderate iodine.","note":"ETA 2023 · Energy increased by 20-30% (increased basal metabolism) · Protein 1.2-1.5g/kg/day (increased catabolism) · Calcium 1000-1200mg/day and vitamin D ≥1000 IU/day (osteoporosis risk) · Iodine: do not exceed (may worsen hyperthyroidism) · Selenium 200µg/day (useful in Graves' disease) · Caffeine: limit (may exacerbate tachycardia)."},"anoressia":{"nome":"Anorexia Nervosa","desc":"Gradual, controlled renourishment. Refeeding syndrome: monitor phosphorus, potassium, magnesium. Multidisciplinary team.","note":"ESPEN 2022 · Refeeding syndrome: risk with initial intake >10 kcal/kg/day → start at 5-10 kcal/kg and increase gradually · Phosphorus, potassium, magnesium: supplement prophylactically · Thiamine (B1) before starting renourishment · Target caloric intake: 30-40 kcal/kg/day (individualized) · Frequent laboratory monitoring · Multidisciplinary treatment mandatory."},"bulimia":{"nome":"Bulimia Nervosa","desc":"Regularize meals, avoid excessive restriction. Replenish electrolytes if frequent vomiting. Psychological therapy.","note":"ESPEN 2022 · Regular meals (3 meals + 2-3 snacks) to reduce binges · Avoid restrictive diets (binge triggers) · If vomiting: hypokalemia, dental erosion (acids), esophageal damage · Supplement potassium, magnesium if deficient · Intuitive eating supported · Multidisciplinary team essential."},"bed":{"nome":"Binge Eating Disorder (BED)","desc":"Regularize meals, avoid restriction. Mindful eating. Cognitive-behavioral therapy.","note":"DSM-5/ESPEN 2022 · Recurrent binges without compensatory behaviors · Regular, structured meals reduce binges · Avoid very restrictive diets (triggers) · Mindful eating: eat slowly, without distractions · Behavior-based rather than weight-based approach · Psychotherapy (CBT) is the cornerstone."},"lupus":{"nome":"Systemic Lupus Erythematosus (SLE)","desc":"Mediterranean anti-inflammatory diet. Vitamin D essential. Watch photosensitivity (reduced vitamin D).","note":"EULAR 2023 · Vitamin D: often deficient due to photoprotection and corticosteroids · Omega-3 2-3g/day (immunomodulatory effect) · Mediterranean diet reduces disease activity · Corticosteroids: monitor glucose, blood pressure, weight · Associated lupus nephritis: sodium and protein restriction if needed · Calcium to prevent corticosteroid-induced osteoporosis."},"allergia_uova":{"nome":"Egg Allergy","desc":"Complete elimination of eggs and derivatives. Watch food labels and baked goods.","note":"EAACI 2019 · Eliminate whole eggs, egg white, yolk and all derivatives · Read labels: ovalbumin, lysozyme, mayonnaise, lecithin (egg-derived) · Cross-reactivity with bird feathers rare · Alternative sources of complete protein · Vitamin D and B12 if restrictive diet · Auto-injectable epinephrine if anaphylaxis."},"stomia":{"nome":"Stoma (Colostomy / Ileostomy)","desc":"Individualized diet by stoma type. Ileostomy: initially low-residue, high hydration. Colostomy: progressive normalization.","note":"ESPEN 2021 · Ileostomy: water losses 1-2L/day and sodium → hydration ≥2.5L/day · Risk of B12 deficiency if ileal resection · Avoid high-residue foods initially · Odor/gas-causing foods: identify individually · Increased protein for wound healing."},"tumore_seno":{"nome":"Breast Cancer (Breast Carcinoma)","desc":"Anti-inflammatory diet and optimal weight maintenance. Zero alcohol. Soy phytoestrogens not contraindicated. Omega-3 and vitamin D.","note":"ESPEN 2021 · BMI 20-25 goal (overweight increases recurrence risk by 30-40%) · Alcohol: independent risk factor → zero · Dietary soy phytoestrogens: not contraindicated (2019 meta-analysis) · Omega-3 EPA/DHA 2g/day · Vitamin D target >40 ng/mL · Fiber ≥25g/day."},"tumore_pancreas":{"nome":"Pancreatic Cancer","desc":"High cachexia risk. Mandatory PERT with every meal. Secondary pancreatic diabetes frequent. High caloric and protein density. No alcohol.","note":"ESPEN 2021 · Cachexia in 80% of patients · PERT (Creon) 40,000-80,000 IU lipase per main meal · Type 3c diabetes: monitor glucose · Omega-3 EPA 2g/day anti-cachexia · High-protein ONS if intake <60% · Absolute no alcohol."},"tumore_colon":{"nome":"Colorectal Cancer","desc":"Preoperative immunonutrition. Early post-surgical refeeding. High-fiber diet in maintenance. No processed meats.","note":"ESPEN 2021 · Pre-op immunonutrition (arginine 15-20g + EPA + nucleotides) 5-7 days · Early oral refeeding (within 4h post-op) · Fiber ≥25-30g/day in maintenance · Processed meats: IARC Group 1 carcinogen · Alcohol: risk factor."},"diverticolosi":{"nome":"Diverticulosis","desc":"High-fiber diet (≥25-35g/day). Opposite of acute diverticulitis. Abundant hydration. Nuts and seeds not contraindicated (myth debunked).","note":"ACG 2015 · Fiber ≥25-35g/day prevents progression and complications · Hydration ≥1.5-2L/day · Nuts and seeds not contraindicated (negative RCTs: Health Professionals Follow-up Study) · Physical activity recommended · Avoid chronic constipation."},"allergia_pesce":{"nome":"Fish Allergy","desc":"Total elimination of fish and derivatives. Omega-3 from plant sources (flaxseed, walnuts) or algae. Always read labels.","note":"EAACI 2019 · Eliminate all fish (high cross-reactivity: parvalbumin conserved across species) · Also avoid: fish oil, fish collagen, fish gelatin · Omega-3 ALA from: flaxseed, walnuts, chia seeds · EPA/DHA from microalgae · Iodine from: iodized salt."},"allergia_molluschi":{"nome":"Shellfish and Mollusk Allergy","desc":"Elimination of crustaceans (shrimp, crab, lobster) and mollusks (mussels, clams, squid). Fish is generally tolerated. Watch for cross-contamination.","note":"EAACI 2019 · Crustaceans: tropomyosin (different from fish parvalbumin) · Very high cross-reactivity between crustaceans · 40-50% co-allergy with mollusks · Fish: different protein, generally tolerated · Glucosamine from shrimp/crab: check supplement source."},"allergia_frutta_secca":{"nome":"Tree Nut Allergy","desc":"Elimination of all tree nuts. High anaphylaxis risk. High cross-reactivity between species. Omega-3 from fish and seeds (flax, chia).","note":"EAACI 2019 · Tree nuts: almonds, walnuts, hazelnuts, pistachios, cashews, pine nuts, macadamia nuts, pecans, Brazil nuts · High cross-reactivity between different nuts · Peanuts = legume (40-60% co-allergy) · Sesame seeds: separate but common allergy · Always carry auto-injectable epinephrine."},"fibrosi_cistica":{"nome":"Cystic Fibrosis","desc":"Very high energy requirement (110-200% of normal). PERT mandatory. Fat-soluble vitamin supplementation.","note":"ECFS 2016 · Energy 110-200% of normal requirement (malabsorption + work of breathing) · Protein 1.5-2.0 g/kg/day · PERT with every meal and snack · Vitamins A, D, E, K · Extra sodium in summer and during physical activity · CF-related diabetes (CFRD): monitor blood glucose."},"epilessia":{"nome":"Epilepsy / Ketogenic Diet","desc":"High-fat, low-carbohydrate ketogenic diet. Ratio 3:1-4:1 fat:(protein+CHO).","note":"ILAE 2008 · ESPEN 2021 · Indicated in drug-resistant epilepsy · Ratio 3:1-4:1 (classic) · Modified Atkins Diet as a more flexible alternative · CHO <20g/day · Adequate protein (1.0-1.2 g/kg/day) · Monitor: growth, bone density, lipids, renal function."},"alzheimer":{"nome":"Alzheimer's Disease / Dementia","desc":"Prevent malnutrition. Mediterranean / MIND diet. Adapt texture if dysphagia. Early nutritional support.","note":"ESPEN 2023 · High risk of malnutrition (forgetfulness, dysphagia, anorexia) · Vitamin B12, folate, vitamin D, omega-3 · MIND diet (Mediterranean + DASH) reduces cognitive decline · Small frequent appetizing meals · IDDSI-adapted texture if dysphagia · ONS if intake <75% for >1 week."},"gastroparesi":{"nome":"Gastroparesis","desc":"Small, frequent meals. Reduced fat and reduced fiber. Prefer soft and liquid foods. Avoid high-residue foods.","note":"ADA/ACG 2022 · Fat <40g/day · Fiber <10g/day · 6-8 small frequent meals · Consistency: liquid/soft/minced · Glycemic control if associated diabetes · Chew thoroughly · Do not lie down within 2h of eating · Caloric liquids if solids not tolerated."},"sla":{"nome":"Amyotrophic Lateral Sclerosis (ALS)","desc":"Increased energy requirement. Prevention of malnutrition. Dysphagia management. Preventive PEG if needed.","note":"ESPEN 2023 · Energy 30-40 kcal/kg/day (hypermetabolism + amyotrophy) · Protein 1.5-2.0 g/kg/day · Assess dysphagia regularly (IDDSI) · Early PEG when FVC >50% and weight declining · Omega-3 2g/day · Vitamin D · Monitor weight every 2-4 weeks · Specialized nutritional support mandatory."},"6fed":{"nome":"Six Food Elimination Diet – 6FED (EoE)","desc":"Elimination of 6 allergens for Eosinophilic Esophagitis: milk, wheat, eggs, soy, tree nuts, fish/shellfish.","note":"ACG/AGA 2020 · Indicated for Eosinophilic Esophagitis (EoE) · Eliminates the 6 main triggers: milk/dairy, wheat/gluten, eggs, soy, tree nuts/peanuts, fish/seafood · Sequential reintroduction (one food at a time) with follow-up EGD every 6-8 weeks per category · Supplement: calcium 1000-1200mg/day, vitamin D, B12, algae-based omega-3 · Elimination phase duration: 6 weeks."},"4fed":{"nome":"Four Food Elimination Diet – 4FED (EoE)","desc":"Elimination of 4 main allergens for EoE: milk, wheat, eggs, soy. Better adherence than 6FED.","note":"ACG/AGA 2020 · Indicated for Eosinophilic Esophagitis (EoE) · Eliminates the 4 most frequent triggers: milk/dairy, wheat/gluten, eggs, soy · Efficacy ~54-64% histologic remission with better compliance than 6FED · Sequential reintroduction with follow-up EGD every 6-8 weeks · Monitor calcium, vitamin D and protein adequacy."},"cded_fase1":{"nome":"CDED Phase 1 – Weeks 1-6 (50% PEN)","desc":"CDED Phase 1 (wk 1-6): allowed foods + 50% of caloric requirement from polymeric enteral formula (Modulen IBD or equivalent). Schedule for 1800 kcal/day total.","note":"Levine et al. 2019 · ECCO 2022 · Phase 1 (wk 1-6): 50% kcal from PEN (polymeric formula, e.g. Modulen IBD ~900 kcal from ~600 mL) + 50% from solid diet (~900 kcal). Allowed foods: chicken, fish (not canned), eggs, potato, carrot, zucchini, banana, apple, pear, strawberry, rice, rice cakes, extra virgin olive oil, honey. EXCLUDED: red/processed meats, gluten, high-fat dairy, seed oils, emulsifiers (E322/E471), preservatives, UPF. Goal: reduction of pro-inflammatory microbiota and restoration of intestinal barrier."},"cded_fase2":{"nome":"CDED Phase 2 – Weeks 7-12 (25% PEN)","desc":"CDED Phase 2 (wk 7-12): expanded diet + 25% of caloric requirement from polymeric enteral formula. Greater food variety than Phase 1.","note":"Levine et al. 2019 · ECCO 2022 · Phase 2 (wk 7-12): 25% kcal from PEN (polymeric formula ~450 kcal from ~300 mL) + 75% from solid diet (~1350 kcal). Compared to Phase 1, can add: cooked legumes, more fish variety, seasonal fruit, additive-free low-fat yogurt. Still EXCLUDED: red/processed meats, gluten, high-fat dairy, seed oils, emulsifiers, UPF. Continue until clinical and biochemical remission (CRP, fecal calprotectin)."},"cded_mant":{"nome":"CDED Maintenance – Beyond wk 12","desc":"CDED Maintenance (wk 12+): full diet without formula, wide variety of unprocessed foods, sustained exclusion of red/processed meats and UPF.","note":"Levine et al. 2019 · ECCO 2022 · Maintenance phase: full CDED diet without PEN. Progressively add: legumes, tree nuts, partially skimmed milk, additive-free low-fat cheeses, eggs, natural yogurt. Remain EXCLUDED for life: red and processed meats, gluten (from industrial cereals), industrial seed oils, emulsifiers, ultra-processed foods. Periodic monitoring: CRP, fecal calprotectin, ferritin, vitamin D, B12, zinc every 3-6 months."},"scd":{"nome":"SCD – Specific Carbohydrate Diet","desc":"Specific carbohydrate diet for IBD. Eliminates disaccharides and polysaccharides. Allows monosaccharides and fresh unprocessed foods.","note":"CCF 2021 · ECCO 2022 · Used for Crohn's Disease and UC · Eliminates: disaccharides (sucrose, lactose), all grains and starches (wheat, corn, rice, potato) · Allows: fresh meat/fish/eggs, fruit, non-starchy vegetables, honey, tree nuts, legumes (from dried, long-cooked), 24h-fermented yogurt (lactose-free) · Growing evidence especially in pediatric age · Requires specialized nutritional supervision."},"larn_popolazione_sana":{"nome":"Healthy Population — LARN 5th Revision","desc":"Balanced Mediterranean diet for the healthy Italian population. Energy and nutrients per LARN (SINU 5th revision). Primary prevention of chronic degenerative disease.","note":"LARN 2014 (5th Revision) — SINU · Typical adult energy: EAR ~1700-2100 kcal/day (F/M) · Protein 0.9 g/kg/day (adult) · CHO 45-60% kcal · Fat 20-35% kcal · Fiber 25-30 g/day · Salt <5 g/day · Folate 400 µg/day · Vitamin D 15 µg/day · Calcium 1000 mg/day · Iron 10-18 mg/day · Model: Mediterranean Diet."},"diabete_gestazionale":{"nome":"Gestational Diabetes (GDM)","desc":"Glycemic control through carbohydrate distribution, low GI and postprandial monitoring. No simple sugars. Split into 5-6 meals.","note":"ADA 2023 · ACOG 2023 · CHO 40-50% kcal, low GI · No free sugars · 3 meals + 3 snacks · Fasting glucose <95 mg/dL, 1h postprandial <140 mg/dL, 2h <120 mg/dL · Moderate physical activity recommended · Monitor weight gain (11-16 kg if normal weight, 7-11 kg if overweight) · Supplement folate, iron, DHA · Breastfeeding reduces future maternal T2DM risk."},"diabete_t1":{"nome":"Type 1 Diabetes Mellitus","desc":"Carbohydrate counting (CHO counting) to adjust insulin dosing. Flexible diet. Continuous glucose monitoring.","note":"ISPAD 2022 · ADA 2022 · CHO counting: 1 unit rapid insulin per 10-15g CHO (personalized ratio) · Variable insulin sensitivity · Caution with hypoglycemia: correct with 15g rapid CHO · Monitor: HbA1c, TIR (Time in Range >70% target) · Protein snacks before physical activity · No CHO restriction if insulin adequate · Micronutrients: vitamin D, Mg, Zn often deficient."},"menopausa":{"nome":"Menopause / Perimenopause","desc":"Diet high in calcium and vitamin D to prevent osteoporosis. Phytoestrogens (soy, flaxseed). Weight control to reduce symptoms.","note":"IMS 2022 · Calcium 1200 mg/day · Vitamin D 1500-2000 IU/day · Phytoestrogens (soy isoflavones, flaxseed lignans) useful for hot flashes · Limit alcohol, caffeine · Adequate protein (1.0-1.2 g/kg) to preserve muscle mass · Fiber 25-30g/day · Omega-3 for mood and cardiovascular health · Moderate caloric restriction if overweight."},"sibo":{"nome":"SIBO (Small Intestinal Bacterial Overgrowth)","desc":"Low-FODMAP diet during the treatment phase. Reduction of fermentable substrates to limit bacterial growth.","note":"ACG 2020 · WGO 2021 · Low-FODMAP diet in the acute phase (4-6 weeks) · Then gradual reintroduction · Avoid excess fermentable fiber · Probiotics: limited and controversial evidence · Small frequent meals · Avoid alcohol and refined sugars · Monitor: malabsorption of vitamins B12, D, iron, zinc."},"allergia_arachidi":{"nome":"Peanut Allergy","desc":"Complete elimination of peanuts and products containing them. Attention to cross-contamination. Always carry auto-injectable epinephrine (EpiPen).","note":"EAACI 2021 · Most dangerous allergy for anaphylaxis risk · Labels: ALWAYS read (EU Reg. 1169/2011 – mandatory allergen) · Frequent cross-contamination in oil mills, pastry shops, pizzerias · Lupin cross-reactive with peanuts in ~30% of cases · OIT (oral immunotherapy): option at specialized centers · Monitor growth in children."},"allergia_grano":{"nome":"Wheat Allergy (non-celiac)","desc":"Elimination of wheat and its derivatives. Less restrictive than celiac disease (barley and rye tolerated in some). Risk of wheat-dependent exercise-induced anaphylaxis.","note":"EAACI 2021 · Distinguish from celiac disease (autoimmune) and NCWS (sensitivity) · Barley and rye: often tolerated (allergy specific to wheat proteins, not gluten) · WDEIA (Wheat-Dependent Exercise-Induced Anaphylaxis): avoid wheat 4-6h before exercise · Read labels: wheat, spelt, kamut, semolina, wheat starch · EpiPen if history of anaphylaxis."},"allergia_sesamo":{"nome":"Sesame Allergy","desc":"Complete elimination of sesame and its derivatives (tahini, sesame oil, hummus). New mandatory allergen on EU labels since 2023.","note":"EAACI 2023 · EU Regulation 2023: sesame 15th mandatory allergen · Hidden sources: tahini, hummus, sesame oil, halva, hamburger buns, oriental crackers, ethnic breadcrumbs · Frequent cross-contamination in Asian and Middle Eastern kitchens · Moderate anaphylaxis risk · Always read labels on packaged bread and crackers."},"intolleranza_istamina":{"nome":"Histamine Intolerance (HIT)","desc":"Low-histamine diet and DAO inhibitor avoidance. Avoid fermented foods, preserves, alcohol. Identify personal threshold.","note":"EAACI 2020 · Deficiency/reduction of the DAO enzyme (diamine oxidase) · Symptoms: urticaria, headache, GI symptoms, nasal congestion · High-content foods: aged cheeses, wine, beer, vinegar, preserves, tuna, mackerel, cured meats · DAO inhibitors: alcohol, drugs (NSAIDs, metoclopramide, codeine) · DAO supplementation: emerging evidence · Vitamin B6, copper, vitamin C are DAO co-factors."},"intolleranza_nichel":{"nome":"Nickel Intolerance (SNAS)","desc":"Low-nickel diet in Systemic Nickel Allergy Syndrome (SNAS). Food rotation and identification of personal threshold.","note":"SNAS (Systemic Nickel Allergy Syndrome) · EAACI 2022 · High-nickel foods: chocolate, nuts, legumes, whole grains, tomatoes, spinach · Exclusion diet 4-6 weeks then gradual reintroduction · Vitamin C reduces nickel absorption · Cooking in stainless steel reduces release · Morning tap water: let it run · Ceramic or glass pots preferred."},"sindrome_nefrosica":{"nome":"Nephrotic Syndrome","desc":"Moderate-high protein to compensate urinary losses. Sodium greatly reduced to counter edema. Limited saturated fat (associated dyslipidemia).","note":"KDIGO 2021 · Protein 0.8-1.0 g/kg/day (adult, not on dialysis) + compensation for urinary losses · Sodium <1.5 g/day (edema) · Saturated fat <7% (nephrotic hypercholesterolemia) · Omega-3 beneficial · Monitor albumin, cholesterol, triglycerides · Vitamin D often deficient · Calcium 1200 mg/day · Avoid unprescribed supplements · Fluids only if hyponatremia."},"pancreatite_acuta":{"nome":"Acute Pancreatitis","desc":"Early enteral nutrition (within 24-48h) in moderate-severe forms. In mild forms, resume oral feeding as soon as tolerated. Very low-fat diet.","note":"IAP/APA 2020 · ESPEN 2020 · Mild forms: early soft low-residue solid diet (within 24-48h) · Severe forms: early NGT enteral nutrition if oral route not tolerated · PN only if EN not feasible · No prolonged fasting (increases bacterial translocation) · Oral reintroduction: liquids → semi-liquids → soft solids · Fat <30g/day in the initial phase · No alcohol for life if alcoholic pancreatitis."},"trapianto":{"nome":"Post-Organ Transplant","desc":"Food safety is a priority (immunosuppression). Increased protein in the early phase. Limit potassium and phosphorus if reduced renal function. No grapefruit juice.","note":"ESPEN 2019 · Early phase (0-3 months): protein 1.2-1.5 g/kg/day, caloric intake 30-35 kcal/kg/day · Food safety: no raw foods, no unpasteurized soft cheeses, no raw seafood · No grapefruit/grapefruit juice (inhibits CYP3A4 metabolism of immunosuppressants) · Corticosteroids: monitor glucose, osteoporosis (vit D+Ca), sodium · Long term: elevated cardiovascular and metabolic risk · Weight: correct steroid-induced weight gain."},"colite_microscopica":{"nome":"Microscopic Colitis (Collagenous/Lymphocytic)","desc":"Low-residue diet during acute phases. Eliminate caffeine, NSAIDs (if taken), PPIs if not necessary. Often associated with lactose and gluten intolerance.","note":"EMCG 2020 · ACG 2020 · Treatment: budesonide (4-8 weeks) + diet · Triggers to eliminate: NSAIDs, statins (rare), PPIs (frequent), sertraline · Try: gluten-free diet (40-50% benefit), lactose-free · Caffeine: secretory effect → limit · Acute phase: low-residue, semi-liquid diet · Remission: balanced diet with gradual fiber increase · Probiotics: no robust evidence."},"endometriosi":{"nome":"Endometriosis","desc":"Anti-inflammatory diet, rich in omega-3 and fiber. Reduce red meat, saturated fat and alcohol. Probiotics and vitamin D useful.","note":"ASRM 2022 · ESHRE 2022 · Mediterranean diet reduces risk and symptoms · Omega-3 EPA/DHA 2-3g/day anti-prostaglandin effect (reduces dysmenorrhea) · Red meat: ≤2 servings/week (increase circulating estrogens) · Fiber ≥25g/day (promotes fecal estrogen excretion) · Vitamin D: target >40 ng/mL (immune modulation) · Magnesium 310-320 mg/day: reduces cramps · Curcumin 500mg/day: emerging anti-inflammatory evidence · Alcohol: increases estrogens → reduce to 0 · Probiotics: improve frequent intestinal dysbiosis · Low FODMAP if coexisting IBS · Soy: weak estrogenic effect, moderate use."},"prediabete":{"nome":"Prediabetes / Impaired Fasting Glucose (IFG/IGT)","desc":"Low glycemic index, fiber-rich diet. 5-10% body weight reduction. Physical activity 150 min/week. Goal: prevent progression to T2DM.","note":"ADA 2024 · IDF 2022 · IFG: fasting glucose 100-125 mg/dL · IGT: 2h OGTT glucose 140-199 mg/dL · HbA1c 5.7-6.4% · Weight loss 5-10%: reduces T2DM risk by 58% (DPP) · CHO: prefer low GI (GI<55); fiber ≥30g/day (oat beta-glucans, psyllium) · Added fructose: minimize · Saturated fat <7%; omega-3 favorable · Alcohol: not recommended (masks hypoglycemia) · Metformin: consider if BMI>35 or <60 years · Monitor fasting glucose and HbA1c every 6-12 months."},"ipercolesterolemia_familiare":{"nome":"Familial Hypercholesterolemia (FH)","desc":"Very restrictive diet for saturated fat and cholesterol. Phytosterols 2g/day mandatory. Omega-3. Drug therapy (statins, ezetimibe, PCSK9 inhibitors) always necessary.","note":"EAS 2023 · LDL-receptor, Apo B or PCSK9 mutation · LDL-C >190 mg/dL (adults), >160 mg/dL (children) · Diet alone reduces LDL by max 15-25% · Saturated fat <7% total calories (ideally <5%) · Dietary cholesterol <200 mg/day · Phytosterols 2g/day (LDL reduction 8-10%) · Oat beta-glucans 3g/day · Soluble fiber ≥10-15g/day · Omega-3 EPA/DHA 2-4g/day · Eliminate trans fats completely · Alcohol: limit · Red meat: ≤1 time/week · Pharmacotherapy MANDATORY: high-intensity statins + ezetimibe (PCSK9i if needed)."},"psoriasi":{"nome":"Psoriasis","desc":"Anti-inflammatory (Mediterranean) diet. Weight loss if overweight. Zero alcohol. Omega-3 and vitamin D useful. Avoid individual food triggers.","note":"BAD 2023 · EADV 2023 · Psoriasis is a chronic inflammatory skin disease with an immune-metabolic component · Obesity: worsens psoriasis and reduces response to biologics → weight loss is a priority · Alcohol: trigger and worsening factor → zero · Omega-3 EPA/DHA 2-3g/day: reduce IL-17, TNF-α · Vitamin D target >40 ng/mL (modulates Th17/Treg) · Mediterranean diet: reduces PASI in observational studies · Gluten: 3-month GFD trial if anti-gliadin IgA positive (15-25% of patients) · Nightshade intolerance: anecdotal evidence · Probiotics: gut-skin axis (altered microbiota in psoriasis) · Frequent metabolic syndrome: monitor glucose, lipids, BP."},"dermatite_atopica":{"nome":"Atopic Dermatitis (Eczema)","desc":"Identify and remove triggering food allergens (mainly milk, eggs, wheat, soy, fish, tree nuts). Probiotics for prevention. Essential fatty acids.","note":"EAACI 2022 · AAD 2022 · Food allergy is a trigger in 30-40% of children with severe AD, less in adults · Allergy testing (ISAC, skin prick, specific IgE) before dietary eliminations · Blind elimination not recommended · Probiotic Lactobacillus rhamnosus GG: prevention and therapy (moderate evidence) · Omega-3 EPA/DHA 1-2g/day: reduces Th2 inflammation · Vitamin D target >40 ng/mL · Exclusive breastfeeding for 6 months: prevents AD · Breast milk: continue if possible · Early food diversification (4-6 months) reduces sensitization · Prebiotics (FOS, GOS): emerging evidence."},"acne":{"nome":"Acne Vulgaris / Seborrheic Dermatitis","desc":"Low glycemic index diet. Reduce skim milk, whey protein supplements. Anti-inflammatory omega-3. Adequate zinc.","note":"JAAD 2022 · AAD 2022 · High GI → hyperinsulinemia → increased IGF-1 → sebum + keratinization → acne · Low GI diet reduces acne lesions by 25-50% (RCT) · Skim milk: more insulinogenic than whole milk; whey protein: increases IGF-1 · Chocolate: suggested correlation, uncertain mechanism · Omega-3 EPA 1-2g/day: reduces follicular inflammation · Zinc 30mg/day (glycinate or acetate): reduces P. acnes, anti-inflammatory · Vitamin A from food sources (liver, eggs): don't overdo · Probiotics: modulate sebaceous and gut microbiota · Brewer's yeast: nickel content may worsen · Hydration: helpful but not a sole solution."},"sjogren":{"nome":"Sjögren's Syndrome","desc":"Adapt food consistency and moisture to xerostomia (dry mouth). Stimulate saliva production. Frequent hydration. Protect dental enamel.","note":"EULAR 2020 · Autoimmune disease: destruction of exocrine glands → xerostomia (dry mouth) + xerophthalmia (dry eyes) · Xerostomia → chewing/swallowing difficulty, cavities, dysphagia · Diet: moist, soft, non-sticky foods · Salivary stimulants: citrus fruit (mind acidity), sugar-free candies, xylitol gum · Avoid: alcohol, caffeine (diuretics), dry/powdery foods, excess acidic foods (enamel erosion) · Oral hygiene after every meal (fluoride) · Hydration: frequent sips of water during meals · Omega-3 3g/day: reduces glandular inflammation · Vitamin D target >30 ng/mL · Monitor: anemia, non-Hodgkin lymphoma (increased risk), neuropathy."},"talassemia":{"nome":"Thalassemia / Mediterranean Anemia","desc":"Avoid excess iron and vitamin C supplements (increase accumulation). Calcium and vitamin D for osteoporosis. Folate. Limited ascorbic acid.","note":"TIF 2021 · Genetic disease: hemoglobin synthesis defect · Beta-thalassemia major: regular transfusions → iron overload (siderosis) · Treatment: iron depletion with chelators (deferoxamine, deferasirox, deferiprone) · Diet: do NOT supplement iron (already in excess from transfusions and increased intestinal absorption) · Vitamin C: do not exceed 200mg/day (mobilizes iron from stores → cardiac toxicity) · Calcium 1200mg/day and Vitamin D 1000-2000 IU/day: frequent osteoporosis (hypogonadism, chelators) · Folate 1-5mg/day: ineffective erythropoiesis · Tea and coffee with meals: reduce non-heme iron absorption (useful) · Alcohol: hepatotoxic with iron overload → zero · Zinc: often deficient (chelators) → monitor."},"favismo":{"nome":"G6PD Deficiency (Favism)","desc":"Completely avoid fava beans (Vicia faba) and their derivatives. Caution with oxidizing drugs. Avoid naphthalene, azo dyes, oxidative stress.","note":"WHO 2022 · ENERCA 2022 · Glucose-6-phosphate dehydrogenase deficiency (X-linked) · Fava beans (Vicia faba): contain vicine and convicine → acute (often severe) hemolytic crisis · Foods to avoid: fresh/dried fava beans, peas (possible cross-reaction), products containing fava bean flour · Drugs to avoid: primaquine, dapsone, cotrimoxazole, nitrofurantoin, rasburicase, some antimalarials · Foods with caution: black raspberries, blueberries (oxidizing anthocyanins at high doses) · Moderate vitamin E and C: protective antioxidant effect · Alcohol: avoid (increases erythrocyte oxidative stress) · Monitor Hb during acute infections (hemolytic crisis) · Always carry a medical card with the list of prohibited drugs."},"wilson":{"nome":"Wilson's Disease (Copper Accumulation)","desc":"Low-copper diet (<1 mg/day). Avoid liver, shellfish, nuts, chocolate, mushrooms. Mandatory chelating drug therapy (penicillamine, trientine) or zinc.","note":"EASL 2012 · AASLD 2022 · ATP7B transport protein deficiency → copper accumulation in liver, brain, eyes · Kayser-Fleischer rings pathognomonic · Low-copper diet: <1 mg/day (normal copper 1.5-3mg/day) · To avoid (high copper): beef/bovine liver (>15mg/100g), oysters, shrimp, crab, shellfish, dark chocolate (>3mg/100g), walnuts, hazelnuts, mushrooms, whole wheat, legumes · Water: prefer bottled water in glass (copper pipes) · Vitamin E 400-800 IU/day: useful antioxidant effect (copper accumulation → oxidative stress) · Mandatory pharmacotherapy: penicillamine or trientine (chelators) or zinc acetate (first-line/maintenance) · Monitor: transaminases, serum/24h urinary copper, ceruloplasmin."},"lipedema":{"nome":"Lipedema","desc":"Anti-inflammatory diet (Mediterranean or low-GI ketogenic). Reduce simple sugars and refined carbohydrates. Caution with weight loss: it does not reduce the lipedema itself but improves quality of life.","note":"ILA 2021 · Chronic adipose-lymphatic condition: pathological symmetric subcutaneous fat accumulation (legs/hips/arms) · Does not respond to conventional caloric restriction · Anti-inflammatory diet: reduces pain and inflammation of dysfunctional adipose tissue · Ketogenic or low-carb diet: reduces lymphatic fluid retention and pain (emerging evidence) · Refined CHO and sugars: increase insulinemia → adipose edema → worsen symptoms · Omega-3 EPA/DHA 2-3g/day: anti-inflammatory · Curcumin 500-1000mg/day: systemic anti-inflammatory · Vitamin D target >40 ng/mL · Adequate selenium · Salt: limit (<5g/day NaCl) · Fluids: ≥2L/day (lymphatic drainage) · Avoid: alcohol, added sugars, refined flours."},"iperemesi_gravidica":{"nome":"Hyperemesis Gravidarum (NVP/HG)","desc":"Extreme meal splitting (6-10 small meals). Dry, cold, bland foods. Ginger 1g/day. Vitamin B6 10-25mg every 8h. IV hydration if necessary.","note":"RCOG 2024 · ACOG 2022 · NVP (Nausea and vomiting of pregnancy): 70-80% of pregnancies · HG (Hyperemesis gravidarum): 0.5-2%; diagnosis: persistent vomiting + weight loss >5% + ketosis · Cause: elevated HCG, psychosocial factors, H. pylori infection · Diet: small frequent meals (every 2-3h) · Recommended foods: crackers, white bread, white rice, banana, apple, yogurt, broth · Foods to avoid: fatty, spicy foods, strong odors, coffee · Temperature: cold/room-temperature foods better tolerated than hot · Ginger (Zingiber officinale) 1g/day: reduces nausea (grade A evidence) · Vitamin B6 10-25mg every 8h: first-line pharmacologic treatment · Doxylamine: safe antiemetic in pregnancy · Prenatal supplements: take with food or in the evening · IV hydration (lactated Ringer's) if >5% weight loss or severe ketosis · Hospitalization if: weight loss >5%, hypokalemia, coagulopathy, encephalopathy."},"sbs":{"nome":"Short Bowel Syndrome (SBS)","desc":"Supplemental parenteral or enteral nutrition. High risk of malnutrition and micronutrient depletion. Progressive intestinal adaptation.","note":"ESPEN 2022 · AGA 2020. Intestinal resection >70% → SBS. Phases: parenteral → enteral → oral. Proximal colostomy: massive electrolyte losses (Na 100-140 mEq/L). Colon preserved: low-fat diet + complex CHO. Glutamine 0.5g/kg/day + GLP-2 (teduglutide) for adaptation. Monitor: B12, iron, calcium, magnesium, zinc, selenium, fat-soluble vitamins A,D,E,K. High-energy ONS."},"addison":{"nome":"Adrenal Insufficiency / Addison's Disease","desc":"Sodium-rich diet. Regular meals to prevent hypoglycemia. Vitamin D and calcium. Potassium not to be exceeded.","note":"ES 2021 · ESE 2021. Mandatory replacement therapy (hydrocortisone + fludrocortisone). Diet: increase sodium (3-4g NaCl/day) especially in summer or with exercise. In addisonian crisis: urgent IV sodium. Regular meals with medium-GI CHO to prevent hypoglycemia. Potassium: do not exceed (hyperkalemia risk). Vitamin D 1000-2000 IU/day + calcium 1000-1200mg/day (for steroid-induced osteoporosis). Small frequent meals (4-5/day)."},"post_covid":{"nome":"Long COVID / Post-COVID-19","desc":"Anti-inflammatory diet. Vitamin D, zinc, omega-3. Small meals if fatigue. Probiotics for post-viral dysbiosis.","note":"WHO 2023. Long COVID: persistent symptoms >12 weeks. Nutrition: anti-inflammatory (Mediterranean). Vitamin D target >40 ng/mL (often deficient). Zinc 10-15mg/day. Omega-3 EPA+DHA 2g/day (anti-inflammatory). Vitamin B12 if deficient (neuropathy). Probiotics: emerging evidence for post-viral dysbiosis. If brain fog: avoid alcohol and simple sugars. Adequate energy: no severe caloric restriction in the acute phase. Hydration ≥2L/day."},"sclerosi_multipla":{"nome":"Multiple Sclerosis","desc":"Mediterranean diet. Vitamin D target 40-60 ng/mL. Omega-3 2g/day. Fiber for dysbiosis. Probiotics.","note":"ECTRIMS 2023. Vitamin D: serum target 40-60 ng/mL (supplement 2000-4000 IU/day). Omega-3 EPA+DHA 2g/day (neuroprotective and anti-inflammatory effect). Low saturated fat diet. Fiber ≥30g/day for gut microbiota. Probiotics for dysbiosis (growing evidence). Alcohol: avoid or minimize. Optimal body weight reduces neurological load. Gut dysbiosis correlated with disease activity."},"emocromatosi":{"nome":"Hereditary Hemochromatosis","desc":"Avoid iron and vitamin C supplements. Calcium and tannins reduce iron absorption. Zero alcohol. Limit red meat.","note":"EASL 2022. Hereditary iron accumulation. Diet: absolutely avoid iron and vitamin C supplements (potentiate Fe absorption). Calcium, tea, coffee with meals reduce iron absorption. Zero alcohol (worsens Fe-related liver damage). Limit red meat and offal (high heme Fe). Clams, oysters, mussels: very iron-rich, avoid. Vitamin C from food is acceptable if taken away from main meals."},"vegetariana":{"nome":"Vegetarian Diet (Lacto-Ovo)","desc":"Excludes meat and fish. Includes eggs and dairy. Ensure adequate intake of iron, zinc, B12 and omega-3.","note":"SINU 2022 · EFSA 2022 · ADA 2016. Protein: favor cereal + legume combinations. Non-heme Fe: pair with vitamin C. B12: monitor (present in eggs and dairy but variable intake). Omega-3 ALA from flax/chia seeds; EPA/DHA from algae if needed. Zinc: legumes, pumpkin seeds, whole grains. Calcium: dairy, broccoli, tofu, fortified plant-based drinks. Adequate planning ensures full nutritional adequacy."},"vegana":{"nome":"Vegan Diet","desc":"Excludes all animal products. Requires B12 supplementation; attention to iron, calcium, zinc, omega-3, vitamin D and iodine.","note":"SINU 2022 · AND 2016 · EFSA 2019. B12: MANDATORY supplement (250 µg/day or 2500 µg/week). Calcium: fortified plant-based drinks, calcium-set tofu, broccoli, kale, sesame. Fe: legumes + vitamin C with meals; avoid tea/coffee during meals. Zinc: sprouted legumes, pumpkin seeds, whole grains. Omega-3: flax, chia, walnuts (ALA); algae-based EPA/DHA supplement recommended. Vitamin D: supplement 800-2000 IU/day. Iodine: iodized salt or supplement. A well-planned vegan diet is nutritionally adequate for all life stages."},"latto_vegetariana":{"nome":"Lacto-Vegetarian Diet","desc":"Excludes meat, fish and eggs. Includes dairy. Attention to iron (no eggs), zinc, omega-3 and vitamin B12.","note":"SINU 2022 · EFSA 2022. Complete protein: cereals + legumes + dairy. Non-heme Fe from legumes, whole grains and leafy greens; always pair with vitamin C. B12: present in dairy but monitor periodically. Omega-3: flax/chia/walnut seeds (ALA); consider algae-based EPA/DHA supplement. Zinc: dairy, legumes, whole grains. Calcium: dairy, broccoli, tofu. Exclusion of eggs creates no issues if dairy intake is varied and regular."},"ovo_vegetariana":{"nome":"Ovo-Vegetarian Diet","desc":"Excludes meat, fish and dairy. Includes eggs. Attention to calcium (no dairy), B12, vitamin D and omega-3.","note":"SINU 2022 · EFSA 2022. Protein: eggs + legumes + whole grains. Calcium: cruciferous vegetables (broccoli, kale), calcium-set tofu, fortified plant-based drinks, almonds, sesame. B12: in eggs but variable concentration; monitor serum levels and supplement if needed. Vitamin D: eggs (yolk) + supplement 800-1000 IU/day if reduced sun exposure. Omega-3: flax, chia, walnut seeds (ALA); consider algae-based EPA/DHA supplement. Fe: legumes + vitamin C; eggs contain non-heme Fe with low bioavailability."},"encefalopatia_epatica":{"nome":"Hepatic Encephalopathy (HE)","desc":"Do NOT reduce protein. BCAA if persistent HE. Frequent meals. Evening snack. Supplemented zinc.","note":"EASL/ESPEN 2019 · Protein restriction CONTRAINDICATED (increases mortality) · Protein 1.2-1.5 g/kg/day · BCAA 0.25g/kg/day if persistent HE · Prefer plant proteins and dairy (less ammonia than meat) · Small frequent meals (4-6/day) · Evening CHO snack (reduces overnight fasting) · Zinc often deficient: supplement 220 mg/day · Lactulose and rifaximin to reduce intestinal ammonia · Avoid fasting >6h."},"tumore_testa_collo":{"nome":"Head and Neck Cancer (nutrition)","desc":"Severe malnutrition in 40-70%. Prophylactic PEG before radiotherapy. Mucositis: soft, cold foods. High-calorie ONS.","note":"ESPEN 2021 · High incidence of malnutrition (40-70%) · Dysphagia and mucositis from radio/chemotherapy worsen intake · Prophylactic PEG recommended before extensive radiotherapy · Goal 30-35 kcal/kg/day · Protein 1.5-2.0 g/kg/day · High-calorie, high-protein ONS · Mucositis: soft, cold, non-acidic, non-spicy foods · Xerostomia: liquids with meals, artificial saliva · Monitor weight weekly · Zinc and vitamin D often deficient."},"nefropatia_diabetica":{"nome":"Diabetic Nephropathy (CKD-DM)","desc":"Moderate protein restriction + glycemic control + limitation of phosphorus/potassium/sodium. Low-GI CHO.","note":"KDIGO 2022 · Protein 0.6-0.8 g/kg/day (reduces renal progression) · Glycemic control a priority: HbA1c target 6.5-7.5% · Low-GI CHO · Phosphorus <800 mg/day · Potassium: adapt to GFR (restrict if K >5 mEq/L) · Sodium <2g/day · Monitor: vitamin D, iron, bicarbonate · Avoid NSAIDs."},"ipertrigliceridemia_severa":{"nome":"Severe Hypertriglyceridemia (>500 mg/dL)","desc":"Total fat <10-15%. Absolute zero alcohol. Simple sugars: zero. Omega-3 4g/day. Acute pancreatitis risk.","note":"EAS 2023 · TG>500 mg/dL: acute pancreatitis risk · Total fat <10-15% energy · Alcohol: absolute zero · Simple sugars and fructose: zero · Moderate complex CHO · Omega-3 EPA+DHA 4g/day (reduces TG by 25-50%) · MCT as a substitute for normal fats · Monitor amylase/lipase · Urgent goal: TG <500 mg/dL."},"sindrome_refeeding":{"nome":"Refeeding Syndrome (Prevention)","desc":"Gradual refeeding in severely malnourished patients. Thiamine BEFORE refeeding. Close monitoring of P, K, Mg. Max 10 kcal/kg/day initially.","note":"ASPEN 2020 · ESPEN 2018 · Risk: anorexia, fasting >5 days, alcoholism, severe malnutrition (>15% weight loss), post-surgery · Phase 1 (days 1-3): max 10 kcal/kg/day · Phase 2 (days 4-7): 15-20 kcal/kg/day · Phase 3 (day 8+): gradual increase · BEFORE refeeding: thiamine 200-300 mg IV x3/day · Monitor every 12-24h: phosphate (target >0.6 mmol/L), potassium, magnesium · Stop if severe hypophosphatemia (<0.3 mmol/L)."},"colangite_biliare_primitiva":{"nome":"Primary Biliary Cholangitis / PSC (PBC)","desc":"Steatorrhea: moderate fat (<40g/day). Supplemented fat-soluble ADEK vitamins. No alcohol. Calcium and vitamin D.","note":"EASL 2017 · Cholestasis → fat malabsorption → fat-soluble vitamin deficiency (A, D, E, K) · Vitamin D target 40-60 ng/mL (2000-4000 IU/day) · Vitamin K if prolonged PT · Vitamin E 400 IU/day · Calcium 1000-1200 mg/day · Fat <40g/day if steatorrhea · Zero alcohol · UDCA as primary therapy."},"nutrizione_preoperatoria":{"nome":"Pre-Operative Nutrition (Prehabilitation)","desc":"Identify and correct pre-surgical malnutrition. Immunonutrition 5-7 days pre-op. Liquid CHO up to 2h before anesthesia.","note":"ESPEN 2021 · ERAS protocol · Malnutrition identification (MNA, NRS-2002) · If malnourished: nutritional support 7-14 days pre-op · Pre-op immunonutrition (arginine 15-20g/day + EPA 2g/day + nucleotides) for 5-7 days: reduces infectious complications by 30-40% · 12.5% carbohydrate drink up to 2h before anesthesia (400mL evening, 200mL morning) · Protein 1.2-1.5 g/kg/day."},"galattosemia":{"nome":"Classic Galactosemia (GALT)","desc":"Lifelong galactose-free diet. All dairy excluded. Calcium from alternative sources. Supplemented vitamin D.","note":"SSIEM 2022 · GALT enzyme deficiency · Total and permanent elimination of milk and dairy (galactose) · Attention to hidden galactose: some fruits (papaya, dates), legumes (fava beans), additives · Alternatives: rice, oat, soy drinks (check label, galactose-free) · Supplemental calcium 1000-1200 mg/day · Vitamin D 1000-2000 IU/day · Monitor bone density · Multidisciplinary follow-up."},"sindrome_cushing":{"nome":"Cushing's Syndrome (hypercortisolism)","desc":"Reduce sodium, increase calcium and vitamin D, increased protein (catabolism). Control glucose. Low-GI CHO.","note":"ES 2021 · Hypercortisolism causes: hyperglycemia, hypertension, osteoporosis, muscle catabolism · Sodium <2g/day · Calcium 1000-1200 mg/day + vitamin D 2000 IU/day · Protein 1.2-1.5 g/kg/day · Low-GI CHO (insulin resistance) · Limit saturated fat · Monitor: glucose, lipids, bone density."},"neutropenia_oncologica":{"nome":"Oncologic Neutropenia (Neutropenic Diet)","desc":"Strict microbiological safety. No raw animal foods. No soft/blue cheeses. No fresh juices. Thorough cooking.","note":"ESPEN 2021 · Severe neutropenia (PMN <500/µL) from chemotherapy · Goal: prevent foodborne infections · Prohibited: raw meat, sushi, unpasteurized soft cheeses, raw eggs, sprouts, unpasteurized fresh juices, raw honey · Meat internal temp >75°C, hard-boiled eggs, well-cooked fish · Fruit/vegetables: wash thoroughly, prefer peeled."},"epatite_cronica":{"nome":"Chronic Hepatitis B/C (HBV/HCV)","desc":"Balanced diet. Alcohol: absolute zero. Coffee: documented benefit. Avoid overweight. Supplemented vitamin D.","note":"EASL 2024 · Alcohol: absolute zero (cofactor for progression to cirrhosis and carcinoma) · Overweight accelerates fibrosis → BMI 20-25 · Coffee 2-3 cups/day: slows fibrosis · Fiber ≥25g/day, antioxidants · Avoid iron supplements · Vitamin D if <30 ng/mL · HCV curable with DAA in >95% of cases · HBV: long-term antiviral therapy."},"artrite_psoriasica":{"nome":"Psoriatic Arthritis (PsA)","desc":"Weight loss if overweight (improves biologics). Mediterranean diet. Omega-3 3g/day. Zero alcohol. Vitamin D.","note":"GRAPPA 2022 · EULAR 2022 · Overweight reduces biologic efficacy → weight loss is therapeutic · Mediterranean diet reduces CRP and disease activity · Omega-3 EPA/DHA 3g/day anti-inflammatory · Zero alcohol (worsens psoriasis and arthritis) · Vitamin D target >40 ng/mL · Folate 5mg/day if on MTX · Limit saturated fat and sugars."},"acalasia":{"nome":"Achalasia","desc":"Soft/semi-liquid foods. Small frequent meals (5-6/day). Upright posture after meals. Prevent malnutrition.","note":"ESGE 2020 · ACG 2020 · Soft/semi-liquid diet, small meals (5-6/day), upright posture 30-60 min post-meal. Cold liquids: aggravate spasm. B12 and iron: monitor. ONS if intake <70% of requirement."},"iperomocisteinemia":{"nome":"Hyperhomocysteinemia","desc":"Folate, B12, B6. Leafy greens, legumes, whole grains. Limit methionine. Zero alcohol.","note":"ESC 2020 · EFNS 2020 · Homocysteine >15 µmol/L: CV and neurological risk. Folate 0.4-5 mg/day. B12 1000 µg/day if deficient. B6 10-25 mg/day. Methionine: reduce red meat, aged cheeses. Zero alcohol. Monitor homocysteine, B12, folate, creatinine."},"dumping_syndrome":{"nome":"Dumping Syndrome","desc":"5-6 small meals. No liquids during meals. Limit simple sugars. Protein at every meal.","note":"ESPEN 2021 · Post-gastrectomy/bypass: accelerated gastric emptying. Early dumping (30 min): intestinal hyperosmolality. Late dumping (1-3h): reactive hypoglycemia. No liquids during meals (only 30-45 min after), no simple sugars, complex CHO, protein and fat at every meal, 5-6 small meals."},"malassorbimento_fruttosio":{"nome":"Fructose Malabsorption","desc":"Limit free fructose (apple, pear, mango, honey, HFCS). Avoid sorbitol. Tolerated: banana, citrus fruit, strawberry.","note":"ACG 2021 · GLUT-5 deficiency: excess free fructose → colonic fermentation, bloating, diarrhea. To avoid: apple, pear, mango, watermelon, honey, agave, HFCS, sorbitol (E420). Tolerated: banana, citrus fruit, strawberry. FODMAP overlap: often co-present."},"dieta_fodmap":{"nome":"Low-FODMAP Diet (IBS)","desc":"Phase 1: FODMAP elimination (6 weeks). Phase 2: systematic reintroduction. Dietitian guidance essential.","note":"Monash University 2022 · IBS: effective in 50-75%. Phase 1 (6 wk): rice, quinoa, carrot, zucchini, banana, strawberry, lactose-free milk, chicken, fish. To avoid: wheat, onion, garlic, legumes, cow's milk, apple, pear, mango. Phase 2: gradual reintroduction to identify personal triggers."},"ernia_iatale":{"nome":"Hiatal Hernia / GERD","desc":"Small frequent meals. Do not lie down for 3h. Avoid: fats, chocolate, coffee, alcohol, mint, tomato, citrus fruit.","note":"ACG 2022 · ESGE 2020 · Hiatal hernia: LES incompetence. Triggers to avoid: fats, chocolate, mint, coffee, alcohol, spicy foods, tomato, citrus fruit. Do not lie down for 3h post-meal, raise head of bed 15-20 cm. Small frequent meals (5/day). Weight loss if BMI >25."},"deficit_vitamina_d":{"nome":"Vitamin D Deficiency","desc":"Salmon, mackerel, tuna, eggs, fortified milk. Supplement 1000-4000 IU/day. Target 25-OH-D >30 ng/mL.","note":"SIOMMMS 2022 · ESPEN 2022 · 25-OH-D target >30 ng/mL (ideal 40-60 ng/mL). Cholecalciferol: 1000-2000 IU/day maintenance, 3000-4000 IU/day correction. Rich foods: salmon, mackerel, canned tuna, egg yolk. Sun exposure 15-20 min/day. Calcium 1000-1200 mg/day."},"deficit_b12_folati":{"nome":"B12 and Folate Deficiency","desc":"B12: liver, shellfish, fish, eggs, dairy. Folate: leafy greens, legumes, whole grains.","note":"BSH 2022 · ESPEN 2022 · Megaloblastic anemia: distinguish B12 from folate deficiency. Low B12: vegans, gastrectomy, atrophic gastritis. B12 1000 µg/day IM (severe deficiency) or 1000-2000 µg/day po. Folate 5 mg/day until normalization. B12 foods: liver, shellfish, mackerel, salmon, eggs, dairy. Do not replace B12 with folate alone."},"terapia_anticoagulante":{"nome":"Diet for Anticoagulant Therapy (Warfarin)","desc":"Constant vitamin K (do not eliminate). Leafy greens: 1-2 servings/day, kept constant. NOACs: no restriction.","note":"ESC 2021 · ACCP 2021 · Warfarin: INR target 2-3 (AFib). Vitamin K: do NOT eliminate, keep constant (spinach, broccoli 1-2 servings/day). Sudden changes in vitamin K → INR instability. NOACs: no dietary restriction. Monitor INR if diet changes."},"ncgs":{"nome":"NCGS - Non-Celiac Gluten Sensitivity","desc":"Gluten-free diet as in celiac disease. GF cereals: rice, corn, buckwheat, quinoa, millet.","note":"ESPGHAN 2021 · BSG 2021 · NCGS: exclude celiac disease (IgA anti-tTG) and wheat allergy. No specific serological marker. GF diet: improves symptoms in 70-80%. Allowed cereals: rice, corn, buckwheat, quinoa, millet, sorghum. Monitor: fiber, folate, B12, iron, vitamin D."},"epatite_autoimmune":{"nome":"Autoimmune Hepatitis (AIH)","desc":"Absolute zero alcohol. Mediterranean diet. Steroid therapy: limit sodium and sugars. Calcium + vitamin D.","note":"EASL 2022 · Absolute zero alcohol. Anti-inflammatory Mediterranean diet. Steroids: fluid-sodium retention → limit sodium <2g/day and simple sugars. Steroid-induced osteoporosis: calcium 1000-1200 mg/day + vitamin D 2000 IU/day. Azathioprine: folate 0.4-1 mg/day."},"obesita_pediatrica":{"nome":"Pediatric Obesity","desc":"Family-based intervention. Reduce ultra-processed foods and sugary drinks. 5 servings of fruit/vegetables. Physical activity 60 min/day.","note":"ESPGHAN 2022 · ISPAD 2022 · Goal: slow weight gain (not rapid weight loss). Multi-component family intervention. Reduce: ultra-processed foods, sugary drinks. Increase: fruit (5 servings/day), vegetables, whole grains, legumes. Physical activity 60 min/day. No drastic diets <12 years."},"celiachia_refrattaria":{"nome":"Refractory Celiac Disease (RCD)","desc":"Strict GFD + verification of cross-contamination (<20 ppm). Supplement: iron, folate, B12, calcium, vit D, zinc. ONS.","note":"ESGE 2022 · AGA 2022 · RCD: persistent symptoms despite GFD >12 months. Type I: responds to steroids. Type II: risk of T-cell-associated lymphoma (EATL). Ultra-strict GFD: <20 ppm. Severe malabsorption: ONS or EN/PN. Supplement: IV iron, IM B12, folate 5 mg, calcium 1500 mg, vitamin D 4000 IU, zinc 15-30 mg."},"iperparatiroidismo":{"nome":"Primary Hyperparathyroidism","desc":"Calcium: moderate (<1000mg/day if serum Ca elevated). Vitamin D target 50-60 ng/mL. Abundant hydration. Limit sodium.","note":"AACE 2022 · Elevated PTH → hypercalcemia, hypercalciuria, bone resorption. Do not drastically reduce dietary calcium (stimulates PTH) but moderate if calcemia >11 mg/dL. Vit D target 50-60 ng/mL (not above 100). Hydration 2-3 L/day (prevents stones). Na <1.5 g/day (reduces calciuria). Vitamin K2 (MK-7) 100-200 µg/day. Avoid thiazide diuretics (increase serum Ca). After parathyroidectomy: \"hungry bone syndrome\" → transiently increase calcium and vitamin D."},"sclerodermia":{"nome":"Systemic Sclerosis (Scleroderma)","desc":"Dysphagia and esophageal dysmotility: soft foods. Malabsorption: small frequent meals. Vitamin D, omega-3, antioxidants.","note":"EULAR 2017 · ACR 2022 · GI involvement in 90% → esophageal dysmotility, reflux, malabsorption, SIBO. Soft foods, small frequent meals (5-6/day), upright posture post-meal. SIBO: fermented foods, probiotics. Omega-3 3g/day: anti-fibrotic. Vitamin D 2000-4000 IU/day (immunomodulatory). Antioxidants (vitamins C, E). Adequate protein 1.2-1.5 g/kg/day. If cold fingers (Raynaud's): avoid cold, caffeine."},"allergia_nichel":{"nome":"Nickel Allergy / SNAS","desc":"Low-nickel diet (SNASIT). Limit: whole grains, legumes, cocoa, tree nuts, spinach. Rotation and individual threshold.","note":"SIAAIC 2022 · SNAS (Systemic Nickel Allergy Syndrome): GI, cutaneous, systemic symptoms from nickel. Daily threshold ~100-200 µg Ni/day. High-content foods: cocoa/chocolate, sunflower seeds, legumes, whole grains, spinach, tomatoes, tree nuts, pears, plums, figs. Preferred: rice, refined pasta, meat, fish, eggs, milk, low-content vegetables. Vitamin C reduces nickel absorption if paired with meals. Personalize based on severity and threshold."},"intestino_corto":{"nome":"Short Bowel Syndrome (SBS)","desc":"Home parenteral nutrition if <100cm without ileocecal valve or <150cm with valve. Intestinal adaptation 1-2 years.","note":"ESPEN 2020 · ASPEN 2021 · SBS: residual bowel <200 cm (adults). Type 1: terminal jejunostomy → high HPN. Type 2: colon preserved → greater autonomy. Intestinal adaptation up to 2 years. Oral rehydration: isotonic ORS solution. Complex CHO > simple. Avoid: high osmolality, lactose, long-chain fatty acids. Prefer MCT, soft foods. Supplement: magnesium, zinc, B12, fat-soluble vitamins, calcium. Probiotics: LGG, S. boulardii. Teduglutide (GLP-2): reduces parenteral requirement."},"masld_nash_avanzato":{"nome":"MASLD/NASH with Fibrosis (F2-F4)","desc":"Weight loss 7-10% (reduces fibrosis). Eliminate alcohol. Zero fructose. Omega-3, vitamin E. Aerobic exercise 150 min/week.","note":"EASL 2024 · AASLD 2023 · MASLD: metabolic-associated steatotic liver disease (formerly NAFLD). Weight loss 7-10%: reduces inflammation and fibrosis. Absolute zero alcohol (even low doses). Fructose/HFCS: eliminate. Omega-3 2-4g/day EPA+DHA. Vitamin E 800 IU/day (NASH without DM). Vitamin D if <30 ng/mL. Low-GI CHO. Fiber 30g/day. Aerobic exercise 150 min/week + resistance. 2024-approved drugs: resmetirom (THR-β)."},"depressione_nutrizione":{"nome":"Depression and Nutrition (Nutritional Psychiatry)","desc":"Mediterranean diet reduces risk by 33%. Omega-3 EPA 2g/day. Tryptophan, B12, folate, vitamin D, zinc, magnesium, iron.","note":"ISNS 2023 · ESPEN 2023 · Nutritional psychiatry: growing evidence for the Mediterranean diet (2024 meta-analysis). Omega-3 EPA 2g/day: efficacy equal/superior to antidepressants in RCTs. Tryptophan (serotonin precursor): turkey, eggs, dairy, legumes, oats. Folate: leafy greens, legumes. B12. Vitamin D. Zinc: meat, shellfish, pumpkin seeds. Magnesium: dark chocolate, nuts, legumes. Gut-brain-microbiota axis: probiotics and fiber. Simple sugars and UPF increase depression risk."},"sonno_nutrizione":{"nome":"Sleep Disorders and Nutrition","desc":"Evening tryptophan: milk, turkey. Melatonin: cherries, grapes. Limit caffeine after 2pm. Light evening meal 2h before bed.","note":"AASM 2023 · Circadian nutrition. Caffeine: avoid after 2pm (half-life 5-7h). Evening meal: at least 2-3h before sleep. Evening tryptophan (melatonin-serotonin precursor): warm milk, turkey, oats, banana. Dietary melatonin: cherries, grapes, tomatoes, walnuts. Vitamin D and magnesium: support sleep quality. Simple sugars, UPF, alcohol: worsen sleep architecture. Magnesium glycinate 300 mg/evening. Regular meal times (chrono-nutrition)."},"ipertensione_resistente":{"nome":"Resistant Hypertension (>3 drugs)","desc":"Extended DASH: Na <1.5g/day. Potassium 3500-5000mg/day. Nitrates (beetroot, green vegetables). Caffeine: moderate. Zero alcohol.","note":"ESH 2023 · AHA 2021 · Resistant hypertension: BP >140/90 mmHg with ≥3 drugs including a diuretic. Maximal DASH diet: Na <1.5 g/day (additional -5/-3 mmHg BP reduction). Potassium 3500-5000 mg/day (from fruit and vegetables). Dietary nitrates (beetroot, spinach): endogenous vasodilators (NO). Dark chocolate 30g/day: flavanols. DASH + 5% weight loss: BP reduction equivalent to 1 drug. Zero alcohol."},"gravidanza_fisiologica":{"nome":"Normal Pregnancy","desc":"+350 kcal/day in 2nd trimester, +450 in 3rd. Folate 400µg/day from conception. DHA 200mg/day. Iron 27mg/day. Iodine 220µg/day.","note":"SIGO 2022 · ISS 2022 · Folate: 400 µg/day pre-conception and 1st trimester (reduces spina bifida by 72%). DHA 200 mg/day (CNS development). Iron 27 mg/day (mainly 2nd-3rd trimester). Iodine 220 µg/day (iodized salt). Calcium 1000 mg/day. Vitamin D 600-1000 IU/day. 1st trimester nausea: small meals, crackers on an empty stomach, ginger. Avoid: swordfish, large amounts of tuna (mercury), unpasteurized dairy, alcohol, coffee >200 mg/day, raw meat."},"trapianto_renale":{"nome":"Post-Kidney Transplant","desc":"Avoid grapefruit (cyclosporine). Reduce Na (<2g/day). Calcium + vitamin D. Protein 1.3-1.4 g/kg/day. No cranberry.","note":"KDIGO 2022 · ESPEN 2022 · Immunosuppressants (cyclosporine, tacrolimus, sirolimus): food interactions. AVOID: grapefruit (increases immunosuppressant levels 3-5x), cranberry (interacts with cyclosporine), pomegranate juice. Steroids: limit Na and simple sugars, calcium 1000-1200 mg/day, vitamin D 2000 IU/day. Protein 1.3-1.4 g/kg/day (post-transplant catabolism). Potassium and phosphorus: normalized but monitor. Hypertension: DASH. Dyslipidemia: limit saturated fat."},"ipoglicemia_reattiva":{"nome":"Reactive (Postprandial) Hypoglycemia","desc":"5-6 small meals. Low-GI complex CHO + protein + fat at every meal. No simple sugars.","note":"Endocrine Society 2022 · Reactive hypoglycemia: glucose <70 mg/dL at 1-4h after a meal. Rule out insulinoma. Low-GI CHO at every meal (brown rice, oats, legumes). Protein and fat at every meal. 5-6 small meals/day. Avoid: sugary drinks, juices, sweets. Monitor glucose 1-2h post-meal."},"coronaropatia":{"nome":"Coronary Artery Disease (CAD)","desc":"Reduced coronary flow due to atherosclerosis. Mediterranean diet reduces cardiovascular events by 30%.","note":"Favor omega-3, soluble fiber, fruit and vegetables. Limit saturated fat and sodium. Zero or moderate alcohol."},"post_infarto":{"nome":"Post-Myocardial Infarction Rehabilitation","desc":"Nutritional plan in the rehabilitation phase after acute myocardial infarction. Prevention of recurrence.","note":"Modified DASH diet. Omega-3 EPA+DHA ≥1g/day. Eliminate trans fats. Sodium <1500mg/day. Strict weight control."},"fibrillazione_atriale":{"nome":"Atrial Fibrillation","desc":"Cardiac arrhythmia with thromboembolic risk. If on warfarin therapy: attention to vitamin K. If on DOAC: fewer restrictions.","note":"With warfarin: stable vitamin K (do not eliminate, but keep constant). With DOAC: no specific dietary restriction. Limit alcohol, caffeine."},"cardiomiopatia_dilatativa":{"nome":"Dilated Cardiomyopathy","desc":"Dilation and dysfunction of the left ventricle. Frequent malnutrition due to cardiac cachexia.","note":"Monitor daily weight (fluid retention). Sodium restriction <2g/day. Fluid restriction if indicated. Thiamine and selenium should be repleted."},"aop":{"nome":"Peripheral Arterial Occlusive Disease","desc":"Atherosclerosis of the peripheral arteries of the lower limbs. Often associated with diabetes and smoking.","note":"Anti-atherosclerotic diet. Omega-3. Antioxidants (vitamin C, E). Glycemic control if associated diabetes. Smoking cessation."},"cardiomiopatia_ipertrofica":{"nome":"Hypertrophic Cardiomyopathy","desc":"Thickening of the heart muscle, often genetic. Risk of arrhythmias and sudden death. Limit intense exertion.","note":"No excess caffeine. Avoid alcohol. Adequate hydration. Avoid prolonged fasting and heavy meals."},"miastenia_gravis":{"nome":"Myasthenia Gravis","desc":"Autoimmune disease of the neuromuscular junction. Frequent dysphagia. Attention to drugs that interfere with nutrition.","note":"Adapt food consistency if dysphagia present. Small frequent meals. Avoid foods requiring prolonged chewing. Eat during periods of greatest drug efficacy."},"spondilite_anchilosante":{"nome":"Ankylosing Spondylitis","desc":"Chronic inflammatory arthropathy of the spine. Associated with IBD in 5-10% of cases. Vitamin D and calcium essential.","note":"Anti-inflammatory diet. Omega-3 EPA+DHA. Vitamin D (often deficient). Adequate calcium. If on biologic therapy: avoid ibuprofen with certain drugs."},"colangite_sclerosante":{"nome":"Primary Sclerosing Cholangitis (PSC)","desc":"Chronic cholestatic disease causing biliary tract fibrosis. Frequently associated with IBD (ulcerative colitis).","note":"Reduce fat if steatorrhea. Fat-soluble ADEK vitamins supplemented. Calcium and vitamin D crucial. Absolute avoidance of alcohol."},"emicrania":{"nome":"Migraine and Nutrition","desc":"Recurrent headache with a possible nutritional component. Some substances are triggers: tyramine, nitrates, caffeine, alcohol.","note":"Identify and avoid personal food triggers. Regular meals (no fasting). Abundant hydration. Magnesium and riboflavin (B2) may reduce frequency."},"autismo_nutrizione":{"nome":"ASD and Nutrition","desc":"Autism spectrum disorder with frequent food selectivity, sensory hypersensitivity and risk of nutritional deficiencies.","note":"Individualized approach. Gradual expansion of variety. Attention to zinc, iron, vitamin D, B12, omega-3 deficiencies. Assess real vs. behavioral intolerances."},"glicogenosi_i":{"nome":"Glycogen Storage Disease Type I (Von Gierke)","desc":"Glucose-6-phosphatase deficiency. Severe fasting hypoglycemia. Requires raw cornstarch or continuous overnight feeding.","note":"Raw cornstarch every 3-6h (children) or 4-6h (adults). Infants: continuous overnight nasogastric feeding. Avoid fructose and galactose. No fasting."},"mastocitosi":{"nome":"Systemic Mastocytosis / MCAS","desc":"Pathological accumulation/activation of mast cells. Systemic reactions to food triggers: histamine, additives, preservatives.","note":"AAAAI 2022 · ESPEN. Low-histamine diet. Avoid individual triggers. No universal diet exists: food diary mandatory. Vitamin D + Vitamin C (natural antihistamine)."},"porfiria":{"nome":"Acute Intermittent Porphyria","desc":"Enzyme deficiency in heme biosynthesis. Attacks precipitated by fasting, alcohol, drugs, stress. Carbohydrate-rich diet prevents attacks.","note":"EPNET 2022. CHO ≥60% of total calories during remission (≥300g/day). During attacks: IV glucose 300-400g/day. AVOID: fasting, low-calorie diets, alcohol, smoking. Hydration 2.5L/day. Heme arginate in severe attacks."},"ipoparatiroidismo":{"nome":"Hypoparathyroidism","desc":"PTH deficiency: chronic hypocalcemia, hyperphosphatemia. Risk of tetany, seizures. Requires calcium + active vitamin D supplementation.","note":"ETA 2022. Dietary calcium 1000-1500 mg/day (do not exceed). Active vitamin D (calcitriol). Reduce phosphorus: limit excess dairy, phosphate additives (E450, E451), cola. Magnesium 300 mg/day. Avoid excess fiber (reduces Ca absorption). Hydration 2L/day."},"linfangectasia":{"nome":"Primary Intestinal Lymphangiectasia","desc":"Dilation of intestinal lymphatic vessels. Lipid malabsorption with protein loss. MCT-based diet essential.","note":"ESPEN 2020. Medium-chain fats (MCT) replacing LCT: 40-60g MCT/day. LCT fat <10g/day (omega-3 only). Protein 1.5-2.0g/kg/day (enteric loss). Supplement ADEK, albumin. Omega-3 allowed (does not pass through lymphatics). TPN if severe malnutrition."},"pancreatite_autoimmune":{"nome":"Autoimmune Pancreatitis Type 1/2","desc":"Immune-mediated pancreatitis (IgG4 type 1, inflammatory type 2). Responds to steroids. Nutritional management similar to chronic pancreatitis.","note":"IAP 2023 · AIP guidelines. Acute phase: liquid diet then progression. Chronic phase: low fat content <40g/day, MCT if malabsorption. Alcohol: absolute zero. Steroids: reduced Na, increased Ca. Pancreatic enzymes if exocrine insufficiency. Vitamin D, B12."},"prader_willi":{"nome":"Prader-Willi Syndrome","desc":"Genetic syndrome with compulsive hyperphagia, short stature, hypogonadism. Strict caloric control essential to prevent severe obesity.","note":"PWSA 2021 · ESPEN. Reduced caloric intake: 60-80% of calculated requirement for age/height. Adequate protein for muscle mass. Low-calorie, high-volume foods. Controlled food environment (limited food access). GH: increases protein requirement. Abundant fiber for satiety."},"trapianto_midollo":{"nome":"Bone Marrow Transplant (HSCT)","desc":"Peri-transplant nutrition for hematopoietic stem cell transplant. Neutropenia phase: low microbial load diet. Post-transplant phase: nutritional recovery, GvHD management.","note":"ESPEN 2021 · EBMT. Neutropenia (<500/µL): low bacterial load diet (no raw foods). Mucositis: soft, cold foods. Increased protein intake for marrow regeneration. Intestinal GvHD: ONS/EN. TPN if intake <60% for >3 days. Avoid grapefruit (drug interaction)."},"mieloma":{"nome":"Multiple Myeloma","desc":"Plasma cell neoplasm. Risk of hypercalcemia, renal failure, anemia, protein catabolism. Nutrition essential for treatment tolerance.","note":"ESPEN 2021 · IMF. Hypercalcemia: hydration 2.5-3L/day, limit dietary Ca if Ca>11. Associated CKD: limit P and K. Increased protein for catabolism. Anemia: Fe, B12, folate. Treatment-induced immunosuppression: food hygiene. Bisphosphonates: Ca 1000mg + Vit D 800IU."},"tirosinemia":{"nome":"Tyrosinemia Type 1","desc":"Fumarylacetoacetate hydrolase deficiency. Succinylacetone accumulation. Therapy: NTBC (nitisinone) + low phenylalanine and tyrosine diet.","note":"SSIEM 2023. Plasma tyrosine target: 200-400 µmol/L (adults <500). Phenylalanine: 20-50 mg/kg/day. Amino acid formula free of Tyr/Phe as the main protein source. Natural foods calculated by Phe+Tyr content. Monitor liver/kidney function. NTBC: avoid excessive sunlight (photosensitivity)."},"msud":{"nome":"MSUD - Maple Syrup Urine Disease","desc":"Branched-chain alpha-ketoacid dehydrogenase complex deficiency. BCAA (Leu, Ile, Val) accumulation. Leucine is neurotoxic.","note":"ACMG 2014 · SSIEM 2020. Plasma leucine target: 75-200 µmol/L (critical). Isoleucine: 40-90 µmol/L. Valine: 200-425 µmol/L. BCAA-free formula as protein base. Leucine: natural amount calculated to the mg. Thiamine 10-100 mg/day (thiamine-responsive form). Monitor amino acids every 1-3 months."},"glomerulonefrite":{"nome":"Glomerulonephritis","desc":"Diet adapted to residual renal function. Control of protein, sodium, potassium and phosphorus according to GFR stage.","note":"KDIGO 2021. Protein 0.6-0.8 g/kg/day if GFR<60, increase if nephrotic syndrome with massive proteinuria. Sodium <2g/day for edema and BP control. Potassium adapted to GFR. Omega-3 2g/day (documented anti-proteinuric effect). Vitamin D often deficient: supplement."},"ulcera_peptica":{"nome":"Peptic Ulcer","desc":"Diet that reduces acid stimulation and promotes gastroduodenal mucosal healing.","note":"ACG 2022. No strict \"anti-ulcer diet\" exists: avoid only foods the patient recognizes as triggers. Eliminate alcohol and smoking. NSAIDs contraindicated. If H. pylori: eradication therapy + probiotics. Regular meals 4-5/day, moderate portions. Soluble fiber speeds mucosal healing."},"osteoartrite":{"nome":"Osteoarthritis","desc":"Anti-inflammatory diet and body weight management to reduce joint load and synovial inflammation.","note":"EULAR 2023 · OARSI 2020. 5-10% weight loss reduces pain and improves joint function (NNT 4). Mediterranean diet: anti-inflammatory effect. Omega-3 EPA/DHA 2-3g/day reduces joint pain. Vitamin D target >40 ng/mL. Glucosamine sulfate 1500mg/day: moderate evidence. Hydrolyzed collagen 10g/day: promising studies. Vitamin C 200mg/day (collagen synthesis). Turmeric 1g/day (anti-inflammatory)."},"tumore_polmone":{"nome":"Lung Cancer","desc":"Intensive nutritional support to prevent cachexia and maintain lean mass during chemotherapy and radiotherapy.","note":"ESPEN 2021. Frequent cachexia (40-80%). Omega-3 EPA 2g/day: anti-cachexia (grade A evidence). High-calorie, high-protein ONS if intake <60% for >7 days. Thoracic radiotherapy: dysphagia, esophagitis – soft, fresh foods. Anorexia: small frequent meals, food fortification. Vitamin D target >30 ng/mL. Zinc and selenium: monitor."},"tumore_prostata":{"nome":"Prostate Cancer","desc":"Anti-inflammatory, antioxidant diet to support treatment and reduce disease progression.","note":"ESPEN 2021 · PCF 2023. Lycopene (cooked tomatoes) 10-15mg/day: associated with reduced progression risk. Soy and phytoestrogens: documented protective effect. Saturated fat <10%: reduce (promotes tumor growth). Omega-3 3g/day (anti-inflammatory). Vitamin D target >40 ng/mL. Zinc: do not exceed (≤25mg/day). Alcohol: eliminate or drastically reduce."},"tumore_stomaco":{"nome":"Gastric Cancer","desc":"Nutritional support adapted to residual gastric function, often reduced by surgery or chemotherapy.","note":"ESPEN 2021. Total/partial post-gastrectomy frequent. Small frequent meals (6-8/day). Dumping syndrome: avoid liquids with meals, simple sugars. Mandatory deficiencies: parenteral B12, iron, calcium citrate, vitamin D, folate. Adapted texture if dysphagia. High-protein ONS if intake inadequate."},"tumore_fegato":{"nome":"Hepatocellular Carcinoma (HCC)","desc":"Nutritional support in the context of underlying chronic liver disease. Prevent malnutrition and sarcopenia.","note":"EASL 2022 · ESPEN 2021. HCC arises on cirrhosis in 90% of cases: follow cirrhosis nutritional guidelines. Malnutrition in 60-90%: early nutritional support. Small frequent meals (4-6/day). Evening CHO snack (50g). BCAA 12g/day if encephalopathy or sarcopenia. Vitamin D. ONS if intake <70% of requirement."},"steatoepatite_alcolica":{"nome":"Alcoholic Steatohepatitis (ASH)","desc":"High-calorie, high-protein diet to counter severe malnutrition. Absolute abstinence from alcohol.","note":"EASL 2023 · AASLD 2020. Malnutrition in 90% of patients. Absolute zero alcohol. 35-40 kcal/kg/day (dry weight). Protein 1.2-1.5 g/kg/day (do NOT reduce: dangerous). 4-6 meals/day. Evening CHO snack (50g). Thiamine 100mg/day IV then oral (Wernicke). Zinc, magnesium, vitamin K, vitamin D: supplement. BCAA if encephalopathy. High-protein ONS if intake <70%."},"polimialgia_reumatica":{"nome":"Polymyalgia Rheumatica","desc":"Anti-inflammatory diet and protection against long-term corticosteroid-induced osteoporosis.","note":"EULAR 2023 · BSR 2020. Long-term corticosteroids: osteoporosis risk (Ca 1000-1200mg/day + vitamin D 2000 IU/day mandatory). Sodium <2g/day (steroid fluid retention). Limited simple sugars (steroid-induced glucose elevation). Omega-3 3g/day anti-inflammatory. Mediterranean diet. BMI <25: goal."},"iperaldosteronismo":{"nome":"Primary Hyperaldosteronism","desc":"Low-sodium, high-potassium diet to counter the effects of excess aldosterone.","note":"ES 2021 · AHA 2022. Sodium <1.5g/day (essential: aldosterone retains sodium). Potassium ≥4g/day (frequent hypokalemia). Eliminate alcohol and smoking. DASH diet. After adrenalectomy: normalization of BP and potassium (monitor). Spironolactone/eplerenone: yes to potassium but monitor (hyperkalemia risk in combination)."},"nefropatia_iga":{"nome":"IgA Nephropathy (Berger's Disease)","desc":"Renal diet adapted to GFR stage with attention to BP control and proteinuria reduction.","note":"KDIGO 2021. Sodium <2g/day (BP and proteinuria control). Protein 0.6-0.8 g/kg/day (slows progression). Omega-3 EPA+DHA 2-3g/day: moderate evidence (2023 meta-analysis). Potassium and phosphorus adapted to GFR. Vitamin D often deficient. Gluten-free: not routinely recommended despite IgA deposits (negative trials)."},"artrite_reattiva":{"nome":"Reactive Arthritis","desc":"Anti-inflammatory diet to reduce the systemic post-infectious inflammatory response.","note":"EULAR 2022. Anti-inflammatory diet: Mediterranean. Omega-3 EPA/DHA 2-3g/day. Vitamin D target >40 ng/mL. Zinc 15mg/day (immunity and repair). Probiotics (Lactobacillus): may reduce duration and intensity of post-infectious inflammation. Alcohol: avoid in the acute phase. Abundant hydration."},"acromegalia":{"nome":"Acromegaly","desc":"Normocaloric diet with attention to glycemic control and cardiovascular and bone health.","note":"ES 2014 · AACE 2021. Often associated with secondary diabetes: low-GI CHO. Frequent hypertension: sodium <2g/day. Arthropathy: omega-3 3g/day anti-inflammatory. Calcium 1000-1200mg/day + vitamin D (osteoporosis). Untreated acromegaly: increases colon cancer risk → fiber ≥30g/day. After IGF-1 normalization: goal BMI <25."},"nutrizione_anziani":{"nome":"Nutrition in the Elderly","desc":"Diet adapted to the specific nutritional needs of the elderly to prevent malnutrition, sarcopenia and frailty.","note":"ESPEN 2022 · PROT-AGE 2013. Protein 1.0-1.2 g/kg/day (increase up to 1.5 if malnourished or sarcopenic). Vitamin D 800-2000 IU/day (almost universally deficient). Calcium 1200mg/day. Supplemental B12 if deficient (frequent due to atrophic gastritis). Leucine ≥3g/meal (muscle anabolism). Omega-3. Zinc. Hydration: monitor (reduced thirst sensation). Adapted texture if dysphagia."},"fragilita":{"nome":"Frailty Syndrome","desc":"Nutritional intervention aimed at countering sarcopenia and functional decline in the frail elderly.","note":"ESPEN 2022 · ICFSR 2020. Protein 1.2-1.5 g/kg/day (primary goal). Leucine ≥3g/meal. Vitamin D 800-2000 IU/day. Calcium 1200mg/day. Omega-3 2g/day. ONS if intake insufficient (NNT 6 to prevent frailty). Resistance exercise + adequate protein intake = essential synergy. Vitamin B12. Zinc. Monitor weight weekly."},"vasculite":{"nome":"Systemic Vasculitis (ANCA+/PAN)","desc":"Anti-inflammatory diet and protection from long-term corticosteroid complications in systemic vasculitis.","note":"EULAR 2022 · ACR 2021. Long-term corticosteroids → osteoporosis: Ca 1000-1200mg/day + Vitamin D 2000 IU. Sodium <2g/day (fluid retention and hypertension). Anti-inflammatory Mediterranean diet. Omega-3 3g/day. Azathioprine/MTX: folate 5mg/day. Monitor glucose (steroids). Renal involvement (GPA, MPA): apply renal restrictions. Alcohol: avoid (drug hepatotoxicity)."},"sarcoidosi":{"nome":"Sarcoidosis","desc":"Diet to prevent renal calculi from hypercalciuria and manage the calcium dysregulation typical of sarcoidosis.","note":"ATS/ERS 2022. Granulomas autonomously produce active vitamin D (1,25-OH-D) → hypercalcemia/hypercalciuria in 30-50%. Vitamin D3: AVOID supplements if 25-OH-D normal (paradox). Dietary calcium: reduce to 500-600mg/day. Fluids ≥2.5L/day (dilution). Limited oxalates. Vitamin K2 100µg/day (ectopic calcifications). Corticosteroids: Ca+D only if documented iatrogenic hypocalcemia. Reduced caffeine. Alcohol: zero."},"dermatomiosite":{"nome":"Dermatomyositis / Polymyositis","desc":"High-protein anti-inflammatory diet to counter inflammatory myopathy and prevent corticosteroid-induced sarcopenia.","note":"EULAR 2023 · BSR 2022. Chronic muscle inflammation + steroid-induced catabolism → muscle atrophy. Protein 1.2-1.5 g/kg/day (essential goal). Leucine ≥3g/meal (muscle anabolism). Vitamin D target >40 ng/mL (deficiency myopathy). Calcium 1000-1200mg/day. Omega-3 EPA/DHA 3g/day. If dysphagia (cricopharyngeal): adapted IDDSI texture. Calcinosis: abundant fluids, vitamin K2. MTX: folate 5mg/day. Hydroxychloroquine: no dietary restriction."},"trapianto_fegato":{"nome":"Liver Transplant","desc":"Peri-operative and maintenance nutritional support after liver transplant to prevent rejection and metabolic complications.","note":"EASL 2019 · ESPEN 2019. Pre-transplant: correct malnutrition (present in 70-90%). Post-acute: 1.2-1.5 g/kg protein. Maintenance: immunosuppressants = AVOID grapefruit/non-acidic citrus (CYP3A4). Tacrolimus: yes with food, but consistently; no grapefruit/cranberry juice. Food safety: no raw foods for 3-6 months. Steroids: Na <2g, reduced sugars, Ca+D. Frequent post-transplant metabolic syndrome (monitor glucose, lipids). NODAT (post-transplant diabetes): low-GI CHO."},"nutrizione_uti":{"nome":"Nutrition in Intensive Care (ICU)","desc":"Specialized nutritional support for the critically ill patient in intensive care to prevent malnutrition and infectious complications.","note":"ESPEN 2023 · ASPEN 2022 (Critical Care). Early acute phase (days 1-2): 10-20 kcal/kg/day (intentionally hypocaloric). Late acute phase (days 3-7): 20-25 kcal/kg/day. Post-acute phase: 25-30 kcal/kg/day. Protein: 1.3-2.0 g/kg/day (increase progressively). Early enteral nutrition (within 24-48h if possible) vs PN. Glutamine 0.35 g/kg/day in major burns/polytrauma. Vitamin C 1-2g/day (sepsis). Zinc, selenium, vitamin D: supplement. Monitor glucose (target 140-180 mg/dL). Refeeding syndrome: watch for."},"nutrizione_palliativa":{"nome":"Palliative Nutrition","desc":"Nutritional support centered on quality of life and comfort in advanced-stage oncologic and non-oncologic patients.","note":"ESPEN 2021 · EAPC 2021. Goal: quality of life, not life prolongation. Prognosis >3 months: active nutritional support (ONS, EN). Prognosis <1 month: minimal rehydration, food for pleasure. Symptoms to treat: nausea (antiemetics), anorexia (manage expectations), xerostomia (ice, ice cream, cold liquids), mucositis (soft cold foods). No compulsive feeding. Shared decision-making with patient and family. Terminal overhydration: NO (increases dyspnea and secretions). Final fasting is normal and does not cause additional suffering."},"ipertensione_polmonare":{"nome":"Pulmonary Arterial Hypertension","desc":"Low-sodium, low-fluid diet to prevent right ventricular overload and worsening cardiopulmonary function.","note":"ESC/ERS 2022. Sodium <1.5-2g/day (fluid retention worsens RV failure). Fluids 1.5-2L/day. Iron: monitor (deficiency worsens prognosis); supplement if ferritin <100µg/L even without anemia. Omega-3 2g/day. Avoid high altitudes (>1500m increases pulmonary vasoconstriction). Alcohol: drastically reduce (myocardial depression). Moderate physical activity recommended. Warfarin/anticoagulants: constant vitamin K. Sildenafil/tadalafil: no grapefruit juice."},"asma_bronchiale":{"nome":"Bronchial Asthma","desc":"Anti-inflammatory diet to reduce airway inflammation and prevent asthma exacerbations.","note":"GINA 2023 · Thorax 2022. Mediterranean diet: reduces symptoms by 30% (meta-analysis). Omega-3 EPA/DHA 2-3g/day (anti-leukotriene). Vitamin D target >40 ng/mL (meta-analysis: reduces exacerbations by 50%). Vitamin C 500mg/day (bronchial antioxidant). Magnesium 300-400mg/day (bronchodilator). Quercetin 500mg/day (stabilizes mast cells). Sulfites (E220-228): avoid (sulfite-sensitive asthma). Aspirin/NSAIDs: caution with ASA triad. Obesity: 5-10% weight loss improves symptoms. Alcohol: avoid red wine (sulfites + histamine). Natural salicylates: monitor in severe asthma."},"bronchiectasie":{"nome":"Bronchiectasis","desc":"High-calorie, high-protein diet to counter increased energy requirements and prevent malnutrition in bronchiectasis.","note":"ERS 2017 · BTS 2019. Energy requirement increased by 20-30% (work of breathing, chronic inflammation). Protein 1.2-1.5 g/kg/day. Omega-3 EPA/DHA 2g/day. Vitamin D target >30 ng/mL. Zinc 15mg/day (immune function). Antioxidants: vitamin C 500mg, vitamin E 200 IU. If cystic fibrosis: follow CF guidelines. If overlapping COPD: limited CHO. Abundant hydration (secretion thinning). Mucoviscidosis overlap: pancreatic enzymes. ONS if losing weight."},"acidemia_metilmalonica":{"nome":"Methylmalonic Acidemia (MMA)","desc":"Diet with reduced intake of propionate precursors and support with specific cofactors for the enzyme defect.","note":"ACMG 2022 · SSIEM 2020. Restrict: isoleucine, valine, threonine, methionine (propionyl-CoA precursors). IVMT-free formula (isoleucine+valine+methionine+threonine): main protein source. Vitamin B12 (hydroxocobalamin) 1-2 mg IM/week: effective in 40% (cobalamin-responsive forms). Carnitine 100 mg/kg/day (chronic depletion). L-Leucine: allowed. Intermittent metronidazole: reduces propionate-producing gut bacteria. Metabolic crisis: high-flow IV glucose + insulin, stop protein. Renal/liver transplant: therapeutic option. Monitor: ammonia, lactate, B12, carnitine."},"sindrome_down":{"nome":"Nutrition in Down Syndrome","desc":"Balanced, personalized diet to manage overweight, hypothyroidism, celiac disease and frequent nutritional deficiencies in Down syndrome.","note":"JIDSA 2022 · ESPGHAN 2022. Overweight/obesity: prevalence 50-70% → low caloric density diet (vegetables ad libitum). Subclinical hypothyroidism in 30%: monitor TSH. Celiac disease: 5-12% → mandatory tTG antibody screening. Vitamin D 800-2000 IU/day (almost universally deficient). Omega-3 DHA (cognitive development). Calcium 1000-1200mg/day (early osteoporosis). Chewing often impaired: adapted texture. Vitamin B6, zinc, selenium monitored. Avoid ultra-processed foods. Physical activity included in the plan."},"fibrosi_polmonare":{"nome":"Idiopathic Pulmonary Fibrosis (IPF)","desc":"High-calorie, antioxidant diet to counter respiratory cachexia and reduce oxidative stress in pulmonary fibrosis.","note":"ATS/ERS 2022 · ERS 2022. Requirement increased by 20-30% (chronic dyspnea). Malnutrition in 50-80% of patients. Protein 1.2-1.5 g/kg/day. Antioxidants: vitamin C 1g/day, vitamin E 400IU, N-acetylcysteine (NAC) 600mg 3x/day (former therapy, now controversial). Omega-3 EPA/DHA 2g/day. Vitamin D target >30 ng/mL. Not excessive CHO (increase CO2). Fat 35-40% en (favors oxygenation). Moderate fiber. Small frequent meals (5-6/day). Oxygen therapy during meals if saturation <88%."},"emofilia":{"nome":"Hemophilia A and B","desc":"Diet to maintain ideal body weight, reduce hemarthrosis risk and support joint and bone health.","note":"WFH 2020 · Haemophilia Journal. Overweight worsens hemarthrosis (joint load). BMI target 20-25. Vitamin K: not contraindicated (hemophilia is a factor VIII/IX defect, not vitamin K-dependent). Calcium 1000-1200mg/day + Vitamin D (osteoporosis from recurrent hemarthrosis, immobility). Omega-3 2g/day (anti-inflammatory, synovial). Iron: monitor (bleeding losses). Alcohol: limit (liver bleeding risk). NSAIDs: CONTRAINDICATED (use paracetamol). Hard/crunchy foods: increase oral bleeding risk → chew carefully. Maintaining ideal weight: primary goal."},"cistinuria":{"nome":"Cystinuria","desc":"Low-methionine, alkalinizing, low-osmolar diet to prevent cystine stone formation.","note":"EAU 2022 · CKJD 2021. ABUNDANT fluids: ≥3-4L/day (goal: diluted urine <300 mg cystine/L). Alkaline urine: target pH 7.0-7.5 (oral sodium bicarbonate). Methionine: limit precursors → red meat, fish, eggs, soy (limit; do not eliminate). Salt <2g/day (sodium-dependent cystine excretion). Vitamin C: AVOID (acidifies urine). Adequate folate. Potassium citrate 60-80 mEq/day (alkalinizing). D-penicillamine or tiopronin if diet ineffective."},"sindrome_antifosfolipidi":{"nome":"Antiphospholipid Syndrome (APS)","desc":"Diet to manage anticoagulant therapy and reduce thrombotic and cardiovascular risk in antiphospholipid syndrome.","note":"EULAR 2023 · CAPS Registry. Warfarin (main anticoagulant): CONSTANT vitamin K (do not eliminate). Leafy greens: 1-2 constant servings/day. INR target 2.5-3.5 (high risk). Omega-3 EPA/DHA 2-3g/day (anti-platelet aggregation, anti-inflammatory). Mediterranean diet reduces CV risk. Homocysteine: control with folate, B6, B12. Alcohol: avoid (unstable warfarin). No grapefruit (inhibits CYP2C9 = warfarin metabolism). NOACs (apixaban, rivaroxaban): no dietary restriction. Pregnancy with APS: low-dose aspirin + LMWH."},"ipercalcemia":{"nome":"Hypercalcemia","desc":"Diet to reduce intestinal calcium absorption and promote renal excretion in hypercalcemic syndromes.","note":"ENDO 2022 · AACE 2021. Causes: primary hyperparathyroidism (50%), malignancy (25%), sarcoidosis, vitamin D intoxication. Abundant fluids: 2.5-3L/day (dilution and renal clearance). Dietary calcium: reduce to 500-600mg/day (intestinal absorption contributes). Vitamin D: AVOID supplements if Ca>10.5 mg/dL. Oxalates: not restrictive (calcium-free foods favored). Moderate salt. Dietary fiber reduces Ca absorption. Adequate phosphorus (binds calcium). Alcohol: avoid (osmotic diuresis). Prednisone: reduces 1-alpha-hydroxylase (sarcoidosis)."},"obesita_sarcopenica":{"nome":"Sarcopenic Obesity","desc":"Low-calorie, high-protein diet to reduce fat mass while preserving (or increasing) muscle mass.","note":"ESPEN 2022 · EASO 2022. Conventional caloric restriction also reduces lean mass (dangerous in sarcopenic patients). Protein 1.2-1.5 g/kg ideal weight/day (preserves muscle). Leucine ≥3g/meal. Moderate caloric deficit: -500 kcal/day (never <1200F/1500M kcal). Vitamin D 2000 IU/day (both for muscle and fat reduction). Calcium 1000-1200mg/day. Omega-3 2g/day (anti-inflammatory + anti-sarcopenic). RESISTANCE EXERCISE: essential (without exercise diet alone does not resolve sarcopenia). Monitor: DEXA (lean and fat mass), handgrip strength, gait speed."},"nutrizione_atleta":{"nome":"Sports Nutrition / Athlete","desc":"Personalized diet to optimize athletic performance, muscle recovery and body composition of the athlete.","note":"IOC 2021 · ISSN 2017. CHO: 5-12g/kg/day (adapted to training volume/intensity). Protein: 1.4-2.0 g/kg/day. Fat: 20-35% en. Timing: CHO+Protein within 30-60 min post-training (anabolic window). Creatine 3-5g/day: grade A ergogenic (strength + mass). Caffeine 3-6 mg/kg pre-competition: grade A ergogenic (endurance). Beta-alanine 3-6g/day (lactate buffer). Hydration: 500ml 2h before, replace losses during. Vitamin D target >40 ng/mL. Iron (endurance athletes, especially women): monitor ferritin. Energy availability (EA): >45 kcal/kg FFM/day (prevent RED-S)."},"diarrea_cronica":{"nome":"Chronic Functional Diarrhea","desc":"Targeted elimination diet and adequate rehydration to reduce stool frequency in chronic diarrhea.","note":"ACG 2022 · WGO 2021. Rule out organic causes (IBD, celiac disease, malabsorption, infections) before treating functional diarrhea. Low-FODMAP diet: 4-6 weeks then reintroduction (effective in 70% of IBS-D). Lactose: 2-week exclusion test. Excess free fructose: limit. Insoluble fiber: reduce in the acute phase (adds fecal bulk). Psyllium: ok (gelling soluble fiber). Hydration: ORS (Oral Rehydration Solution) 1-2L/day. Probiotics: S. boulardii 500mg 2x/day (grade A evidence). Small frequent meals. Alcohol/caffeine: drastically reduce."},"digiuno_intermittente":{"nome":"Intermittent Fasting (IF 16:8 / 5:2)","desc":"Eating pattern with an extended fasting window. 16:8: 16h fast, eating in an 8h window. 5:2: 2 days/week at ~500 kcal. Growing evidence for metabolism, weight loss and longevity.","note":"Contraindicated in pregnancy, eating disorders, unmonitored insulin-dependent diabetes, BMI<18.5. Not recommended under 18 years of age. Abundant hydration during fasting hours."},"dieta_mediterranea":{"nome":"Mediterranean Diet (Optimal Pattern)","desc":"Traditional eating pattern of Mediterranean countries. High adherence associated with a -30% reduction in cardiovascular events (PREDIMED study). Basis of the LARN National Recommended Diet.","note":"MedScore ≥9/14 associated with maximum benefits. Favor EVO oil, oily fish, legumes, whole grains, seasonal vegetables and fruit. Moderate red wine (optional, with meals)."},"nutrizione_enterale":{"nome":"Home Enteral Nutrition (HEN)","desc":"Artificial nutrition via nasogastric tube, PEG or jejunostomy in patients unable to feed orally. First choice over parenteral nutrition if the GI tract is functioning.","note":"Standard formulas: 1 kcal/ml, 1.5 kcal/ml (high-energy), high-protein (≥20% energy). Infusion rate: start at 20-25 ml/h, gradual increase. Monitor gastric residual every 4h in ICU."},"nutrizione_parenterale":{"nome":"Total Parenteral Nutrition (TPN)","desc":"Intravenous nutrition in patients with a non-functioning or contraindicated GI tract. 3-in-1 bags (glucose + amino acids + lipids). Administered via central venous catheter or PICC.","note":"Standard requirement: 25-30 kcal/kg/day, protein 1.2-1.5 g/kg/day. Monitor glucose (target 140-180 mg/dL in ICU), electrolytes, liver function, triglycerides. Risk of complications: CVC infections, hepatic steatosis."},"ustioni_gravi":{"nome":"Severe Burns (>20% BSA)","desc":"Severe burns induce the most marked hypermetabolic state in medicine. Energy expenditure 150-200% of baseline in the first weeks. Early nutrition (within 6-12h of the event) is essential.","note":"Curreri formula for energy: (25×kg) + (40×%BSA). Protein: 1.5-2.5 g/kg/day. IV/enteral glutamine 0.3-0.5 g/kg/day. Vitamin C 66 mg/kg/day (first 24h for edema). Zinc, vitamin D, folate."},"sepsi":{"nome":"Sepsis / Septic Shock","desc":"In sepsis and septic shock, nutrition must be early but cautious. Early acute phase (first 48h): hypocaloric (70% of requirement) to respect the protective catabolic response. Subacute phase: full nutrition.","note":"Acute phase day 1-2: no more than 20 kcal/kg/day. From day 3: 25-30 kcal/kg/day. Protein: 1.2-1.5 g/kg/day, increase progressively. Glutamine contraindicated in MOF/shock. Prefer EN over PN."},"tumori_net":{"nome":"Neuroendocrine Tumors (NET / Carcinoid)","desc":"Secreting NETs (carcinoid syndrome) require a low-tyramine, low-tryptophan diet to reduce serotonin production. Functioning pancreatic NETs require specific adaptations.","note":"Carcinoid syndrome: avoid alcohol, aged cheeses, tyramine-rich foods. Hypoglycemic NET (insulinoma): frequent meals, slow-release carbohydrates. Frequent niacin deficiency (pellagra): supplement B3."},"leucemia":{"nome":"Acute / Chronic Leukemia (Nutritional Support)","desc":"Leukemia patients during chemotherapy are at high risk of malnutrition due to mucositis, nausea, anorexia. Neutropenic diet during periods of severe aplasia (ANC<500). Need for high caloric and protein density.","note":"Neutropenic diet: avoid raw foods, unpasteurized soft cheeses, raw salads, sushi, sprouts. Meat internal temperature ≥74°C. No unpeeled fruit. Target: 30-35 kcal/kg, 1.5-2 g protein/kg."},"linfoma":{"nome":"Lymphoma (Hodgkin and Non-Hodgkin)","desc":"Lymphomas during chemotherapy cause hypermetabolism, muscle wasting and immunosuppression. Nutritional targets similar to leukemia. Attention to drug-food interactions (MTX, rituximab).","note":"Methotrexate: reduce alcohol, limit dietary folate on therapy days (only if prescribed). Corticosteroids: low-sodium diet, low-glycemic-index carbohydrates. High protein requirement."},"trapianto_cuore":{"nome":"Heart Transplant (Post-Operative)","desc":"Post-cardiac transplant: long-term immunosuppression with tacrolimus/cyclosporine requires avoiding grapefruit and grapefruit juice. Risk of metabolic syndrome from chronic corticosteroids.","note":"Avoid: grapefruit, bergamot, pomegranate (inhibit CYP3A4 → tacrolimus toxicity). Reduce sodium for cyclosporine-induced hypertension. Monitor hyperkalemia if on ACE inhibitors. Low-fat diet post-transplant."},"rene_policistico":{"nome":"Polycystic Kidney Disease (ADPKD)","desc":"Autosomal dominant PKD requires progressive renal monitoring. Diet should support residual renal function and potentially slow cyst growth. High hydration recommended.","note":"High hydration (2.5-3L/day) to dilute ADH and reduce cyst growth. Salt <5g/day (reduces intra-renal cAMP). Moderate protein 0.8 g/kg/day if normal GFR. Caffeine <300 mg/day (reduces cAMP)."},"deficit_zinco":{"nome":"Zinc Deficiency","desc":"Zinc deficiency causes immune alterations (lymphopenia), perioral and acral dermatitis, alopecia, hypogeusia. Frequent in malnutrition, celiac disease, IBD, chronic alcoholism, institutionalized elderly.","note":"Adult requirement: 8-11 mg/day. Therapeutic supplement: 25-40 mg/day elemental zinc × 3-6 months. Phytates in whole grains reduce absorption (improve by soaking legumes). Excess zinc: copper inhibitor."},"deficit_iodio":{"nome":"Iodine Deficiency / Endemic Goiter","desc":"Iodine deficiency causes endemic goiter and cretinism if severe during pregnancy. Main preventable cause of mental retardation worldwide. In Italy, endemic goiter still present in Alpine and Apennine areas.","note":"Adult requirement: 150 μg/day. Pregnancy/breastfeeding: 200-250 μg/day. Iodized salt ≈ 30 μg of iodine per gram. Goitrogens (cabbage, broccoli, soy, millet) reduce iodine utilization: cooking activates them."},"anemia_falciforme":{"nome":"Sickle Cell Disease (SCD)","desc":"Patients with sickle cell disease have increased nutritional requirements due to chronic hemolysis and inflammation. High cell turnover requires folate, zinc and vitamin B12. Adequate hydration prevents crises.","note":"Folate: 1-5 mg/day supplement (increased consumption for erythropoiesis). Zinc: 25 mg/day (frequent deficiency, reduces hemolysis and infections). Vitamin D: often deficient (95% of patients). Omega-3 reduce viscosity."},"abuso_alcol":{"nome":"Alcohol Use Disorder (AUD)","desc":"AUD causes multiple malnutrition: thiamine deficiency (Wernicke), folate, zinc, magnesium, vitamin B6/B12. Often accompanied by steatosis, alcoholic hepatitis and cirrhosis with further malnutrition.","note":"Absolute priority: IV thiamine before glucose (Wernicke prevention). Folate 5 mg/day. Zinc 220 mg/day. Magnesium if hypomagnesemia. Gradual refeeding (refeeding risk if prolonged fasting). Abstinence = goal."},"distrofia_muscolare":{"nome":"Muscular Dystrophy (Duchenne/Becker)","desc":"Duchenne muscular dystrophy (DMD) causes progressive muscle decline with risk of malnutrition from progressive dysphagia and hypometabolism due to reduced active mass. Corticosteroid treatment worsens weight and metabolism.","note":"Chronic corticosteroids: low-calorie, low-sodium, high calcium/vitamin D diet. Dysphagia: texture modifications (IDDSI), thickeners. Frequent obesity from hypomobility. Constipation: high fiber and hydration."},"alimentazione_complementare":{"nome":"Weaning / Complementary Feeding (6-12 months)","desc":"Complementary feeding begins around 6 months (not before 4 months) with gradual food introduction. Breast milk or formula remains the main source up to 12 months. Prevents allergies, overweight and deficiencies.","note":"Iron: critical food — introduce meat, legumes, fortified cereals early. Allergens: introduce early (peanuts, eggs, fish) to reduce allergies. Avoid: honey (<1 year), salt, sugar, whole cow's milk (<12m)."},"sindrome_premestruale":{"nome":"Premenstrual Syndrome (PMS / PMDD)","desc":"PMS affects 75% of women of reproductive age; PMDD (severe form) 5-8%. Symptoms: bloating, irritability, sweet cravings, headache, mastalgia. Nutrition and supplements reduce symptoms by 30-50%.","note":"Magnesium 200-400 mg/day: reduces fluid retention and irritability. Calcium 1000-1200 mg/day: reduces mood symptoms. Vitamin B6 50-100 mg/day: improves mood. Reduce sodium, caffeine, alcohol in the luteal phase."},"infertilita_nutrizione":{"nome":"Infertility: Nutritional Support","desc":"Diet influences both female and male fertility. Mediterranean diet associated with +40% probability of pregnancy in IVF. Obesity reduces fertility; optimal BMI 20-25. Folate deficiency increases NTD risk.","note":"Folate: 400-800 μg/day pre-conception and 1st trimester. Omega-3 improve oocyte and sperm quality. CoQ10 200-600 mg/day may improve ovarian reserve. Vitamin D: correct deficiency. Alcohol: zero pre-conception."},"ortoressia":{"nome":"Orthorexia Nervosa (ON)","desc":"Orthorexia is an obsessive preoccupation with \"healthy\" eating that compromises quality of life, social relationships and often leads to real nutritional deficiencies. Not classified in DSM-5 but clinically recognized.","note":"Approach: gradual nutritional rehabilitation without anxiety triggers, CBT psychotherapy, progressive reintroduction of \"forbidden\" foods. Avoid unnecessary elimination diets. Goal = dietary flexibility."},"microbiota_intestinale":{"nome":"Gut Microbiota Support","desc":"The gut microbiota influences immunity, metabolism, mood (gut-brain axis) and chronic disease risk. A diet rich in diverse fibers and fermented foods increases microbial diversity.","note":"Goal: >30 different plant types/week (APC study). Fermented foods: yogurt, kefir, kimchi, miso, tempeh. Prebiotic fiber: inulin (chicory, Jerusalem artichoke), FOS, pectins. Antibiotics: disrupt microbiota — support afterward."},"politrauma":{"nome":"Polytrauma / Severe Traumatic Brain Injury (TBI)","desc":"Polytrauma and severe traumatic brain injury induce an intense hypermetabolic state (up to 2× BMR in the first 2 weeks). Early nutrition (within 24-48h) reduces mortality and infectious complications.","note":"Severe TBI: 140% of REE in the first weeks. Protein: 1.5-2.5 g/kg/day. Enteral glutamine 0.3-0.5 g/kg/day. Omega-3 (DHA) for neuroprotection. Vitamin D and zinc for bone healing. Hypoglycemia increases mortality."},"rachitismo_osteomalacia":{"nome":"Rickets / Osteomalacia","desc":"Rickets (children) and osteomalacia (adults) are caused by vitamin D and/or calcium deficiency resulting in defective bone mineralization. Prevalent in populations that cover skin, have low sun exposure, or follow a dairy-free diet.","note":"Treatment: vitamin D3 50,000 IU/week × 8 weeks, then maintenance 1500-2000 IU/day. Calcium 1000-1500 mg/day. Adequate phosphorus. Avoid excess phytates (reduces Ca absorption). Moderate sun exposure."},"deficit_tiamina":{"nome":"Thiamine B1 Deficiency / Wernicke's Encephalopathy","desc":"Thiamine (vitamin B1) deficiency causes Wernicke-Korsakoff syndrome (confusion, ataxia, nystagmus) in chronic alcoholics and patients on parenteral nutrition without thiamine. Clinical emergency — requires immediate IV thiamine.","note":"Urgent treatment: IV thiamine 200-500 mg 3x/day × 3-5 days, then 100 mg/day orally. NEVER glucose before thiamine! RDA requirement 1.1-1.2 mg/day. Causes: alcoholism, bariatric surgery, TPN without vitamins, hyperemesis gravidarum."},"celiachia_bambini":{"nome":"Pediatric Celiac Disease","desc":"Celiac disease in children often presents with diarrhea, failure to thrive, iron-deficiency anemia, abdominal distension. Strict GFD normalizes growth and prevents complications. Diagnosis: anti-tTG IgA + biopsy (Marsh ≥2).","note":"Strict GFD (cross-contamination <20 ppm). Allowed foods: rice, corn, potatoes, buckwheat, quinoa, amaranth, millet. Monitor iron, folate, vitamin D, zinc (often deficient at onset). Growth and bone density."},"deficit_vitamina_a":{"nome":"Vitamin A Deficiency","desc":"Hypovitaminosis A: night blindness, xerophthalmia, increased susceptibility to infections. Cause: retinol/beta-carotene-poor diet, fat malabsorption, alcoholism.","note":"WHO 2023. Supplementation 200,000 IU/2 months (at-risk countries). In Italy: the main cause is malabsorption or a very restrictive diet."},"deficit_vitamina_c":{"nome":"Vitamin C Deficiency (Scurvy)","desc":"Scurvy: gum bleeding, petechiae, delayed wound healing, fatigue. Rare in Italy but present in the elderly, alcoholics, very restricted diets.","note":"EFSA 2013. RDA: 80-90 mg/day adults, 35 mg/day additional for smokers. Tissue saturation at ~250 mg/day."},"deficit_vitamina_e":{"nome":"Vitamin E Deficiency","desc":"Hypovitaminosis E: peripheral neuropathy, myopathy, hemolysis, reduced immunity. Almost always caused by fat malabsorption (cystic fibrosis, cholestasis, SBS).","note":"EFSA 2015. RDA 12 mg α-TE/day. Primary dietary deficiency very rare in healthy Italian adults."},"deficit_vitamina_k":{"nome":"Vitamin K Deficiency","desc":"Hypovitaminosis K: impaired coagulation (increased INR/PT), bleeding. Causes: prolonged antibiotics, fat malabsorption, unvaccinated newborns, warfarin therapy.","note":"EFSA 2017. RDA 70 µg/day. K1 (phylloquinone) from green vegetables; K2 (menaquinone) from fermented foods and dairy."},"deficit_niacina":{"nome":"Pellagra / Niacin (B3) Deficiency","desc":"Pellagra: the \"3 D's\" — photosensitive Dermatitis, Diarrhea, Dementia. Historically in maize-dependent populations without protein diversity; today in alcoholism, malabsorption, tryptophan load.","note":"WHO 2000. Niacin RDA 16 mg NE/day (M), 14 mg NE/day (F). Tryptophan is a precursor: 60 mg trp → 1 mg niacin."},"deficit_riboflavina":{"nome":"Riboflavin (Vitamin B2) Deficiency","desc":"Ariboflavinosis: cheilosis, glossitis, seborrheic dermatitis, photophobia, normocytic anemia. Often associated with other B-group deficiencies.","note":"EFSA 2017. RDA 1.6 mg/day (M), 1.3 mg/day (F). Riboflavin is light-sensitive — store milk away from light."},"deficit_biotina":{"nome":"Biotin (Vitamin B7) Deficiency","desc":"Dermatitis, alopecia, conjunctivitis, organic acidosis, neuropathy. Causes: avidinism (raw egg white), biotin-free parenteral nutrition, drugs (antiepileptics).","note":"EFSA 2014. AI 40 µg/day. Biotinidase deficiency: rare genetic cause (newborn screening)."},"deficit_magnesio":{"nome":"Hypomagnesemia / Magnesium Deficiency","desc":"Tremors, muscle cramps, arrhythmias, neuromuscular hyperexcitability, refractory hypocalcemia. Common in: diabetes, alcoholism, chronic diarrhea, PPI/diuretic use.","note":"EFSA 2015. RDA 300-350 mg/day. Hypomagnesemia <0.7 mmol/L. Often coexists with hypokalemia."},"deficit_calcio":{"nome":"Hypocalcemia / Calcium Deficiency","desc":"Muscle cramps (tetany), perioral paresthesias, Chvostek and Trousseau signs, arrhythmias. Causes: hypoparathyroidism, vitamin D deficiency, malabsorption, renal failure.","note":"EFSA 2015. RDA 1000-1200 mg/day. Total calcemia <2.1 mmol/L. Distinguish from osteoporosis (chronic deficiency without acute hypocalcemia)."},"deficit_rame":{"nome":"Copper Deficiency","desc":"Normocytic anemia, neutropenia, progressive myelopathy (similar to B12 deficiency), osteoporosis. Causes: zinc excess, bariatric surgery, malabsorption, copper-free PN.","note":"EFSA 2015. RDA 1.3-1.5 mg/day. Normal copper level: 12-22 µmol/L. Excess zinc reduces copper absorption."},"omocistinuria":{"nome":"Homocystinuria","desc":"Cystathionine β-synthase (CBS) deficiency → homocysteine accumulation. Manifestations: ectopia lentis, thromboembolism, marfanoid skeleton, cognitive delay. B6-responsive and non-responsive forms.","note":"ESIEM/MetabERN 2022. B6-responsive forms: pyridoxine 100-1000 mg/day. Non-responsive forms: low-methionine diet + betaine + folate + B12."},"glicogenosi_iii":{"nome":"Glycogen Storage Disease Type III (Cori/Forbes)","desc":"Debranching enzyme (AGL) deficiency. Involves liver, muscle and heart. Fasting hypoglycemia, hepatomegaly, myopathy. Unlike GSD I, lactate does not accumulate.","note":"ESIEM 2023. Diet: slow-release starch (raw cornstarch), high protein for muscle, avoid prolonged fasting."},"glicogenosi_v":{"nome":"Glycogen Storage Disease Type V (McArdle)","desc":"Muscle myophosphorylase deficiency → inability to use glycogen during exercise. Exercise intolerance, cramps, myoglobinuria (red urine). \"Second wind\" phenomenon.","note":"Quinlivan et al., Brain 2010. Nutritional approach: carbohydrates before and during exercise. Creatine and vitamin B6 studied."},"acidemia_propionica":{"nome":"Propionic Acidemia","desc":"Propionyl-CoA carboxylase deficiency → propionic acid accumulation. Neonatal metabolic emergencies, cardiomyopathy, pancreatitis, immunodeficiency. Severe prognosis without early treatment.","note":"Baumgartner 2014 (JIMD). Restriction of propiogenic amino acids (isoleucine, valine, threonine, methionine). Specific formula without propiogenic AAs."},"malattia_gaucher":{"nome":"Gaucher Disease","desc":"Lysosomal storage disorder with glucocerebrosidase deficiency → glucosylceramide accumulation. Splenomegaly, hepatomegaly, cytopenias, bone lesions. Main treatment: enzyme replacement therapy (ERT).","note":"EMQN/Gaucher Alliance 2022. Nutritional support: anemia, osteopenia/porosis, vitamin D and B12 deficiency."},"esofagite_eosinofila":{"nome":"Eosinophilic Esophagitis (EoE)","desc":"Chronic eosinophilic inflammation of the esophagus → dysphagia, impaction, refractory reflux. Closely related to food allergies. Gold standard: >15 eosinophils/HPF on biopsy.","note":"AGREE 2022/UEG 2022. Empiric elimination diet (SFED: 6 foods) or step-up approach. 8-week PPI trial before the diet."},"dieta_chetogenica":{"nome":"Therapeutic Ketogenic Diet","desc":"Very high-fat diet (70-80% kcal), moderate protein, very low carbohydrate (<50g/day). Clinical uses: refractory epilepsy, GLUT1 deficiency, brain tumors, neurodegeneration.","note":"ILAE/Charlie Foundation 2022. Classic ratio 4:1 (fat:carbohydrate+protein). MCT-KD and MAD as variants. Monitoring: urinary/blood ketones."},"dieta_dash":{"nome":"DASH Diet","desc":"Dietary Approaches to Stop Hypertension. Also effective for dyslipidemia, type 2 diabetes, cardiovascular prevention. Systolic reduction up to 11 mmHg in hypertensive patients.","note":"NHLBI 2021/AHA 2021. Sodium restriction: 1500-2300 mg/day. 8-10 servings of fruit and vegetables/day. Low-fat dairy 2-3 servings."},"dieta_antiinfiammatoria":{"nome":"Anti-Inflammatory Diet","desc":"Eating pattern rich in polyphenols, omega-3, fiber and antioxidants that reduces systemic inflammation markers (CRP, IL-6, TNF-α). Effective in preventing chronic diseases.","note":"Calder 2017 (Nature Reviews). Base: Mediterranean diet + key anti-inflammatory foods + UPF reduction."},"prevenzione_oncologica":{"nome":"Cancer Preventive Nutrition","desc":"Eating style based on WCRF/AICR recommendations to reduce the risk of developing cancer. Goal: not eliminate all risk but reduce it significantly.","note":"WCRF/AICR Cancer Prevention Recommendations 2018 (updated 2023). Estimate: 30-40% of cancers preventable through diet, weight and physical activity."},"cachessia_oncologica":{"nome":"Cancer Cachexia","desc":"Multifactorial metabolic syndrome: weight loss >5% in 6 months (or >2% with BMI<20), loss of muscle mass, resistance to refeeding. Present in 50-80% of advanced-stage cancer patients.","note":"Fearon 2011 (Lancet Oncology). Diagnostic criteria: loss >5% in 6 months; or BMI<20 with loss >2%; or low ASMI with loss >2%."},"sindrome_lisi_tumorale":{"nome":"Tumor Lysis Syndrome (TLS)","desc":"Oncologic emergency during chemotherapy: massive cell lysis → hyperkalemia, hyperphosphatemia, hyperuricemia, hypocalcemia. Risk: leukemias, lymphomas, rapidly proliferating tumors.","note":"Cairo-Bishop 2004 (updated Howard 2011). Prevention: IV hydration, allopurinol/rasburicase, electrolyte monitoring every 6-8h."},"artrite_idiopatica_giovanile":{"nome":"Juvenile Idiopathic Arthritis (JIA)","desc":"Chronic inflammatory arthritis with onset before age 16. Various subtypes (oligoarticular, polyarticular, systemic). Impact on growth, nutrition, bone mass.","note":"EULAR/ACR 2019. Nutritional support: optimize growth, protect bone, reduce inflammation through diet."},"sport_endurance":{"nome":"Endurance Sports Nutrition","desc":"Nutrition for prolonged endurance sports: marathon, triathlon, cycling, cross-country skiing. High energy expenditure, need for carb-loading, fluid-electrolyte management.","note":"ISSN 2021/ACSM 2022. CHO target: 7-10 g/kg/day during intense training, 10-12 g/kg 36-48h before competition."},"sport_forza":{"nome":"Strength Sports Nutrition","desc":"Nutrition for strength/power sports: weightlifting, bodybuilding, CrossFit, power athletics. Focus on protein synthesis, recovery and body composition.","note":"ISSN 2022/Phillips 2016. Protein: 1.6-2.2 g/kg/day. Distribution: 4 meals of 0.4 g/kg. Leucine threshold: 2-3g for MPS stimulus."},"lipodistrofia":{"nome":"Lipodystrophy","desc":"Selective loss of subcutaneous adipose tissue with visceral accumulation, severe insulin resistance, dyslipidemia, hepatic steatosis. Genetic forms (Berardinelli-Seip, Familial) or acquired (HIV-HAART therapy).","note":"Akinci 2022 (Nature Reviews Endocrinology). Diet: essential for managing often severe hypertriglyceridemia and insulin resistance."},"sindrome_gilbert":{"nome":"Gilbert's Syndrome","desc":"Benign unconjugated hyperbilirubinemia from reduced UGT1A1 activity. Intermittent functional jaundice, accentuated by fasting, stress, infections, alcohol. No chronic liver damage.","note":"Bosma 1995. Prevalence ~5-10% of the general population. Excellent prognosis — no treatment necessary but avoid triggers."},"iperfosfatemia":{"nome":"Hyperphosphatemia","desc":"Serum phosphate >4.5 mg/dl (1.45 mmol/L). Common in dialysis and advanced CKD. Causes: vascular calcifications, secondary hyperparathyroidism, cardiovascular disease. Requires specific dietary management.","note":"KDIGO 2017. Target serum phosphorus: 3.5-5.5 mg/dl on dialysis. Binder timing: with meals to maximize efficacy."},"nutrizione_geriatrica_rsa":{"nome":"Nutrition in Nursing Homes / Long-Term Care","desc":"Institutionalized elderly patients with multiple comorbidities, polypharmacy, reduced autonomy, often with dysphagia and malnutrition. High risk of iatrogenic nutritional decline.","note":"ESPEN 2020/SINPE 2021. Screening: MNA-SF every 3 months. Protein target: 1.2-1.5 g/kg/day. High energy density with small volumes."},"anemia_emolitica":{"nome":"Hemolytic Anemia","desc":"Premature destruction of red blood cells (half-life <120 days). Causes: autoimmune (AIHA), hereditary (G6PD favism, spherocytosis, thalassemia), mechanical, drugs. Manifestations: anemia, jaundice, splenomegaly.","note":"ASH 2018. Nutritional support: folate (increased consumption from erythropoiesis), vitamin B12, vitamin E (antioxidant), iron with caution (overload)."},"allergia_soia":{"nome":"Soy Allergy","desc":"Allergy to soy (Glycine max). Among the 14 main EU allergens. IgE-mediated or non-IgE-mediated reaction.","note":"EAACI 2019. Complete elimination of soy and derivatives. Cross-reactivity with peanuts (20-30%). Hidden soy in: tofu, tempeh, edamame, miso, tamari, soy milk, margarines, packaged products."},"allergia_sedano":{"nome":"Celery Allergy","desc":"Allergy to celery (Apium graveolens). One of the 14 main EU allergens. Cross-reactivity with birch, carrot, parsley (birch-fruit syndrome).","note":"EAACI 2019. Eliminate celery, celeriac, celery roots, celery seeds. Cross-reactivity: carrots, parsley, anise, cumin, coriander. Present in soups, stock cubes, sauces."},"allergia_senape":{"nome":"Mustard Allergy","desc":"Allergy to mustard (Sinapis alba, Brassica). One of the 14 main EU allergens. Cross-reactivity with pollens.","note":"EAACI 2019. Eliminate mustard in seeds, flour, oil, sauce, curry preparations. Present in: mayonnaise, prepared sauces, condiments, some margarines, baked goods. Cross-reactivity with rapeseed."},"allergia_lupino":{"nome":"Lupin Allergy","desc":"Allergy to lupin (Lupinus albus). One of the 14 main EU allergens. High cross-reactivity with peanuts (30-50%).","note":"EAACI 2019. Eliminate lupin flour present in: bread, pasta, organic baked goods. Elevated risk in those allergic to peanuts. Lupin present in alternative \"natural\" flours — always read labels."},"allergia_solfiti":{"nome":"Sulfite Allergy/Intolerance","desc":"Adverse reaction to sulfites (E220-E228): sulfur dioxide, metabisulfite. Non-IgE-mediated pseudo-allergy.","note":"EAACI/FDA 2019. Reaction threshold: 10-50mg SO₂/kg. Sulfites in: wine, beer, dried fruit, shrimp and shellfish, fruit juices, canned foods, medications. Prevalence: 0.05% general population, 3-10% asthmatics."},"diabete_lada":{"nome":"LADA Diabetes (Latent Autoimmune Diabetes in Adults)","desc":"Slow-onset adult autoimmune diabetes. Hybrid T1+T2 features: positive anti-GAD antibodies, progression toward insulin dependence.","note":"ADA/EASD 2023. Often diagnosed as T2 but with anti-GAD+ or anti-IA2+. Diet: low GI, as for T1 diabetes. Progressive insulin deficiency. Monitor HbA1c, C-peptide, anti-GAD antibodies."},"tumore_rene":{"nome":"Renal Cell Carcinoma (RCC)","desc":"Nutritional support in renal cell carcinoma. Therapy: surgery (nephrectomy), immunotherapy (nivolumab, pembrolizumab), sunitinib/sorafenib.","note":"ESPEN 2021. Protein 1.2-1.5g/kg/day. Adequate hydration. Immunotherapy side effects: nausea, fatigue. Monitor creatinine and residual renal function. With sunitinib therapy: nausea, mucositis."},"tumore_tiroide":{"nome":"Thyroid Carcinoma (differentiated)","desc":"Nutritional support in differentiated thyroid carcinoma (papillary, follicular). Therapy: thyroidectomy, radioiodine (I-131).","note":"ESPEN/ETA 2021. Before radioiodine: low-iodine diet (LID) for 2-4 weeks (iodine <50µg/day). After thyroidectomy: calcium + vitamin D supplementation (hypoparathyroidism). Avoid iodine supplements."},"tumore_ovaio":{"nome":"Ovarian Carcinoma","desc":"Nutritional support in ovarian carcinoma. Chemotherapy: platinum+taxol. Risk of cachexia, ascites, bowel obstruction.","note":"ESPEN 2021. Frequent cachexia (60-80% of advanced cases). Chemo effects: nausea, vomiting, peripheral neuropathy. Enteral nutrition if intake <60% for >7 days. Omega-3 EPA 2g/day anti-cachexia."},"anemia_megaloblastica":{"nome":"Megaloblastic Anemia (B12/folate deficiency)","desc":"Anemia from vitamin B12 and/or folate deficiency. Megalocytosis, neutrophil hypersegmentation, pancytopenia in severe cases.","note":"BSH/WHO 2014. B12 <200 pg/ml: start supplementation. Folate <4 µg/L: folic acid. In pernicious anemia: IM B12. Caution: folate alone can mask B12 deficiency (irreversible neurological damage)."},"morbo_crohn":{"nome":"Crohn's Disease","desc":"Chronic transmural inflammatory bowel disease that can involve any part of the GI tract (from mouth to anus). Typically ileocolic. Complications: strictures, fistulas, abscesses.","note":"ECCO 2023. In active phase: exclusive enteral nutrition (efficacy equal to corticosteroids in pediatrics). CDED (Crohn's disease exclusion diet) in remission. Eliminate insoluble fiber if strictures present. Monitor Fe, B12, folate, vitamin D, zinc."},"colite_ulcerosa":{"nome":"Ulcerative Colitis","desc":"Chronic inflammatory bowel disease limited to the colonic mucosa, with continuous extension from the rectum. Characterized by flares and remissions.","note":"ECCO 2023. In remission: Mediterranean diet, soluble fiber (probiotics). In flare: low fiber, low residue. Supplement Fe (anemia from blood loss), folic acid (sulfasalazine therapy). Omega-3 as anti-inflammatory adjuvant."},"ipotiroidismo":{"nome":"Hypothyroidism","desc":"Reduced thyroid hormone production (T3/T4). Primary hypothyroidism (thyroid damage), secondary (pituitary), tertiary (hypothalamus). Symptoms: asthenia, bradycardia, weight gain, constipation.","note":"ETA/ATA 2021. Take levothyroxine on an empty stomach, 30-60 min before breakfast. Soy, calcium, iron, fiber: separate by at least 2-4 hours (reduce absorption). Seaweed and iodine: caution — may alter function. Adequate selenium (200µg/day) for T4→T3 conversion."},"feocromocitoma":{"nome":"Pheochromocytoma (post-surgery)","desc":"Neuroendocrine tumor of the adrenal medulla with catecholamine hypersecretion. Post-adrenalectomy: management of reactive hypoglycemia, BP monitoring, nutritional recovery.","note":"ENSAT 2023. Pre-surgical: low-sodium diet, abundant hydration. Post-surgical: reactive hypoglycemia risk (monitor glucose). Avoid tyramine (fermented foods, alcohol, dark chocolate) if residual tumor. Calcium and Mg if post-op hypoaldosteronism."},"apnea_sonno":{"nome":"Obstructive Sleep Apnea Syndrome (OSAS)","desc":"Recurrent episodes of upper airway obstruction during sleep. Associated with obesity, metabolic syndrome, hypertension. AHI ≥5 events/hour.","note":"AASM 2023. A 10% weight loss can reduce AHI by 26%. Low-calorie diet (500 kcal/day deficit). Eliminate alcohol (worsens apneas). Light evening meals. Anti-inflammatory diet. Omega-3, vitamin D. Regular schedules."},"tumore_vescica":{"nome":"Bladder Cancer","desc":"Epithelial neoplasm of the bladder (90% urothelial carcinomas). Risk factors: smoking, chemical exposure. Nutrition supporting chemotherapy, radiotherapy, cystectomy.","note":"ESPEN 2021. After radical cystectomy: B12 deficiency risk (terminal ileum resection in urinary diversions). Lifelong B12 supplementation. During chemotherapy: early nutritional support, nausea/vomiting control. Increase fluid intake (≥2.5L/day) during chemo."},"tumore_esofago":{"nome":"Esophageal Cancer","desc":"Esophageal carcinoma (squamous or adenocarcinoma). High prevalence of malnutrition and dysphagia. Cachexia in 60-80% of patients. Surgical treatment, radio-chemotherapy.","note":"ESPEN 2021. Dysphagia almost universal: modify consistency (semi-liquid→liquid). Enteral nutrition (NJ) often necessary before and after surgery. Post-esophagectomy: dumping syndrome, reflux. Split into 6-8 small meals. Upright position after meals. Oral supplements (ONS)."},"tumore_endometrio":{"nome":"Endometrial Cancer","desc":"Neoplasm of the uterine body (endometrioid adenocarcinoma). Associated with obesity, diabetes, metabolic syndrome. Surgery ± radiotherapy ± chemotherapy.","note":"ESPEN 2021. Obesity present in 40-50%: weight loss before surgery improves outcomes. After pelvic radiotherapy: intestinal toxicity (diarrhea, proctitis). Low-fiber diet in the acute phase, then gradual reintroduction. Vitamin D and Ca for osteoporosis risk (aromatase inhibitors)."},"policitemia_vera":{"nome":"Polycythemia Vera","desc":"Myeloproliferative neoplasm with excess red blood cells (and often leukocytes and platelets) from a JAK2 mutation. Increased blood viscosity, elevated thrombotic risk.","note":"ELN 2021. Low-calorie diet if overweight (reduces erythropoiesis). Abundant hydration (≥2L/day) to reduce viscosity. Limit alcohol (increases hematocrit). Iron: do NOT supplement (fuels pathological erythropoiesis). Aspirin: compatible. Stable vitamin K if anticoagulated."},"arfid":{"nome":"ARFID (Avoidant/Restrictive Food Intake Disorder)","desc":"Eating disorder characterized by intake restriction not motivated by body image. Sensory aversion, fear of choking, lack of interest in food. Frequent in children and ASD.","note":"DSM-5 2013 / NICE 2017. Multidisciplinary approach: dietitian, psychologist, CBT. Gradual expansion of food variety (food chaining). Monitor deficiencies: vitamin D, Fe, Zn, B12 (if avoiding animal protein). Targeted supplementation. Never force — increases aversion."},"pots":{"nome":"POTS / Orthostatic Dysautonomia","desc":"Postural orthostatic tachycardia syndrome: HR increases ≥30 bpm (≥40 in <19 years) within 10 min of standing without hypotension. Frequent in young women, post-COVID.","note":"ESC 2022. Increase salt (5-10g extra NaCl/day) and fluids (2.5-3.5L/day) to expand blood volume. Small frequent meals (large meals increase splanchnic pooling). Caffeine: useful in some. Eliminate alcohol. Lower limb compression. Low-GI meals."},"neuropatia_periferica":{"nome":"Peripheral Neuropathy","desc":"Damage to peripheral nerves (sensory, motor, autonomic). Causes: diabetes (most common), B12 deficiency, alcohol, chemotherapy, hereditary (CMT). Symptoms: pain, tingling, distal weakness.","note":"EFNS 2020. In diabetic neuropathy: glycemic control (target HbA1c <7%). B12 deficiency: high-dose IM or oral supplementation. Alcohol-related: abstinence + thiamine 100mg/day + multivitamin. Omega-3 fatty acids neuroprotective. Antioxidants: vitamin E, alpha-lipoic acid."},"epatite_b_cronica":{"nome":"Chronic Hepatitis B (HBV)","desc":"Chronic HBV infection with persistent viral replication (HBsAg+ >6 months). Possible progression to cirrhosis (15-40%) and HCC. Treatment: entecavir, tenofovir.","note":"EASL 2023. Absolute abstinence from alcohol (accelerates fibrosis). Normal weight (co-existing MASLD in 30-40%: worsens prognosis). Coffee 2-3 cups/day: reduces HCC. Vitamin D and zinc often deficient. Avoid hepatotoxic herbal supplements. Cooked food if cirrhosis."},"epatite_c_cronica":{"nome":"Chronic Hepatitis C (HCV)","desc":"Chronic HCV infection. SVR (sustained virologic response) with DAA (direct-acting antivirals) >95%. Even after cure: residual fibrosis risk, HCC if cirrhosis already present.","note":"EASL 2024. DAA (glecaprevir/pibrentasvir, sofosbuvir/velpatasvir): do not require significant dietary restrictions. Alcohol abstinence during therapy. Post-SVR: monitor MASLD, glucose (HCV increases IR). Coffee: reduces fibrosis. Vitamin D often deficient."},"intolleranza_sorbitolo":{"nome":"Sorbitol and Polyol Intolerance","desc":"Intestinal malabsorption of sorbitol (E420) and other polyols (xylitol, maltitol, mannitol). Bacterial fermentation → bloating, flatulence, diarrhea. Often co-exists with fructose malabsorption.","note":"SGAMN 2018. Sorbitol-rich foods: stone fruit (plums, peaches, apricots), apples, pears. \"Sugar-free\" products with polyol sweeteners. Label reading: E420, E421, E953, E965, E966, E967. Often improves following the FODMAP protocol (sorbitol is one of the \"P\"s of FODMAP)."},"huntington":{"nome":"Huntington's Disease","desc":"High-calorie, energy-dense diet. Chorea movements increase requirement by 20-40%. Progressive dysphagia.","note":"ESPEN 2023 + EHDN 2022. Requirement 35-45 kcal/kg/day. Protein 1.5 g/kg/day. EN often necessary in the advanced phase. Monitor weight weekly. IDDSI-modified texture level 3-4 as needed."},"prolattinoma":{"nome":"Prolactinoma / Hyperprolactinemia","desc":"Weight control (obesity risk from hyperprolactinemia). Fertility support. Vitamin D and calcium if associated hypogonadism.","note":"Endocrine Society 2022. Normalize BMI. Reduce oxidative stress. Vitamin D ≥30 ng/mL. Calcium 1200 mg/day if hypogonadism. Anti-inflammatory omega-3. Limit alcohol (raises PRL). Moderate caffeine."},"piaghe_decubito":{"nome":"Pressure Injuries / Pressure Ulcers","desc":"High-calorie, high-protein diet. Essential micronutrients for wound healing: zinc, vitamin C, arginine, vitamin A.","note":"EPUAP/NPIAP 2022. Kcal 35-40/kg/day. Protein 1.5-2.0 g/kg/day. Vitamin C 500mg/day. Zinc 15-30mg/day. Arginine 4.5-9g/day if stage III-IV. Adequate hydration for skin elasticity. Arginine-enriched ONS (e.g. Cubitan) if malnourished."},"bypass_gastrico":{"nome":"Roux-en-Y Gastric Bypass (post-op)","desc":"Post-bariatric surgery: small volumes, high nutritional density, lifelong supplementation. Texture progression.","note":"ASMBS 2023 + ESPEN 2022. Phase 1 (0-2 wk): clear liquids. Phase 2 (2-4 wk): protein liquids. Phase 3 (1-3 months): pureed. Phase 4 (3+ months): soft solids. Protein 60-80g/day minimum. Supplements: bariatric multivitamin, sublingual B12, iron, calcium citrate, vitamin D3. Small meals every 2-3h."},"sleeve_gastrectomy":{"nome":"Sleeve Gastrectomy (post-op)","desc":"Stomach reduced by 75-80%: reduced volumes, high protein, texture progression, lifelong supplementation.","note":"ASMBS 2023. Similar to bypass but lower dumping risk. Protein 60-80g/day. Fluids away from meals (15-30 min). Multivitamin, vitamin D3, calcium citrate, B12. Monitor B12, Fe, D, folate deficiencies at 3-6-12 months."},"sport_squadra":{"nome":"Nutrition for Team Sports (Soccer, Basketball, Rugby)","desc":"Nutritional periodization. Adequate carbohydrates for repeated sprints. Protein for muscle recovery. Optimal hydration.","note":"IOC 2018 + ISSN 2023. Kcal 45-65 kcal/kg/day (variable by phase). CHO 5-8g/kg/day (6-8 in the 48h pre-competition). Protein 1.4-1.7g/kg/day. Pre-training breakfast 3h before: CHO+protein. Recovery within 30-60 min: CHO 1-1.2g/kg + protein 0.4g/kg. Hydration: 400-600ml in the 2h pre-competition."},"sport_peso":{"nome":"Weight-Category Sports (Judo, Wrestling, Boxing, MMA)","desc":"Periodization between mass-gain and weight-cutting phases. Never drastic cuts (<5% acutely). Rapid post-competition recovery.","note":"IOC 2018 + ISSN 2023. Off-season: CHO 5-7g/kg, protein 1.6-2.0g/kg. Pre-competition (weight cutoff): gradual reduction -0.5kg/week. Post-weigh-in rehydration: 1.5L/kg lost. Protein 2.0-2.5g/kg during the cutting phase. Avoid pharmacological diuresis. Creatine 3-5g/day in off-season."},"ansia_nutrizione":{"nome":"Anxiety Disorders and Nutrition","desc":"Anti-inflammatory diet. Omega-3 and magnesium for neuronal modulation. Reduce caffeine and simple sugars.","note":"ISSFAL 2021 + Jacka 2017. Omega-3 EPA/DHA 2g/day. Magnesium 350-400mg/day. Probiotics (gut-brain axis). Limit caffeine to 200mg/day. Reduce refined sugars. Tryptophan (serotonin precursor) from food. Vitamin D ≥40ng/mL."},"ckd_stadio1_2":{"nome":"Chronic Kidney Disease Stages 1-2 (CKD G1-G2)","desc":"Prevention of progression. DASH-like diet, sodium reduction, protein control (not severe restriction), antioxidants.","note":"KDIGO 2024. Protein 0.8g/kg/day (healthy adult). Sodium <2.3g/day. BP <130/80mmHg with diet. Phosphorus not yet limited (additives to be reduced). Potassium: monitor, do not limit if normokalemic. Normal weight. Plant-rich diet. No NSAIDs."},"burnout_nutrizionale":{"nome":"Chronic Stress, Burnout and Nutrition","desc":"Anti-inflammatory diet, dietary adaptogens, meal regularity, cortisol reduction through targeted nutrition.","note":"ISSFAL 2021. Magnesium 400mg/day (stress depletes it). Vitamin C 200-500mg. Omega-3. Adaptogens: ashwagandha, maca (non-pharmacological). Reduce caffeine after 2pm. Substantial breakfast. Sleep and nutritional circadian rhythm. Avoid aggressive caloric restriction during burnout."}};
const MEAL_SLOT_EN = {"10-12 mesi: cena":"10-12 months: dinner","6-7 mesi: primo pasto (pranzo)":"6-7 months: first meal (lunch)","7-8 mesi: pranzo completo":"7-8 months: full lunch","8-10 mesi: merenda":"8-10 months: snack","Bevanda serale":"Evening drink","Bevuta notturna":"Night drink","Break-fast (ore 12:00)":"Break-fast (12:00)","Cena":"Dinner","Cena (leggera)":"Dinner (light)","Cena (ore 19:30 — ultima finestra)":"Dinner (7:30 PM — last window)","Cena (piccola)":"Dinner (small)","Cena leggera":"Light dinner","Cena leggera (2h prima del sonno)":"Light dinner (2h before sleep)","Colazione":"Breakfast","Colazione (fase luteale)":"Breakfast (luteal phase)","Colazione (giorno di riposo)":"Breakfast (rest day)","Colazione (giorno gara)":"Breakfast (competition day)","Colazione (mantenimento)":"Breakfast (maintenance)","Colazione (piccola)":"Breakfast (small)","Colazione (post-risveglio)":"Breakfast (post-wake)","Colazione (riabilitativa)":"Breakfast (rehabilitative)","Colazione (se appetito)":"Breakfast (if appetite allows)","Durante gara (ogni 45-60 min)":"During competition (every 45-60 min)","Fase acuta (UTI, g 1-5)":"Acute phase (ICU, days 1-5)","Fase acuta (giorno 1-2)":"Acute phase (day 1-2)","Fase anabolica (dopo 1° settimana)":"Anabolic phase (after 1st week)","Fase di transizione (NE → orale)":"Transition phase (EN → oral)","Fase orale iniziale":"Initial oral phase","Fase riabilitativa (>14 gg)":"Rehabilitative phase (>14 days)","Fase sub-acuta (g 6-14)":"Sub-acute phase (days 6-14)","Fase subacuta (giorno 3+)":"Subacute phase (day 3+)","Formula PEN (≈25% kcal)":"PEN formula (≈25% kcal)","Formula PEN (≈50% kcal)":"PEN formula (≈50% kcal)","Giorno 1-3 (10 kcal/kg)":"Day 1-3 (10 kcal/kg)","Infusione continua (24h su 24h)":"Continuous infusion (24h/24h)","Infusione continua notturna (20:00-08:00)":"Continuous nighttime infusion (8:00 PM-8:00 AM)","Infusione diurna intermittente (se tollerata)":"Intermittent daytime infusion (if tolerated)","Merenda":"Snack","Merenda pomeriggio":"Afternoon snack","Nutrizione enterale (NE) continua":"Continuous enteral nutrition (EN)","Nutrizione enterale precoce (entro 6-12h)":"Early enteral nutrition (within 6-12h)","Pasto principale":"Main meal","Post-allenamento (entro 30 min)":"Post-workout (within 30 min)","Post-allenamento (entro 30-60 min)":"Post-workout (within 30-60 min)","Pranzo":"Lunch","Pranzo (leggero)":"Lunch (light)","Pranzo (piccolo pasto)":"Lunch (small meal)","Pre-allenamento (1-2h prima)":"Pre-workout (1-2h before)","Pre-allenamento (30 min prima)":"Pre-workout (30 min before)","Pre-allenamento (3h prima)":"Pre-workout (3h before)","Snack notturno":"Night snack","Snack serale":"Evening snack","Snack serale CHO":"Evening CHO snack","Spuntino":"Snack","Spuntino (ore 14:30)":"Snack (2:30 PM)","Spuntino (piccole quantità)":"Snack (small amounts)","Spuntino 1":"Snack 1","Spuntino 2":"Snack 2","Spuntino mattina":"Morning snack","Spuntino mattino":"Morning snack","Spuntino pomeriggio":"Afternoon snack","Spuntino pre-serale":"Pre-evening snack","Spuntino serale":"Evening snack","Spuntino serale (CHO)":"Evening snack (CHO)"};
function patNomeEN(p) {
  try {
    const l = (typeof getLang === 'function') ? getLang() : (localStorage.getItem('nlang') || 'it');
    if (l !== 'en') return p.nome;
    const t = PATOLOGIE_EN[p.id];
    return (t && t.nome) || p.nome;
  } catch (e) { return p.nome; }
}
function patDescEN(p) {
  try {
    const l = (typeof getLang === 'function') ? getLang() : (localStorage.getItem('nlang') || 'it');
    if (l !== 'en') return p.desc;
    const t = PATOLOGIE_EN[p.id];
    return (t && t.desc) || p.desc;
  } catch (e) { return p.desc; }
}
function patNoteEN(p) {
  try {
    const l = (typeof getLang === 'function') ? getLang() : (localStorage.getItem('nlang') || 'it');
    if (l !== 'en') return p.note;
    const t = PATOLOGIE_EN[p.id];
    return (t && t.note) || p.note;
  } catch (e) { return p.note; }
}
function mealSlotEN(n) {
  try {
    const l = (typeof getLang === 'function') ? getLang() : (localStorage.getItem('nlang') || 'it');
    return l === 'en' ? (MEAL_SLOT_EN[n] || n) : n;
  } catch (e) { return n; }
}


const FABBISOGNO_PATOLOGIE={
  diabete:{kcal:'25-35 kcal/kg/die (peso ideale)',prot:'1.0-1.2 g/kg/die',note:'ESPEN 2023. Preferire peso ideale o aggiustato se sovrappeso. CHO 45-60% (basso IG). Fibre ≥25g/die. Grassi saturi <10%.'},
  irc:{kcal:'30-35 kcal/kg/die',prot:'0.6-0.8 g/kg/die (pre-dialisi stadio 3-4)',note:'ESPEN 2021. Fosforo <800mg/die. Potassio <2000mg/die. Sodio <2g/die. Se GFR<25: supplementazione di keto-analoghi.'},
  dialisi:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.4 g/kg/die (emodialisi), 1.2-1.5 (peritoneale)',note:'ESPEN 2021. Le perdite proteiche dialitiche richiedono apporto aumentato. Fosforo <800mg, K <2g, Na <2g/die. Liquidi 500ml + diuresi residua.'},
  obesita:{kcal:'Deficit 500-750 kcal/die sul TDEE (min 1200F/1500M)',prot:'1.2-1.5 g/kg peso ideale/die',note:'ESPEN 2022. Usare peso ideale per calcolo proteico. Fibre ≥30g/die. Limitare zuccheri semplici. Obiettivo -0.5/1kg/settimana.'},
  dislipidemia:{kcal:'Normocalorica o ipocalorica se sovrappeso',prot:'1.0-1.2 g/kg/die',note:'ESC/EAS 2019. Grassi saturi <7% tot. Colesterolo <200mg/die. Omega-3 ≥2g/die. Fibre solubili ≥10g. Fitosteroli 2g/die.'},
  ipertensione:{kcal:'Normocalorica o deficit se sovrappeso',prot:'1.0-1.2 g/kg/die',note:'ESH 2023. Sodio <2g/die (ideale <1.5g). Potassio ≥3.5g/die. DASH diet. Alcol <14 unità/settimana uomini, <7 donne.'},
  celiachia:{kcal:'Normocalorica (adattata al peso)',prot:'1.0-1.2 g/kg/die',note:'AIC/ESPEN. Dieta rigorosamente gluten-free. Monitorare Fe, Ca, folati, B12, vitamina D, zinco. Evitare cross-contaminazione.'},
  ibd:{kcal:'25-30 kcal/kg/die (remissione), 30-35 (riacutizzazione)',prot:'1.2-1.5 g/kg/die',note:'ECCO-ESPEN 2023. In riacutizzazione grave: nutrizione enterale esclusiva. Omega-3 anti-infiammatori. Monitorare Fe, B12, vitamina D, zinco.'},
  sarcopenia:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die (fino a 2.0 se molto sedentario/malnutrito)',note:'ESPEN 2018. Leucina ≥3g/pasto (stimola sintesi proteica). Vitamina D 800-1000 UI/die. Omega-3. Attività fisica di resistenza fondamentale.'},
  steatosi:{kcal:'Deficit 500-750 kcal se BMI>25 (obiettivo -7-10% peso)',prot:'1.2-1.5 g/kg/die',note:'EASL 2024. Eliminare alcol e fruttosio aggiunto. Dieta mediterranea. Omega-3 EPA/DHA 2-4g/die. Vitamina E 800 UI/die (NASH selezionata). Caffeina permessa.'},
  cirrosi:{kcal:'35-40 kcal/kg/die (peso secco)',prot:'1.2-1.5 g/kg/die (non ridurre!)',note:'EASL/ESPEN 2019. Non limitare proteine (aumenta mortalità). 4-6 pasti/die. Snack serale CHO (50g). Sodio <2g se ascite. BCAA se encefalopatia.'},
  bpco:{kcal:'30-40 kcal/kg/die (aumentato per lavoro respiratorio)',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. CHO non >50% (aumenta produzione CO2). Grassi 35-45% energia. Pasti piccoli e frequenti. Vitamina D, calcio. Evitare sovrappeso.'},
  calcolosi:{kcal:'Normocalorica',prot:'0.8-1.0 g/kg/die (limitare animali)',note:'EAU 2022. Liquidi ≥2.5L/die. Calcio 1000-1200mg/die (NON ridurre). Sodio <5g NaCl. Ossalati limitati. Vitamina C <1000mg. Purine ridotte.'},
  gotta:{kcal:'Ipocalorica se sovrappeso',prot:'1.0 g/kg/die (limitare animali)',note:'ACR/EULAR 2020. Alcol zero (soprattutto birra). Evitare frattaglie, carni rosse, pesce grasso. Fruttosio limitato. Latticini scremati protettivi. Idratazione ≥2L/die.'},
  anemia:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'WHO/LARN 2022. Ferro eme (carne) + non-eme (legumi, verdure a foglia). Vitamina C ai pasti principali. Evitare tè, caffè, calcio ai pasti (inibiscono assorbimento Fe). Folati e B12 adeguati.'},
  oncologia:{kcal:'25-30 kcal/kg/die (cachessia: 30-35)',prot:'1.2-2.0 g/kg/die',note:'ESPEN 2021. Supporto nutrizionale precoce. Omega-3 EPA 2g/die (anti-cachessia). ONS se intake <60% per >7 giorni. Nutrizione enterale se tratto GI funzionante.'},
  osteoporosi:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'IOF 2021. Calcio 1000-1200mg/die. Vitamina D 800-2000 UI/die. Vitamina K2 90-120µg/die. Limitare alcol e sodio. Attività fisica con carico. Evitare diete molto ipocaloriche.'},
  scompenso:{kcal:'25-30 kcal/kg/die',prot:'1.0-1.2 g/kg/die',note:'ESC 2021. Sodio <2g/die. Liquidi 1.5-2L/die se edemi. Monitorare potassio (diuretici). Peso quotidiano. Alcol limitato o assente. Piccoli pasti frequenti.'},
  pancreatite:{kcal:'25-35 kcal/kg/die',prot:'1.0-1.5 g/kg/die',note:'AGA/ESPEN 2020. Alcol zero. Grassi <40g/die se steatorrea (poi liberalizzare). 5-6 pasti piccoli. Enzimi pancreatici se insufficienza esocrina. Vitamina D, B12, zinco.'},
  gravidanza:{kcal:'+350 kcal/die (II trim), +460 kcal/die (III trim)',prot:'+25g/die rispetto al fabbisogno base',note:'LARN 2023. Folati 600µg/die. Ferro 27mg/die. Calcio 1000mg/die. DHA 200mg/die extra. Iodio 220µg/die. Evitare: alcol, crudi animali, pesce ad alto Hg, fegato eccessivo.'},
  allattamento:{kcal:'+500 kcal/die',prot:'+28g/die rispetto al fabbisogno base',note:'LARN 2023. DHA 200mg/die extra. Calcio 1000mg/die. Vitamina D 1500 UI/die. Iodio 290µg/die. Liquidi ≥2L/die. Caffeina <200mg/die.'},
  fenilchetonuria:{kcal:'Normocalorica per età',prot:'Phe <300mg/die da alimenti naturali',note:'ACMG 2014. Fenilalanina monitorata e limitata. Integratori di aminoacidi senza Phe obbligatori. Tirosina supplementata. Vitamina B12, D, selenio, zinco da monitorare.'},
  hiv:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'WHO/ESPEN. Prevenire la malnutrizione. Micronutrienti: zinco, selenio, vitamina D, B12. Attenzione a interazioni farmaci-nutrienti (antiretrovirali). Lipodistrofia: limitare grassi saturi.'}
,
  gastrectomia:{kcal:'25-30 kcal/kg/die (inizialmente) → 30-35',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Pasti piccoli e frequenti (6-8/die). Evitare liquidi ai pasti. Rischio: Dumping syndrome (evitare zuccheri semplici ai pasti). Supplementare: B12, Fe, Ca, vitamina D, folati. Rischio carenza vitamina B12 permanente (supplementazione parenterale).'},
  stomia:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Ileostomia: restrizione liquidi freddi, ossalati, cibi ad alto residuo. Colostomia: dieta normale con adattamenti individuali. Attenzione a disidratazione. Monitorare sodio e potassio.'},
  tumore_seno:{kcal:'25-30 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021 Oncologia. Dieta anti-infiammatoria. Fitoestrogeni (soia): moderati, non controindicati. Peso corporeo ottimale riduce rischio recidiva. Alcol: fattore di rischio indipendente.'},
  tumore_pancreas:{kcal:'30-35 kcal/kg/die',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2021. Alta incidenza di cachessia. Enzimi pancreatici se insufficienza esocrina. Diabete secondario frequente. Omega-3 EPA 2g/die. ONS precoci se intake inadeguato.'},
  tumore_colon:{kcal:'25-30 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Pre-chirurgia: immunonutrizione (arginina, omega-3). Post-chirurgia: ripresa alimentazione precoce. Fibre post-operatorie da introdurre gradualmente.'},
  diverticolite:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ACG 2015. In fase acuta: dieta liquida o a basso residuo. In remissione: dieta ricca di fibre (25-35g/die) per prevenire recidive. Nuts e semi non sono controindicati (sfatato mito). Idratazione abbondante.'},
  diverticolosi:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'ACG 2015. Fibre ≥25-35g/die per prevenire complicanze. Idratazione ≥1.5-2L/die. Attività fisica. Probiotici: possibile beneficio.'},
  allergia_latte:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2019. Eliminazione totale di latte vaccino e derivati. Attenzione a etichette (caseina, siero di latte, lattosio). Supplementare calcio e vitamina D. Alternative: latte di soia, riso, avena, mandorla (arricchiti).'},
  allergia_pesce:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2019. Eliminazione di tutti i pesci (cross-reattività). Attenzione a prodotti derivati (olio di pesce, gelatina). Supplementare omega-3 da fonti vegetali (alghe, semi di lino, noci).'},
  allergia_molluschi:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EAACI 2019. Eliminazione di crostacei e molluschi. Attenzione a contaminazione crociata nei ristoranti di pesce. Il glucosamina può dare cross-reattività.'},
  allergia_frutta_secca:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2019. Eliminazione della frutta secca specifica (o tutta in caso di allergia multipla). Attenzione a tracce in prodotti da forno, cioccolato, pesto. Portare sempre adrenalina auto-iniettabile.'},
  intolleranza_lattosio:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'WGO 2013. La soglia individuale varia (molti tollerano 12g/pasto = 1 bicchiere latte). Formaggi stagionati e yogurt sono meglio tollerati. Lattasi enzimatica disponibile. Calcio da fonti alternative o supplementi.'},
  gerd:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ACG 2022. Evitare cioccolato, menta, alcol, caffè, cibi grassi, agrumi, pomodoro, cibi piccanti. Pasti piccoli e frequenti (4-5/die). Cena 3h prima di coricarsi.'},
  gastrite:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'WCOG 2020. Evitare FANS, alcol, fumo, cibi piccanti e acidi. Pasti regolari. Cottura: vapore, bollitura (no frittura). Probiotici se H. pylori.'},
  stipsi:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'ACG 2021. Fibre ≥25-35g/die. Acqua ≥1.5-2L/die. Probiotici: evidenza moderata. Attività fisica quotidiana.'},
  artrite_reumatoide:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'EULAR 2022. Omega-3 2-3g/die. Vitamina D target >40 ng/mL. Dieta mediterranea riduce DAS28. Folati se MTX.'},
  fibromialgia:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EULAR 2023. Dieta antiinfiammatoria. Vitamina D target >40 ng/mL. Magnesio 300-400mg/die. Trial gluten-free 3 mesi se sospetta sensibilità.'},
  parkinson:{kcal:'25-30 kcal/kg/die',prot:'1.0-1.2 g/kg/die',note:'ESPEN 2021. Levodopa: proteine ridotte a colazione e pranzo. Fibre ≥30g/die per stipsi. Vitamina D e B12. Texture modificata se disfagia.'},
  sclerosi_multipla:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ECTRIMS 2023. Vitamina D 40-60 ng/mL. Omega-3 2g/die. Dieta a basso contenuto di grassi saturi. Probiotici per disbiosi.'},
  ipertiroidismo:{kcal:'+20-30% del fabbisogno basale',prot:'1.2-1.5 g/kg/die',note:'ETA 2023. Calcio 1000-1200mg/die. Vitamina D ≥1000 UI/die. Selenio 200µg/die (Graves). Moderare iodio. Limitare caffeina.'},
  anoressia:{kcal:'Iniziare 5-10 kcal/kg, incrementare a 30-40 kcal/kg',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2022. Rischio refeeding syndrome: monitorare fosforo, potassio, magnesio. Tiamina prima di renutrire. Team multidisciplinare obbligatorio.'},
  bulimia:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ESPEN 2022. Pasti regolari (no diete restrittive). Reintegrare potassio e magnesio se vomito. Alimentazione intuitiva supportata. CBT essenziale.'},
  bed:{kcal:'Normocalorica o moderato deficit se sovrappeso',prot:'1.0-1.2 g/kg/die',note:'DSM-5/ESPEN 2022. Pasti regolari strutturati. Evitare diete restrittive. Mindful eating. CBT elemento cardine.'},
  post_covid:{kcal:'25-35 kcal/kg/die (aumentato se cachessia)',prot:'1.2-1.5 g/kg/die',note:'OMS 2023. Vitamina D target >40 ng/mL. Zinco 10-15mg/die. Omega-3 2g/die. Vitamina B12 se carente. Probiotici per disbiosi.'},
  emocromatosi:{kcal:'Normocalorica',prot:'1.0 g/kg/die (limitare carni rosse)',note:'EASL 2022. Evitare supplementi di ferro e vitamina C. Alcol zero. Calcio e tè/caffè ai pasti riducono assorbimento ferro.'},
  vegetariana:{kcal:'Normocalorica (25-35 kcal/kg/die)',prot:'1.0-1.2 g/kg/die (completezza aminoacidica con abbinamento cereali+legumi)',note:'SINU 2022 · EFSA 2022. Fe non-eme: abbinare vitamina C ai pasti; evitare tè/caffè. B12: monitorare. Omega-3: semi di lino/chia/noci; considerare EPA/DHA da alghe. Zinco: semi, legumi, integrali. Calcio: latticini, tofu.'},
  vegana:{kcal:'Normocalorica (25-35 kcal/kg/die)',prot:'1.0-1.2 g/kg/die (privilegiare legumi, soia, tofu, tempeh)',note:'SINU 2022 · AND 2016. B12: supplemento OBBLIGATORIO 250 µg/die. Vitamina D: supplemento 800-2000 UI/die. Calcio: bevande vegetali arricchite, tofu, crucifere. Fe+vitamina C ai pasti. Iodio: sale iodato o supplemento. Omega-3 EPA/DHA: supplemento da alghe.'},
  latto_vegetariana:{kcal:'Normocalorica (25-35 kcal/kg/die)',prot:'1.0-1.2 g/kg/die (latticini + legumi + cereali integrali)',note:'SINU 2022. B12: monitorare (presente nei latticini). Fe non-eme: legumi + vitamina C ai pasti. Omega-3: semi di lino/chia/noci; valutare supplemento EPA/DHA da alghe. Calcio: latticini, tofu, broccoli.'},
  ovo_vegetariana:{kcal:'Normocalorica (25-35 kcal/kg/die)',prot:'1.0-1.2 g/kg/die (uova + legumi + cereali)',note:'SINU 2022. Calcio: bevande vegetali arricchite, tofu, crucifere, mandorle. B12: monitorare (uova, variabile). Vitamina D: supplemento se esposizione solare ridotta. Omega-3: semi di lino/chia/noci; valutare supplemento EPA/DHA da alghe.'},
  lupus:{kcal:'Normocalorica (monitorare con cortisonici)',prot:'1.0-1.2 g/kg/die',note:'EULAR 2023. Vitamina D spesso carente. Omega-3 2-3g/die. Calcio per osteoporosi corticosteroidea. Restrizione sodio se nefrite.'},
  allergia_uova:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2019. Eliminazione completa di uova e derivati. Leggere etichette (ovoalbumina, lisozima). Vitamina D e B12 se dieta restrittiva.'},
  hashimoto:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ETA 2022. Selenio 55-200 µg/die (selenometionina). Vitamina D target >40 ng/mL. Iodio: adeguato, non eccessivo. Levotiroxina a stomaco vuoto 30-60 min prima della colazione. Screening celiachia obbligatorio.'},
  ibs:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'ACG 2021. Dieta Low-FODMAP: fase eliminazione 4-6 settimane poi reintroduzione sistematica. Psyllium utile in IBS-C. Evitare salti pasto. Probiotici (LGG, S. boulardii). Gestione dello stress.'},
  pcos:{kcal:'Deficit moderato se sovrappeso (obiettivo -5-10% del peso)',prot:'1.0-1.2 g/kg/die',note:'ESHRE 2023. Dieta a basso indice glicemico. Mio-inositolo 2g + D-chiro-inositolo 200mg. Omega-3. Attività fisica 150-300 min/settimana. Vitamina D target >30 ng/mL.'},
  ictus:{kcal:'25-30 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Valutare deglutizione prima di alimentare oralmente. Texture IDDSI appropriata se disfagia. Omega-3 EPA+DHA 1-2g/die. Dieta DASH/Mediterranea per prevenzione recidive. Sodio <2g/die.'},
  chirurgia_bariatrica:{kcal:'800-1200 kcal/die (fase post-operatoria precoce)',prot:'≥60-80 g/die (1.0-1.5 g/kg peso ideale)',note:'ASMBS 2021. Progressione dieta: liquidi → morbidi → solidi (settimane). Integratori obbligatori: multivitaminico, B12, ferro, calcio citrato, vitamina D. Pasti piccoli e frequenti (5-6/die). Masticare bene. No bevande durante i pasti.'},
  disfagia:{kcal:'25-30 kcal/kg/die',prot:'1.0-1.2 g/kg/die',note:'ESPEN 2021 · IDDSI 2019. Classificazione IDDSI livelli 0-7. Liquidi addensati se necessario. Alimenti omogenei e compatti. Evitare alimenti a doppia consistenza. Idratazione adeguata (rischio disidratazione). Valutazione logopedica obbligatoria.'},
  ipe:{kcal:'25-35 kcal/kg/die',prot:'1.0-1.5 g/kg/die',note:'UEG 2022. PERT obbligatoria ad ogni pasto: 40.000-80.000 UI lipasi per pasto principale. Grassi <40g/die se PERT non adeguata. Vitamine liposolubili A,D,E,K. No alcol assoluto. Pasti piccoli e frequenti (5-6/die).'},
  malnutrizione:{kcal:'25-35 kcal/kg/die (fino a 35-40 kcal/kg se deplezione severa)',prot:'1.2-2.0 g/kg/die',note:'ESPEN 2018. Attenzione alla refeeding syndrome (monitorare P, K, Mg, tiamina). Renutrizione graduale. Supporto nutrizionale multidisciplinare. Identificare e trattare la causa. ONS o NE se intake orale insufficiente.'},
  neoplasia:{kcal:'25-30 kcal/kg/die (cachessia: 30-35 kcal/kg)',prot:'1.2-2.0 g/kg/die',note:'ESPEN 2021. Supporto nutrizionale precoce se rischio malnutrizione. Omega-3 EPA 2g/die anti-cachessia. ONS se intake <60% per >7 gg. Nutrizione enterale se tratto GI funzionante. Controllo sintomi (nausea, mucosite, disgeusia).'},
  sindrome_metabolica:{kcal:'Deficit 500 kcal/die sul TDEE (obiettivo -0.5-1 kg/settimana)',prot:'1.0-1.2 g/kg/die',note:'IDF/AHA 2009. Perdita del 5-10% del peso migliora tutti i parametri. Dieta mediterranea (PREDIMED). Fibre ≥30g/die. Limitare zuccheri semplici e grassi saturi. Attività fisica 150 min/settimana. Monitorare glicemia, lipidi, PA.'},
  fibrosi_cistica:{kcal:'110-200% del fabbisogno basale (30-50 kcal/kg/die)',prot:'1.5-2.0 g/kg/die',note:'ECFS 2016. Energia molto aumentata per malassorbimento e lavoro respiratorio aumentato. PERT ad ogni pasto e spuntino. Vitamine liposolubili A,D,E,K supplementate. Sodio extra in estate. Monitorare glicemia (CFRD). Supplementi calorici se necessario.'},
  epilessia:{kcal:'Normocalorica (adattata all\'età e all\'attività)',prot:'1.0-1.2 g/kg/die (non eccessiva: riduce chetosi)',note:'ILAE 2008 · ESPEN 2021. Dieta chetogenica classica ratio 3:1-4:1. CHO <20g/die. Grassi 65-75% energia. Monitorare lipidi, crescita, densità ossea. Supplementare vitamine e minerali. Modified Atkins Diet come alternativa meno restrittiva.'},
  alzheimer:{kcal:'25-30 kcal/kg/die (aumentare se malnutrizione)',prot:'1.0-1.2 g/kg/die',note:'ESPEN 2023. Dieta MIND (Mediterranea + DASH). Vitamina B12, folati, vitamina D, omega-3 DHA. Pasti piccoli, frequenti e appetibili. Texture adattata IDDSI se disfagia. ONS se intake <75% per >1 settimana. Team multidisciplinare (nutrizionista, logopedista).'},
  gastroparesi:{kcal:'Normocalorica (liquidi calorici se solidi non tollerati)',prot:'1.0 g/kg/die',note:'ADA/ACG 2022. Grassi <40g/die. Fibra <10g/die. 6-8 pasti piccoli e frequenti. Consistenza liquida/morbida. Non coricarsi entro 2h dal pasto. Controllo glicemico se diabete associato. Masticare bene. Liquidi calorici se solidi non tollerati.'},
  sla:{kcal:'30-40 kcal/kg/die',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2023. Ipermetabolismo frequente. Valutare disfagia con logopedista (IDDSI). PEG precoce quando FVC >50% e calo ponderale progressivo. Omega-3 2g/die. Vitamina D. Monitorare peso ogni 2-4 settimane. Supporto nutrizionale specializzato obbligatorio.'},
  '6fed':{kcal:'Normocalorica (30-35 kcal/kg/die)',prot:'1.0-1.2 g/kg/die',note:'ACG/AGA 2020. Eliminare completamente: latte/latticini, frumento/glutine, uova, soia, frutta secca/arachidi, pesce/frutti di mare. Supplementare obbligatoriamente: calcio 1000-1200mg/die, vitamina D 800-1000 UI/die, omega-3 da alghe, B12 se deficit. Reintroduzione un alimento alla volta ogni 6-8 settimane con controllo endoscopico (EGDS).'},
  '4fed':{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ACG/AGA 2020. Eliminare: latte/latticini, frumento/glutine, uova, soia. Calcio: supplementare 1000-1200mg/die (latticini esclusi). Vitamina D adeguata. Pesce e frutta secca consentiti. Reintroduzione sequenziale con EGDS di controllo ogni 6-8 settimane.'},
  cded_fase1:{kcal:'25-35 kcal/kg/die (50% da PEN)',prot:'1.0-1.2 g/kg/die',note:'Levine 2019 · ECCO 2022. Fase 1 (sett. 1-6): 50% del fabbisogno calorico da formula enterale polimerica (Modulen IBD o equivalente). Dieta solida ristretta: pollo, pesce fresco, uova, patata, carota, zucchina, frutta fresca semplice, riso, olio EVO. Monitorare PCR, calprotectina fecale, ferritina, vitamina D, zinco.'},
  cded_fase2:{kcal:'25-35 kcal/kg/die (25% da PEN)',prot:'1.0-1.2 g/kg/die',note:'Levine 2019 · ECCO 2022. Fase 2 (sett. 7-12): 25% kcal da PEN + dieta espansa. Aggiungere progressivamente: legumi, frutta secca, yogurt naturale senza additivi, maggiore varietà di pesce. Continuare ad escludere: glutine, carni rosse/processate, oli di semi, UPF. Monitorare PCR, calprotectina.'},
  cded_mant:{kcal:'25-35 kcal/kg/die',prot:'1.0-1.2 g/kg/die',note:'Levine 2019 · ECCO 2022. Mantenimento: dieta CDED completa senza PEN. Escludere permanentemente: carni rosse/processate, glutine industriale, oli di semi, emulsionanti, UPF. Monitorare ogni 3-6 mesi: PCR, calprotectina, ferritina, vitamina D, B12, zinco.'},
  scd:{kcal:'Normocalorica (adeguata ad età e attività)',prot:'1.0-1.5 g/kg/die',note:'CCF 2021 · ECCO 2022. Eliminare tutti i disaccaridi e polisaccaridi (zucchero, lattosio, amido). Consentire solo monosaccaridi e alimenti non processati. Yogurt fermentato artigianale 24h (privo di lattosio residuo). Richiede supervisione nutrizionale specializzata. Monitorare: calcio, vitamina D, B12, adeguatezza calorica.'},
  larn_popolazione_sana:{kcal:'EAR ~1700 kcal/die (F) – ~2100 kcal/die (M) adulto tipo',prot:'0.9 g/kg/die (adulto)',note:'LARN 2014 (V Revisione) — SINU. CHO 45-60% kcal (preferire basso IG). Grassi 20-35% kcal (saturi <10%). Fibra 25-30 g/die. Sale <5 g/die. Folati 400 µg/die. Calcio 1000 mg/die adulto. Vitamina D 15 µg/die. Acqua ≥2L/die. Alcol: max 1 U/die F, 2 U/die M.'},
  diabete_gestazionale:{kcal:'Normocalorica adattata al BMI pre-gravidico (non ipocalorica <1600 kcal)',prot:'1.1-1.3 g/kg/die',note:'ADA 2023 · ACOG 2023. CHO 40-50% kcal, basso IG. No zuccheri liberi. 3 pasti + 3 spuntini. Glicemia target: digiuno <95 mg/dL, 1h postprandiale <140 mg/dL, 2h <120 mg/dL. Attività fisica moderata raccomandata. Folati, ferro, DHA, iodio come in gravidanza fisiologica. Auto-monitoraggio glicemico.'},
  diabete_t1:{kcal:'Normocalorica per peso e attività (TDEE individuale)',prot:'1.0-1.2 g/kg/die',note:'ISPAD 2022 · ADA 2022. Conteggio CHO preciso: ratio insulina/CHO personalizzato. Fibra ≥25 g/die (rallenta assorbimento). Correzione ipoglicemia: 15g CHO rapidi (regola del 15). Monitoraggio glicemico continuo (CGM) raccomandato. Alcol: rischio ipoglicemia ritardata.'},
  menopausa:{kcal:'Normocalorica (ridurre se aumento ponderale)',prot:'1.0-1.2 g/kg/die',note:'IMS 2022. Calcio 1200 mg/die. Vitamina D 1500-2000 UI/die. Fitoestrogeni (isoflavoni soia, lignani lino) utili per vampate. Proteine adeguate per massa muscolare. Fibre ≥25 g/die. Limitare alcol, caffeina, sodio. Omega-3 2g/die. Attività fisica con carico.'},
  sibo:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'ACG 2020 · WGO 2021. Dieta Low-FODMAP nella fase acuta (4-6 settimane). Poi reintroduzione graduale. Evitare eccessi di fibre fermentabili. Pasti piccoli e frequenti. Antibiotico-terapia ciclica (rifaximina). Probiotici: evidenza limitata. Trattare la causa di base. Monitorare: B12, ferro, vitamina D, zinco.'},
  allergia_arachidi:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2021. Eliminazione totale di arachidi e prodotti derivati. Leggere SEMPRE le etichette (allergene obbligatorio EU). Cross-contaminazione frequente: evitare oleifici/pasticcerie/pizzerie senza certificazione. Portare sempre adrenalina auto-iniettabile. Omega-3 da fonti alternative (pesce, alghe, semi di lino).'},
  allergia_grano:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2021. Distinguere da celiachia (autoimmune) e NCWS. Orzo e segale spesso tollerati (allergia specifica alle proteine del grano). Eliminare frumento e prodotti derivati. Cereali alternativi: riso, mais, grano saraceno, quinoa, amaranto. Supplementare ferro, fibre, vitamine del gruppo B se dieta restrittiva.'},
  allergia_sesamo:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EAACI 2023 · Reg. UE 2023 (15° allergene obbligatorio). Eliminare sesamo e tutti i derivati: tahini, hummus, olio di sesamo, halva. Attenzione a pane da hamburger, cracker orientali, pangrattato etnico. Adrenalina auto-iniettabile sempre disponibile.'},
  intolleranza_istamina:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EAACI 2020. Carenza/riduzione diaminossidasi (DAO). Dieta a basso contenuto di istamina (4-8 settimane di esclusione). Evitare: vino rosso, formaggi stagionati, pesce in scatola/affumicato, salumi, cibi fermentati, spinaci, pomodori, cioccolato. Poi reintroduzione graduale. Vitamina B6, vitamina C, rame cofactori DAO.'},
  intolleranza_nichel:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'SNAS · EAACI 2022. Dieta di esclusione 4-6 settimane poi reintroduzione graduale. Alimenti ad alto nichel da limitare: cioccolato, noci, legumi, cereali integrali, pomodori, spinaci, asparagi. Vitamina C ai pasti riduce assorbimento nichel. Evitare cottura in pentole di acciaio inossidabile.'},
  sindrome_nefrosica:{kcal:'30-35 kcal/kg/die',prot:'0.8-1.0 g/kg/die + compensazione perdite urinarie',note:'KDIGO 2021. Proteine non eccessive (peggiorano proteinuria). Sodio <1.5 g/die per edemi. Grassi saturi <7% per ipercolesterolemia nefrosica. Omega-3 benefici. Monitorare: proteinemia, lipidi, vitamina D (perdita proteina legante), zinco, rame. Liquidi adattati a edemi.'},
  pancreatite_acuta:{kcal:'25-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'IAP/APA 2020 · ESPEN 2020. Forme lievi: dieta solida morbida a basso residuo precoce (entro 24-48h). Forme gravi: NE per SNG precoce se via orale non tollerata. NP solo se NE non fattibile. No digiuno prolungato. Grassi bassi inizialmente (<30 g/die). Alcol zero. Piccoli pasti frequenti.'},
  trapianto:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die (fase precoce), 1.0-1.2 (mantenimento)',note:'ESPEN 2019. Sicurezza alimentare rigorosa: no crudi, no formaggi molli non pastorizzati, no frutti di mare crudi, no pompelmo (interazione immunosoppressori). Glucocorticoidi: limitare zuccheri e sodio. Calcio + vitamina D per osteoporosi da cortisonici. Monitorare peso, lipidi, glicemia (NODAT).'},
  colite_microscopica:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EMCG 2020 · ACG 2020. Eliminare fattori scatenanti: FANS, PPI (se possibile), sertralina. Dieta senza glutine utile nel 40-50% dei casi. Latticini: limitare se lattosio scatenante. Ridurre fibre insolubili in fase acuta. Idratazione abbondante. Budesonide prima linea farmacologica.'},
  endometriosi:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ASRM 2022 · ESHRE 2022. Dieta mediterranea riduce rischio e sintomi. Omega-3 EPA/DHA 2-3 g/die (anti-prostaglandinico, riduce dismenorrea). Carni rosse ≤2 porzioni/settimana. Limitare alcol. Vitamina D target >40 ng/mL. Fibre ≥25 g/die (metabolismo estrogenico). Curcuma 1 g/die: possibile beneficio antinfiammatorio.'},
  prediabete:{kcal:'Deficit 500 kcal/die se sovrappeso (obiettivo -5-10% peso)',prot:'1.0-1.2 g/kg/die',note:'ADA 2024 · IDF 2022. IFG: glicemia digiuno 100-125 mg/dL; IGT: 2h OGTT 140-199 mg/dL. Riduzione peso 5-10% riduce rischio T2DM del 58% (DPP). CHO basso IG. Fibre ≥30 g/die. Attività fisica 150 min/settimana. Limitare zuccheri semplici e grassi saturi. Metformina se dieta insufficiente.'},
  ipercolesterolemia_familiare:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'EAS 2023. Dieta da sola riduce LDL max 15-25% (terapia farmacologica quasi sempre necessaria). Grassi saturi <5-7% kcal totali. Colesterolo alimentare <200 mg/die. Fibre solubili ≥10 g/die (beta-glucani, pectina). Fitosteroli 2 g/die (-8-10% LDL). Omega-3 per trigliceridi. Eliminare alcol, fumo.'},
  psoriasi:{kcal:'Ipocalorica se sovrappeso (obiettivo BMI <25)',prot:'1.0-1.2 g/kg/die',note:'BAD 2023 · EADV 2023. Perdita di peso migliora risposta ai biologici. Dieta mediterranea riduce PASI. Omega-3 EPA/DHA 2-3 g/die antinfiammatorio. Alcol zero (aggrava psoriasi e aumenta rischio epatico con MTX). Vitamina D target >40 ng/mL. Limitare grassi saturi e zuccheri.'},
  dermatite_atopica:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2022 · AAD 2022. Eliminazione dietetica solo se allergia IgE-mediata documentata (test allergologici prima). Omega-3 2 g/die possibile beneficio. Vitamina D target >40 ng/mL. Probiotici Lactobacillus: evidenza moderata nel bambino. Evitare diete elimazione non necessarie (rischio malnutrizione).'},
  acne:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0 g/kg/die',note:'JAAD 2022 · AAD 2022. Dieta a basso IG riduce lesioni acneiche del 25-50% (RCT). Limitare latte scremato (più insulinogeno del latte intero). Omega-3 2 g/die antinfiammatorio. Zinco 30 mg/die utile (forma lieve-moderata). Vitamina A da alimenti (non supplementi). Evitare siero di latte in polvere (whey).'},
  sjogren:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EULAR 2020. Xerostomia → difficoltà masticazione/deglutizione: alimenti morbidi, umidi, in piccoli pezzi. Idratazione frequente. Evitare cibi secchi, acidi, alcolici, caffeina (peggiorano xerostomia). Omega-3 2-3 g/die (effetto antinfiammatorio). Vitamina D, calcio per osso. Igiene orale rigorosa (rischio carie elevato).'},
  talassemia:{kcal:'Normocalorica (aumentata se anemia grave o fabbisogno energetico elevato)',prot:'1.0-1.2 g/kg/die',note:'TIF 2021. Beta-talassemia major: trasfusioni → sovraccarico ferro → evitare supplementi di ferro e vitamina C in eccesso. Folati 5 mg/die (aumentata eritropoiesi). Calcio 1000-1200 mg/die + vitamina D (osteoporosi frequente). Zinco spesso carente. Dieta sana: limitare grassi saturi e zuccheri.'},
  favismo:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'WHO 2022 · ENERCA 2022. Deficit G6PD (X-linked). Evitare ASSOLUTAMENTE: fave (Vicia faba), vicina e convicina. Evitare anche: alcuni farmaci ossidanti (aspirina ad alte dosi, primachina, nitrofurantoina). In crisi emolitica: idratazione, trasfusioni se Hb <6 g/dL. Acido folico se anemia cronica. Dieta normale per il resto.'},
  wilson:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EASL 2012 · AASLD 2022. Dieta a basso rame: <1 mg/die (apporto normale 1.5-3 mg/die). Evitare: fegato, molluschi (ostriche, vongole, capesante), noci, cioccolato, funghi secchi, acqua di pozzo (rame). Terapia chelante (penicillamina o trientina) o zinco per bloccare assorbimento intestinale. Vitamina B6 se penicillamina.'},
  lipedema:{kcal:'Normocalorica (dieta ipocalorica convenzionale non efficace sul lipedema)',prot:'1.2-1.5 g/kg/die',note:'ILA 2021. Accumulo adiposo patologico simmetrico (gambe/fianchi/braccia) non responsivo alla restrizione calorica. Dieta anti-infiammatoria: Mediterranean o RAD (Rare Adipose Disorders). Omega-3 2-3 g/die. Limitare zuccheri semplici, glutine (possibile beneficio). Linfodrenaggio manuale + compressione essenziali. Vitamina D target >40 ng/mL.'},
  iperemesi_gravidica:{kcal:'Obiettivo minimo 1500-1800 kcal/die; adattare alla tolleranza',prot:'1.0-1.2 g/kg/die',note:'RCOG 2024 · ACOG 2022. Frazionamento estremo (6-10 piccoli pasti/die). Alimenti secchi, freddi, blandi tollerati meglio. Zenzero 1 g/die (evidenza A per nausea). Vitamina B6 10-25 mg ogni 8h (prima linea farmacologica). Tiamina 100 mg/die se vomito prolungato >2-3 settimane (previene Wernicke). Idratazione EV se perdita peso >5% o chetosi. Integratori prenatali a stomaco pieno o sera.'},
  sbs:{kcal:'25-40 kcal/kg/die (aumentato per malassorbimento)',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2022 · AGA 2020. NPD se intestino residuo <100cm senza colon o <50cm con colon. Glutammina 0.5g/kg/die. GLP-2 (teduglutide) per adattamento. Vitamine B12, D, A, K; magnesio, zinco, selenio da supplementare. Monitorare ogni 3-6 mesi: micronutrienti, parametri renali, densità ossea.'},
  addison:{kcal:'Normocalorica (adeguata a peso e attività)',prot:'1.0-1.2 g/kg/die',note:'ES 2021 · ESE 2021. Aumentare sodio: 3-4g NaCl/die (estate: +1-2g; sport: +1g/ora). Pasti regolari 4-5/die per prevenire ipoglicemia. Vitamina D 1000-2000 UI/die + calcio 1000-1200mg/die. Potassio: non eccedere (rischio iperkaliemia).'},
  post_covid:{kcal:'25-35 kcal/kg/die (aumentato se cachessia)',prot:'1.2-1.5 g/kg/die',note:'OMS 2023. Vitamina D target >40 ng/mL. Zinco 10-15mg/die. Omega-3 2g/die. Vitamina B12 se carente. Probiotici per disbiosi. No restrizione calorica in fase acuta.'},
  sclerosi_multipla:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ECTRIMS 2023. Vitamina D target 40-60 ng/mL (2000-4000 UI/die). Omega-3 2g/die. Dieta a basso contenuto di grassi saturi. Probiotici per disbiosi. Alcol: evitare o ridurre.'},
  emocromatosi:{kcal:'Normocalorica',prot:'1.0 g/kg/die (limitare carni rosse)',note:'EASL 2022. Evitare supplementi di ferro e vitamina C. Alcol zero. Calcio e tè/caffè ai pasti riducono assorbimento ferro. Limitare carni rosse e frattaglie.'},
  encefalopatia_epatica:{kcal:'35-40 kcal/kg/die (peso secco)',prot:'1.2-1.5 g/kg/die (NON ridurre)',note:'EASL/ESPEN 2019. Restrizione proteica CONTROINDICATA. BCAA 0.25g/kg/die se EE persistente. Preferire proteine vegetali e latticini. 4-6 pasti/die. Snack serale con CHO. Zinco 220mg/die (solfato). Evitare digiuno >6h.'},
  tumore_testa_collo:{kcal:'30-35 kcal/kg/die',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2021. Malnutrizione nel 40-70%. PEG profilattica pre-radioterapia. ONS ipercalorici e iperproteici. Mucositi: alimenti morbidi/freddi. Xerostomia: liquidi ai pasti. Zinco e vitamina D da supplementare. Monitorare peso ogni settimana.'},
  nefropatia_diabetica:{kcal:'30-35 kcal/kg/die',prot:'0.6-0.8 g/kg/die',note:'KDIGO 2022. Proteine 0.6-0.8 g/kg/die riduce progressione renale. Controllo glicemico prioritario (HbA1c 6.5-7.5%). CHO basso IG. Fosforo <800mg/die. Potassio adattato al GFR. Sodio <2g/die.'},
  ipertrigliceridemia_severa:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'EAS 2023. TG>500: rischio pancreatite. Grassi <10-15% en. Alcol zero assoluto. Zuccheri semplici e fruttosio: zero. Omega-3 EPA+DHA 4g/die (riduce TG 25-50%). MCT permessi. Monitorare amilasi/lipasi.'},
  sindrome_refeeding:{kcal:'Iniziare 10 kcal/kg/die, incrementare gradualmente',prot:'0.8-1.0 g/kg/die (incrementare con cautela)',note:'ASPEN 2020 · ESPEN 2018. OBBLIGATORIO: tiamina 200-300mg EV prima di renutrire. Fase 1 (gg 1-3): 10 kcal/kg/die. Fase 2 (gg 4-7): 15-20 kcal/kg/die. Monitorare ogni 12-24h: fosfato (>0.6 mmol/L), K, Mg. Stop se ipofosforemia severa.'},
  colangite_biliare_primitiva:{kcal:'Normocalorica (ipocalorica se steatosi associata)',prot:'1.0-1.2 g/kg/die',note:'EASL 2017. Vitamine liposolubili ADEK supplementate. Vitamina D target 40-60 ng/mL. Calcio 1000-1200mg/die. Grassi <40g/die se steatorrea. Alcol zero. UDCA come terapia principale.'},
  nutrizione_preoperatoria:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021 · ERAS. Immunonutrizione pre-op 5-7 gg (arginina 15-20g + EPA 2g + nucleotidi). Bevanda glucidica 12.5% fino a 2h pre-anestesia. Correggere malnutrizione 7-14 gg pre-op.'},
  galattosemia:{kcal:'Normocalorica per età e peso',prot:'1.0-1.2 g/kg/die (da fonti senza galattosio)',note:'SSIEM 2022. Eliminazione totale e permanente di latte e derivati. Calcio supplementare 1000-1200 mg/die. Vitamina D 1000-2000 UI/die. Monitorare densità ossea. Follow-up multidisciplinare.'},
  sindrome_cushing:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.2-1.5 g/kg/die',note:'ES 2021. Sodio <2g/die. Calcio 1000-1200mg/die + vitamina D 2000 UI/die. Proteine aumentate (catabolismo da ipercortisolismo). CHO basso IG (insulino-resistenza). Monitorare glicemia, lipidi, densità ossea.'},
  neutropenia_oncologica:{kcal:'25-35 kcal/kg/die (adeguata a trattamento)',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Sicurezza microbiologica rigida: no crudi animali, no formaggi molli non pastorizzati, no succhi freschi, no germogli. Cottura completa a >75°C. Frutta/verdura lavata e sbucciata. Latte UHT o pastorizzato.'},
  epatite_cronica:{kcal:'Normocalorica (ipocalorica se sovrappeso/steatosi)',prot:'1.0-1.2 g/kg/die',note:'EASL 2024. Alcol zero assoluto. Mantenere BMI 20-25. Caffè 2-3 tazze/die (rallenta fibrosi). Fibre ≥25g/die, antiossidanti. Evitare supplementi di ferro. Vitamina D se <30 ng/mL.'},
  artrite_psoriasica:{kcal:'Ipocalorica se sovrappeso (BMI target <25)',prot:'1.0-1.2 g/kg/die',note:'GRAPPA 2022 · EULAR 2022. Perdita di peso migliora risposta ai biologici. Dieta mediterranea. Omega-3 3g/die. Alcol zero. Vitamina D target >40 ng/mL. Folati 5mg/die se MTX.'},
  acalasia:{kcal:'Normocalorica (prevenire la malnutrizione)',prot:'1.0-1.2 g/kg/die',note:'ESGE 2020 · ACG 2020. Alimenti morbidi/semiliquidi/tritati. Pasti piccoli e frequenti (5-6/die). Postura eretta durante e 30-60 min dopo i pasti. Evitare liquidi freddi. Vitamina B12 e ferro: monitorare. ONS se intake inadeguato.'},
  iperomocisteinemia:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die (ridurre fonti elevate di metionina)',note:'ESC 2020 · EFNS 2020. Folati 0.4-5 mg/die. B12 1000 µg/die se carente. B6 10-25 mg/die. Verdure a foglia verde, legumi, cereali integrali. Astenersi dall\'alcol. Monitorare omocisteina, B12, folati, funzione renale.'},
  dumping_syndrome:{kcal:'Normocalorica (5-6 piccoli pasti/die)',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Pasti piccoli e frequenti (5-6/die). Niente liquidi durante i pasti (solo 30-45 min dopo). Limitare zuccheri semplici. Fibre solubili rallentano svuotamento gastrico. Dumping tardivo: CHO complessi a basso IG, proteine ad ogni pasto.'},
  malassorbimento_fruttosio:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ACG 2021. Limitare fruttosio libero in eccesso (>glucosio): miele, mela, pera, mango, bevande con HFCS. Sorbitolo: evitare (E420, frutta secca, gomme da masticare). Fruttosio bilanciato da glucosio (banana, agrumi) generalmente tollerato. FODMAP misti spesso coinvolti.'},
  dieta_fodmap:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'Monash University 2022. Fase 1 (6 settimane): eliminazione FODMAP. Fase 2: reintroduzione sistematica per identificare trigger personali. Glutine: possibile cross-intolleranza. Fibre: mantenere (psyllium tollerato). Guida dietistica essenziale per evitare restrizioni inutili.'},
  ernia_iatale:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ACG 2022 · ESGE 2020. Pasti piccoli e frequenti. Non coricarsi per 3h dopo i pasti. Evitare scatenanti: cibi grassi, cioccolato, caffè, alcol, menta, pomodoro, agrumi, cibi piccanti. Elevare testata del letto 15-20 cm. Perdita di peso se BMI >25.'},
  deficit_vitamina_d:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'SIOMMMS 2022 · ESPEN 2022. 25-OH-D target >30 ng/mL (ideale 40-60 ng/mL). Supplementazione 1000-4000 UI/die colecalciferolo. Alimenti ricchi: salmone, sgombro, tonno, tuorlo, latte/derivati fortificati. Esposizione solare 15-20 min/die. Calcio 1000-1200 mg/die.'},
  deficit_b12_folati:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'BSH 2022 · ESPEN 2022. B12 1000 µg/die IM o 1000-2000 µg/die po (alte dosi per assorbimento passivo). Folati 5 mg/die fino a normalizzazione, poi 0.4 mg/die mantenimento. Alimenti ricchi B12: fegato, molluschi, pesce, uova, latticini. Folati: verdure a foglia verde, legumi, cereali integrali.'},
  terapia_anticoagulante:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ESC 2021 · ACCP 2021. Warfarin: vitamina K COSTANTE (non eliminare). Verdure a foglia verde: 1-2 porzioni/die costanti. Monitorare INR frequentemente se cambio dieta. Alcol: evitare eccessi. NAO (apixaban, rivaroxaban): nessuna restrizione dietetica. Evitare integratori di vitamina K non prescritti.'},
  ncgs:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ESPGHAN 2021 · BSG 2021. Dieta priva di glutine (GFD) come per celiachia. Escludere celiachia (IgA anti-tTG) e allergia al grano prima. NCGS: nessun marcatore sierologico confermato. GFD migliora sintomi nel 70-80%. Cereali GF: riso, mais, grano saraceno, quinoa, miglio. Monitorare fibre, folati, ferro, vitamina B.'},
  epatite_autoimmune:{kcal:'Normocalorica (ipocalorica se sovrappeso da steroidi)',prot:'1.0-1.2 g/kg/die',note:'EASL 2022. Alcol zero assoluto. Dieta mediterranea anti-infiammatoria. Terapia steroidea: limitare sodio e zuccheri semplici, aumentare calcio (1000-1200 mg/die) e vitamina D (2000 UI/die). Monitorare peso, glicemia, lipidi (effetti da steroidi). Azatioprina: folati 0.4-1 mg/die.'},
  obesita_pediatrica:{kcal:'Deficit moderato: -10-20% rispetto al fabbisogno stimato per età/sesso/altezza',prot:'1.0-1.2 g/kg/peso ideale/die',note:'ESPGHAN 2022 · ISPAD 2022. Obiettivo: rallentamento aumento peso (non perdita rapida nei bambini in crescita). Intervento familiare. Ridurre cibi ultra-processati, bevande zuccherate. Almeno 5 porzioni frutta/verdura/die. Attività fisica 60 min/die. No diete drastiche <12 anni.'},
  celiachia_refrattaria:{kcal:'30-35 kcal/kg/die (ipercalorica per malassorbimento)',prot:'1.2-1.5 g/kg/die',note:'ESGE 2022 · AGA 2022. GFD stretta con verifica cross-contaminazione (<20 ppm). RCD Tipo I: risposta a steroidi. RCD Tipo II: rischio linfoma T-associato. Nutrizione enterale/parenterale se malassorbimento severo. Integrare: ferro, folati, B12, calcio, vitamina D, zinco. Follow-up bioptico annuale.'},
  ipoglicemia_reattiva:{kcal:'Normocalorica (5-6 piccoli pasti/die)',prot:'1.0-1.2 g/kg/die',note:'Endocrine Society 2022. Pasti piccoli e frequenti (5-6/die). CHO complessi a basso IG ad ogni pasto. Proteine e grassi ad ogni pasto (rallentano assorbimento CHO). Evitare zuccheri semplici e bevande zuccherate. Monitorare glicemia 1-2h dopo i pasti. Distinguere da insulinoma: test da digiuno prolungato.'},
  iperparatiroidismo:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'AACE 2022. Calcio alimentare: non eliminare ma moderare se calcemia >11 mg/dL (restrizione stimola PTH). Vitamina D target 50-60 ng/mL (non oltre 100). Idratazione 2-3 L/die. Na <1.5 g/die. Vitamina K2 100-200 µg/die. Post-paratiroidectomia: supplementare calcio e vitamina D (hungry bone syndrome).'},
  sclerodermia:{kcal:'Normocalorica o ipercalorica se malnutrizione',prot:'1.2-1.5 g/kg/die',note:'EULAR 2017 · ACR 2022. GI involvement 90%: cibi morbidi, pasti piccoli 5-6/die, postura eretta post-pasto. SIBO: antibiotici ciclici, probiotici. Omega-3 3g/die. Vitamina D 2000-4000 UI/die. Vitamina C e E antiossidanti. Monitorare peso settimanalmente. ONS se intake <70% fabbisogno.'},
  allergia_nichel:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'SIAAIC 2022. Soglia nichel ~100-200 µg/die. Alimenti ad alto contenuto: cacao, semi di girasole, legumi, cereali integrali, spinaci, pomodori. Alimenti a basso contenuto: riso, pasta raffinata, carne, pesce, uova, latte. Vitamina C ai pasti riduce assorbimento nichel. Dieta di rotazione. Personalizzare in base a gravità.'},
  intestino_corto:{kcal:'35-45 kcal/kg/die (aumentato per malassorbimento)',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2020 · ASPEN 2021. SBS <200 cm. NPD se autonomia entrale impossibile. ORS isotonica per reidratazione. CHO complessi > semplici. MCT permessi. Integrare: Mg, Zn, B12, ADEK, Ca. Probiotici (LGG, S.boulardii). Teduglutide (GLP-2) riduce fabbisogno NPD. Adattamento intestinale max 2 anni.'},
  masld_nash_avanzato:{kcal:'Ipocalorica se sovrappeso: deficit 500-750 kcal/die',prot:'1.2-1.5 g/kg peso ideale/die',note:'EASL 2024 · AASLD 2023. Perdita peso 7-10%: riduce fibrosi (meta-analisi 2024). Alcol zero assoluto. Fruttosio/HFCS: eliminare. Omega-3 EPA+DHA 2-4g/die. Vitamina E 800 UI/die (solo in NASH senza DM tipo 2). CHO a basso IG. Fibre 30g/die. Esercizio aerobico 150 min/sett + resistenza. Farmaco: resmetirom (2024).'},
  depressione_nutrizione:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ISNS 2023. Dieta mediterranea: riduce rischio depressione del 33% (meta-analisi). Omega-3 EPA 2g/die (RCT efficacia antidepressiva). Triptofano: tacchino, avena, legumi, uova, latticini. Folati 0.4-5 mg/die. B12. Vitamina D 1000-2000 UI/die. Zinco 15-30 mg/die. Magnesio 300-400 mg/die. Microbiota: probiotici e fibre.'},
  sonno_nutrizione:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'AASM 2023. Caffeina: eliminare dopo le 14:00 (t½ 5-7h). Ultimo pasto 2-3h prima del sonno (leggero). Triptofano serale: latte caldo, tacchino, avena, banana. Melatonina alimentare: ciliegie, uva, pomodori, noci. Vitamina D. Magnesio glicinato 300 mg/sera. Alcol peggiora architettura del sonno. Crono-nutrizione: orari regolari.'},
  ipertensione_resistente:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ESH 2023 · AHA 2021. Dieta DASH massimale. Na <1.5 g/die (riduzione PA -5/-3 mmHg aggiuntiva). K 3500-5000 mg/die. Nitrati alimentari (barbabietola, spinaci). Cioccolato fondente 30g/die (flavanoli). DASH + perdita peso 5%: equivale a 1 farmaco aggiuntivo. Alcol zero.'},
  gravidanza_fisiologica:{kcal:'I trim: normocalorica. II trim: +350 kcal/die. III trim: +450 kcal/die',prot:'1.1 g/kg/die (I trim), 1.2 (II), 1.5 (III)',note:'SIGO 2022 · ISS 2022. Folati 400 µg/die pre-concepimento + I trim. DHA 200 mg/die. Ferro 27 mg/die. Iodio 220 µg/die. Calcio 1000 mg/die. Vitamina D 600-1000 UI/die. EVITARE: pesce spada, tonno grandi quantità, latticini non pastorizzati, alcol, caffeina >200 mg/die, carni crude.'},
  trapianto_renale:{kcal:'25-30 kcal/kg/die (fase stabile)',prot:'1.3-1.4 g/kg/die',note:'KDIGO 2022 · ESPEN 2022. EVITARE: pompelmo (inibisce CYP3A4 → tossicità ciclosporina), mirtillo rosso, melograno. Steroidi: Na <2g/die, zuccheri semplici ridotti, Ca 1000-1200 mg/die, vitamina D 2000 UI/die. K e P: monitorare (normalizzati ma variabili). Dislipidemia da immunosoppressori: grassi saturi <7%.'},
  mastocitosi:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'AAAAI 2022. Dieta a bassa istamina: formaggi stagionati, vino, aceto, alimenti fermentati, pesce in scatola, pomodori, spinaci = trigger principali. Lista trigger individuale obbligatoria (diario). Vitamina C 500-1000 mg/die (co-fattore DAO). Vitamina D. Quercetina 500 mg/die come stabilizzatore mastocitario. Alcol: evitare (libera istamina). Additivi (E102-E133, E211-E228, E621): eliminare.'},
  porfiria:{kcal:'≥35 kcal/kg/die (evitare restrizione calorica)',prot:'1.0-1.2 g/kg/die',note:'EPNET 2022 · EASL. CHO ≥300g/die in remissione (≥60% energie). Digiuno: PROIBITO (precipita crisi). Dieta ipocalorica: PROIBITA. Alcol: zero assoluto. In crisi: glucosio ev 3-4 g/kg/die (induce eme ossigenasi). Omega-3 permessi. Supplementare: Mg, vitamina B6 (ma con cautela), vitamina C. Evitare ferro in eccesso. Idratazione 2.5 L/die.'},
  ipoparatiroidismo:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ETA 2022 · ESE 2021. Calcio 1000-1500 mg/die da alimenti. Vitamina D attiva (calcitriolo 0.25-2 µg/die, non colecalciferolo da solo). Fosforo: limitare additivi fosfatici (E450, E451, cola) → target P <4.5 mg/dL. Magnesio 300 mg/die (ipomagnesiemia aggrava ipocalcemia). Fibre non eccessive (riducono assorbimento Ca). Vitamina K2 100 µg/die (calcificazioni ectopiche). Citrato (agrumi) migliora assorbimento Ca.'},
  linfangectasia:{kcal:'35-40 kcal/kg/die (malassorbimento)',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2020 · NORD. LCT <10g/die (grassi a lunga catena: usano linfatici). MCT 40-60g/die in sostituzione (assorbimento portale diretto). Omega-3 permesso (non attraversa linfatici). Supplementare: ADEK parenterali o idrosolubili, albumina ev se grave. Calcio, B12, folati. NPT in fase acuta grave. Probiotici: LGG riduce perdita proteica (piccoli studi).'},
  pancreatite_autoimmune:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'IAP 2023 · JPS. Fase acuta: digiuno + NPT o NE digiunale. Fase di remissione su steroidi: Na <2g/die (cortisonico), Ca 1000-1200 mg, Vitamina D 2000 UI. Lipidi <40g/die se malassorbimento esocrino. Alcol: zero assoluto (precipita riacutizzazioni). Enzimi pancreatici se steatorrea. Glicemia: monitorare (diabete pancreatico frequente). Caffeina: ridotta.'},
  prader_willi:{kcal:'60-70% del fabbisogno standard per peso altezza (non BMI attuale)',prot:'1.2-1.5 g/kg peso ideale/die',note:'PWSA 2021 · GH Research Society. Calorie ridotte ma dieta nutriente. Densità calorica bassa: verdure ad libitum. Nessun accesso libero al cibo (ambiente strutturato). GH terapia: aumenta massa magra, aumenta fabbisogno proteico. Fibre 25-35g/die per sazietà. Calcio + vitamina D (osteoporosi frequente). Omega-3. Obiettivo: BMI <30, idealmente <25.'},
  trapianto_midollo:{kcal:'30-35 kcal/kg/die (fase acuta 35-40)',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2021 · EBMT. Fase aplasia (neutropenia <500): dieta a bassa carica microbica (no crudi, no fermentati non pastorizzati, no frutta con buccia non pelabile). Mucositi: frullati, cibi freddi, ONS. GvHD intestinale: NE elementare/semi-elementare. NPT se GI non funzionante >3gg. Evitare: pompelmo, succo di mirtillo (interazioni farmaci). Vitamina D, Mg, K monitorati.'},
  mieloma:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021 · IMF. Ipercalcemia (30% pazienti): idratazione ≥2.5L/die, non ridurre Ca alimentare (paradossalmente utile). Insufficienza renale: P <800mg, K <2g, Na <2g. Anemia: Fe biodisponibile, B12, folati. Immunosoppressione: igiene alimentare rigorosa. Bifosfonati: Ca 1000-1200mg + Vit D 800-1000UI. Omega-3 anti-infiammatorio. Mieloma smoldering: dieta mediterranea preventiva.'},
  tirosinemia:{kcal:'Normocalorica (adattata a età/peso)',prot:'Formula + quota naturale calcolata al mg',note:'SSIEM 2023 · MetAbolic. NTBC (nitisinone): terapia farmacologica di base, riduce necessità dietetica ma non la elimina. Target aminoacidi plasma: Tyr 200-400 µmol/L adulti, Phe 20-80 µmol/L. Formula aminoacidica priva di Tyr+Phe: fonte proteica principale. Fenilalanina naturale: 20-50 mg/kg/die (calcolata). Integrare: Fe (NTBC può causare carenza), Zn, Ca, vitamina D. Monitoraggio AFP e ecografia epatica.'},
  msud:{kcal:'Normocalorica (adattata a età/peso)',prot:'Formula BCAA-free + quota naturale calcolata',note:'ACMG 2014 · SSIEM 2020 · HCU Network. Target leucina: 75-200 µmol/L (neonati 75-100). Crisi metabolica: eliminare BCAA, glucosio ev ad alto flusso. Formula priva di Leu+Ile+Val: base proteica. Leucina naturale: limitata e calcolata (tossicità neurale). Isoleucina e valina: supplementare separatamente (carenza isolata). Tiamina: 10-100 mg/die (50% risponde). Aminoacidi monitorati ogni settimana (neonato) → ogni 3 mesi (adulto stabile).'},
  glomerulonefrite:{kcal:'30-35 kcal/kg/die',prot:'0.6-0.8 g/kg/die (se GFR<60); aumentare se proteinuria nefrosica',note:'KDIGO 2021. Sodio <2g/die. Potassio adattato al GFR. Omega-3 2g/die (effetto antiproteinurico). Vitamina D integrare. Monitorare PA target <130/80 mmHg.'},
  ulcera_peptica:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ACG 2022. Non esiste dieta rigida. Evitare scatenanti individuali. FANS controindicati. Alcol zero. Pasti regolari 4-5/die. Fibra solubile favorisce guarigione mucosa. Probiotici se H. pylori in eradicazione.'},
  osteoartrite:{kcal:'Ipocalorica se sovrappeso (obiettivo -5-10% peso)',prot:'1.0-1.2 g/kg/die',note:'EULAR 2023 · OARSI 2020. Omega-3 2-3g/die. Vitamina D target >40 ng/mL. Glucosamina solfato 1500mg/die. Collagene idrolizzato 10g/die. Vitamina C 200mg/die. Curcuma 1g/die.'},
  tumore_polmone:{kcal:'30-35 kcal/kg/die',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2021. Cachessia nel 40-80%. Omega-3 EPA 2g/die anti-cachessia. ONS se intake <60% per >7gg. Alimenti morbidi e freschi se esofagite da RT. Vitamina D, zinco, selenio.'},
  tumore_prostata:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ESPEN 2021 · PCF 2023. Licopene 10-15mg/die. Soia e fitoestrogeni. Grassi saturi <10%. Omega-3 3g/die. Vitamina D target >40 ng/mL. Alcol: eliminare.'},
  tumore_stomaco:{kcal:'30-35 kcal/kg/die',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2021. Pasti piccoli 6-8/die. Dumping: no liquidi ai pasti. B12 parenterale obbligatoria. Ferro, calcio citrato, vitamina D, folati.'},
  tumore_fegato:{kcal:'35-40 kcal/kg/die (peso secco)',prot:'1.2-1.5 g/kg/die',note:'EASL 2022 · ESPEN 2021. Malnutrizione 60-90%. 4-6 pasti/die + snack serale CHO. BCAA 12g/die se encefalopatia/sarcopenia. ONS se intake <70%.'},
  steatoepatite_alcolica:{kcal:'35-40 kcal/kg/die (peso secco)',prot:'1.2-1.5 g/kg/die (NON ridurre)',note:'EASL 2023 · AASLD 2020. Alcol zero assoluto. Thiamina 100mg/die. Zinco, magnesio, vitamina K, D. BCAA se encefalopatia. 4-6 pasti + snack serale CHO.'},
  polimialgia_reumatica:{kcal:'Normocalorica (ipocalorica se aumento ponderale da steroidi)',prot:'1.0-1.2 g/kg/die',note:'EULAR 2023. Ca 1000-1200mg/die + Vitamina D 2000 UI/die (obbligatori per corticosteroidi). Na <2g/die. Zuccheri limitati. Omega-3 3g/die.'},
  iperaldosteronismo:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ES 2021. Sodio <1.5g/die. Potassio ≥4g/die. Dieta DASH. Alcol zero. Dopo adrenalectomia: monitorare PA e potassio.'},
  nefropatia_iga:{kcal:'30-35 kcal/kg/die',prot:'0.6-0.8 g/kg/die',note:'KDIGO 2021. Sodio <2g/die. Omega-3 EPA+DHA 2-3g/die. Potassio e fosforo adattati al GFR. Vitamina D carente: integrare.'},
  artrite_reattiva:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EULAR 2022. Omega-3 2-3g/die. Vitamina D target >40 ng/mL. Zinco 15mg/die. Probiotici: Lactobacillus (post-infettivo).'},
  acromegalia:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ES 2014 · AACE 2021. CHO a basso IG (diabete secondario). Sodio <2g/die. Calcio 1000-1200mg/die + vitamina D. Fibre ≥30g/die. Omega-3 3g/die.'},
  nutrizione_anziani:{kcal:'30 kcal/kg/die (monitorare apporti reali)',prot:'1.0-1.2 g/kg/die (aumentare a 1.5 se sarcopenia)',note:'ESPEN 2022 · PROT-AGE 2013. Vitamina D 800-2000 UI/die. Calcio 1200mg/die. B12 monitorare. Leucina ≥3g/pasto. Omega-3. Zinco. Texture IDDSI adattata.'},
  fragilita:{kcal:'30-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2022 · ICFSR 2020. Leucina ≥3g/pasto. Vitamina D 800-2000 UI/die. Calcio 1200mg/die. Omega-3 2g/die. ONS se intake insufficiente. B12. Zinco. Sinergia attività fisica + proteine.'},
  vasculite:{kcal:'Normocalorica (ipocalorica se sovrappeso da steroidi)',prot:'1.0-1.2 g/kg/die',note:'EULAR 2022. Ca 1000-1200mg/die + Vitamina D 2000 UI/die. Sodio <2g/die. Omega-3 3g/die. Folati 5mg/die se immunosoppressori. Monitorare glicemia.'},
  sarcoidosi:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ATS/ERS 2022. Calcio alimentare ridotto (500-600mg/die) per ipercalciuria. Liquidi ≥2.5L/die. Vitamina D3: NON supplementare routinariamente (granulomi producono 1,25-OH-D autonomamente). Vitamina K2 100µg/die.'},
  dermatomiosite:{kcal:'Normocalorica o ipercalorica se malnutrizione',prot:'1.2-1.5 g/kg/die',note:'EULAR 2023. Leucina ≥3g/pasto. Vitamina D target >40 ng/mL. Calcio 1000-1200mg/die. Omega-3 3g/die. Texture IDDSI se disfagia. Folati se MTX.'},
  trapianto_fegato:{kcal:'30-35 kcal/kg/die (pre); 25-30 (mantenimento)',prot:'1.2-1.5 g/kg/die (pre-acuta); 1.0-1.2 (mantenimento)',note:'EASL/ESPEN 2019. Immunosoppressori: evitare pompelmo/mirtillo rosso. Sicurezza alimentare 3-6 mesi post-OLT. NODAT: CHO basso IG. Ca+D per steroidi. Monitorare glicemia, lipidi, peso.'},
  nutrizione_uti:{kcal:'10-20 kcal/kg/die (fase acuta); 25-30 (post-acuta)',prot:'1.3-2.0 g/kg/die (progressivo)',note:'ESPEN 2023 · ASPEN 2022. NE precoce entro 24-48h. Glutammina 0.35g/kg (ustioni/trauma). Vitamina C 1-2g/die (sepsi). Zinco, Se, Vit D. Glicemia target 140-180 mg/dL. Vigilare refeeding.'},
  nutrizione_palliativa:{kcal:'Adattata a tolleranza e aspettativa di vita',prot:'Adattata a tolleranza',note:'ESPEN 2021 · EAPC 2021. Obiettivo: qualità di vita. Aspettativa >3 mesi: ONS/NE attivi. Aspettativa <1 mese: solo comfort. Non forzare l\'alimentazione. Reidratazione minima terminale.'},
  ipertensione_polmonare:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ESC/ERS 2022. Sodio <1.5-2g/die. Fluidi 1.5-2L/die. Ferro: supplementare se ferritina <100µg/L. Omega-3 2g/die. No pompelmo (interazione farmaci). Vitamina K costante se warfarin.'},
  asma_bronchiale:{kcal:'Normocalorica (ipocalorica se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'GINA 2023. Vitamina D target >40 ng/mL. Omega-3 2-3g/die. Vitamina C 500mg/die. Magnesio 300-400mg/die. Quercetina 500mg/die. Evitare solfiti (E220-228). Alcol con cautela (solfiti in vino).'},
  bronchiectasie:{kcal:'+20-30% del fabbisogno basale (30-40 kcal/kg/die)',prot:'1.2-1.5 g/kg/die',note:'ERS 2017. Omega-3 2g/die. Vitamina D target >30 ng/mL. Zinco 15mg/die. Vitamina C 500mg. Idratazione abbondante. ONS se peso in calo.'},
  acidemia_metilmalonica:{kcal:'Normocalorica per età/peso',prot:'Formula IMVT-free + quota naturale calcolata',note:'ACMG 2022. Isoleucina+valina+metionina+treonina: limitare. Vitamina B12 idrossocobalamina 1-2mg IM/sett. Carnitina 100mg/kg/die. Monitorare ammonio, B12, carnitina. Crisi: glucosio ev, stop proteine.'},
  sindrome_down:{kcal:'Moderato deficit se sovrappeso (80-90% fabbisogno standard)',prot:'1.0-1.2 g/kg peso ideale/die',note:'JIDSA 2022. Vitamina D 800-2000 UI/die. Calcio 1000-1200mg/die. Omega-3 DHA (funzione cognitiva). Screening celiachia (5-12% co-prevalenza). Monitorare TSH (ipotiroidismo 30%). Texture adattata se necessario.'},
  fibrosi_polmonare:{kcal:'+20-30% del fabbisogno basale (30-40 kcal/kg/die)',prot:'1.2-1.5 g/kg/die',note:'ATS/ERS 2022. Grassi 35-40% en. CHO non eccessivi. Antiossidanti (C 1g, E 400UI). Omega-3 2g/die. Vitamina D target >30 ng/mL. Pasti piccoli e frequenti. ONS ad alto contenuto lipidico se cachessia.'},
  emofilia:{kcal:'Ipocalorica se sovrappeso (BMI target 20-25)',prot:'1.0-1.2 g/kg/die',note:'WFH 2020. BMI target 20-25 (peso riduce carico articolare). Calcio 1000-1200mg/die + Vitamina D. Omega-3 2g/die. Ferro: monitorare. Alcol: limitare. FANS: CONTROINDICATI.'},
  cistinuria:{kcal:'Normocalorica',prot:'0.8-1.0 g/kg/die (fonti a bassa metionina preferite)',note:'EAU 2022. Liquidi ≥3-4L/die. Urina alcalina pH 7.0-7.5. Metionina limitata: ridurre carni rosse, uova, soia. Sale <2g/die. Vitamina C: EVITARE. Potassio citrato 60-80 mEq/die.'},
  sindrome_antifosfolipidi:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EULAR 2023. Vitamina K costante (se warfarin): verdure a foglia verde 1-2 porz/die costanti. Omega-3 2-3g/die. Folati+B6+B12 (omocisteina). No pompelmo (warfarin). NAO: nessuna restrizione.'},
  ipercalcemia:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ENDO 2022. Liquidi 2.5-3L/die. Calcio alimentare: ridurre a 500-600mg/die. Vitamina D: EVITARE supplementi se Ca>10.5 mg/dL. Fibra riduce assorbimento Ca. Sale moderato. Alcol: evitare.'},
  obesita_sarcopenica:{kcal:'Deficit moderato: -500 kcal/die (mai <1200F/1500M)',prot:'1.2-1.5 g/kg peso ideale/die',note:'ESPEN 2022 · EASO 2022. Leucina ≥3g/pasto. Vitamina D 2000 UI/die. Calcio 1000-1200mg/die. Omega-3 2g/die. ESERCIZIO DI RESISTENZA essenziale. Monitorare DEXA, forza handgrip, velocità del cammino.'},
  nutrizione_atleta:{kcal:'Variabile: TDEE + 300-800 kcal (massa) o TDEE -300-500 kcal (definizione)',prot:'1.4-2.0 g/kg/die',note:'IOC 2021. CHO 5-12g/kg/die (adattati a volume allenamento). Timing: CHO+Prot entro 30-60 min post-allenamento. Creatina 3-5g/die. Caffeina 3-6mg/kg. Idratazione: 500ml pre + perdite durante. EA >45 kcal/kg FFM/die.'},
  diarrea_cronica:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ACG 2022. Low-FODMAP 4-6 settimane. S. boulardii 500mg 2x/die. Psyllium (fibra solubile). ORS 1-2L/die. Fibre insolubili ridotte in fase acuta. No caffeina/alcol. Escludere cause organiche prima.'},
  digiuno_intermittente:{kcal:'16:8 → 1800-2200 kcal in 8h | 5:2 → 500 kcal nei 2 gg di digiuno',prot:'1.2-1.6 g/kg/die per preservare massa muscolare',note:'NEJM 2019. Finestra 8h: 12:00-20:00 tipica. Idratazione libera nelle 16h di digiuno (acqua, tè, caffè non zuccherati). No digiuno in gravidanza, DCA, diabete tipo 1 non monitorato, BMI<18.5.'},
  dieta_mediterranea:{kcal:'1800-2500 kcal/die in base a peso, età, attività',prot:'1.0-1.2 g/kg/die da fonti miste (pesce, legumi, latticini, carne bianca)',note:'PREDIMED 2013: riduzione -30% eventi CV. Score MedDiet target ≥9/14. Olio EVO 40-60 ml/die, legumi ≥3 volte/settimana, pesce ≥2-3 volte/settimana. Vino: opzionale, 1 bicchiere/die con pasto.'},
  nutrizione_enterale:{kcal:'25-35 kcal/kg/die in base alla formula scelta',prot:'1.2-2.0 g/kg/die (standard 1.2, critico 1.5-2.0)',note:'ESPEN 2019. Formula standard 1 kcal/ml; iperenergetica 1.5 kcal/ml; iperproteica ≥20% energia. Avvio 20-25 ml/h, incremento ogni 8-12h. Monitorare residuo gastrico (max 500ml/4h). Risciacquo sonda 30ml acqua ogni 4-6h.'},
  nutrizione_parenterale:{kcal:'25-30 kcal/kg/die (fase acuta 20-25 kcal/kg)',prot:'1.2-2.0 g/kg/die (aminoacidi nella sacca 3-in-1)',note:'ESPEN 2019/ASPEN 2022. Sacca 3-in-1: glucosio 3-5 g/kg/die, lipidi 0.7-1.5 g/kg/die, AA 1.2-2 g/kg/die. Insulina correzione glicemia 140-180 mg/dL. Multivitaminici + oligoelementi obbligatori. Monitorare TG, funzione epatica.'},
  ustioni_gravi:{kcal:'Formula Curreri: (25×kg) + (40×%BSA) kcal/die — può superare 5000 kcal in grandi ustioni',prot:'1.5-2.5 g/kg/die (massimo in medicina clinica)',note:'ESPEN 2013/ABA 2022. Nutrizione enterale entro 6-12h dall\'evento. Glutammina 0.3-0.5 g/kg/die. Vitamina C 66 mg/kg/die nelle prime 24h (riduce edema). Zinco 220 mg/die, selenio, vitamina D. Monitoraggio quotidiano peso e bilancio azotato.'},
  sepsi:{kcal:'Fase acuta (1-2 gg): ≤20 kcal/kg/die | Fase subacuta (3+): 25-30 kcal/kg/die',prot:'1.2-1.5 g/kg/die (aumentare progressivamente)',note:'ESPEN 2023/SCCM 2021. Ipocalorico nelle prime 48h (risposta catabolica protettiva). Glutammina controindicata in MOF/shock multiplo. Selenio 500-1000 μg/die nei primi 10 gg. Target glicemia 140-180 mg/dL. Preferire enterale (30 ml/h trofic) a parenterale.'},
  tumori_net:{kcal:'2000-2500 kcal/die (adeguato fabbisogno oncologico)',prot:'1.2-1.5 g/kg/die',note:'ENETS 2022/ESPEN 2021. Sindrome carcinoide: evitare tiramina (formaggi stagionati, avocado, banana, vino rosso), alcol, caffeina eccessiva. NET secernente serotonina: niacina B3 50-100 mg/die (pellagra da deviazione triptofano). Insulinoma: pasti piccoli e frequenti ogni 3h.'},
  leucemia:{kcal:'30-35 kcal/kg/die (ipermetabolismo da CT e infezioni)',prot:'1.5-2 g/kg/die',note:'ESPEN 2021/NCCN 2023. Dieta neutropenica se ANC<500: tutto cotto, pastorizzato, no crudo. Temperatura interna carni ≥74°C. No formaggi molli, sushi, sprouts, insalate crude. Folati 400-800 μg/die. Ferro, zinco, vitamina D. Considerare NE se malnutrizione >5% del peso corporeo.'},
  linfoma:{kcal:'30-35 kcal/kg/die',prot:'1.5-2 g/kg/die (alto turn-over proteico da CT)',note:'ESPEN 2021/NCCN 2023. Metotrexato: non ridurre folati alimentari arbitrariamente (solo se prescritto specificamente). Corticosteroidi: dieta low-Na, basso IG, calcio 1000 mg/die, vitamina D. Rituximab: no restrizioni alimentari specifiche. Monitorare albumina e prealbumin mensile.'},
  trapianto_cuore:{kcal:'1800-2200 kcal/die (evitare sovrappeso da corticosteroidi)',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2022/ISHLT 2016. EVITARE SEMPRE: pompelmo, succo pompelmo, bergamotto, melograno (inibiscono CYP3A4 → tossicità tacrolimus/ciclosporina). Sodio <2300 mg/die (ipertensione da ciclosporina). Potassio moderato se ACE-inibitori. Alcol controindicato. Follow-up nutrizionale mensile per 1 anno.'},
  rene_policistico:{kcal:'1800-2200 kcal/die (mantenimento peso normale)',prot:'0.8-1.0 g/kg/die se GFR normale; ridurre se GFR scende',note:'KDIGO 2023. Idratazione 2.5-3 L/die (diluisce ADH, riduce crescita cistica). Sale <5 g/die (riduce cAMP intra-renale). Caffeina <300 mg/die. Fruttosio limitato (associato a crescita cistica). Ossalato: moderato se calcolosi concomitante. Adattare progressivamente a stadio CKD.'},
  deficit_zinco:{kcal:'Fabbisogno standard per età e peso corporeo',prot:'Adeguato — le proteine animali migliorano assorbimento zinco',note:'WHO/ESPEN 2022. Supplemento terapeutico: zinco gluconato/solfato 25-40 mg elemento/die × 3-6 mesi. Fonti eccellenti: ostriche (60 mg/100g), carne rossa, semi di zucca, cashew, legumi. Fitati riducono assorbimento (pane integrale < bianco per zinco). Eccesso: inibitore rame (max 40 mg/die senza supervisione).'},
  deficit_iodio:{kcal:'Standard per età',prot:'Standard',note:'WHO/ICCIDD 2007. Sale iodato: obbligatorio in Italia dal 2005. Fabbisogno: 150 μg/die adulti, 200-250 μg/die in gravidanza/allattamento. Fonti: pesce di mare (80-200 μg/100g), latticini (10-60 μg/100g), uova (50 μg/uovo). Goitrogeni (cavoli, broccoli, soia): ridurre assorbimento se crudi — cottura li inattiva parzialmente.'},
  anemia_falciforme:{kcal:'2200-2500 kcal/die (ipermetabolismo per emolisi cronica)',prot:'1.2-1.5 g/kg/die',note:'ASH 2020. Folati 1-5 mg/die supplemento. Zinco 25 mg/die (riduce emolisi e infezioni). Vitamina D 1000-4000 UI/die (deficit quasi universale). Omega-3 (EPA/DHA 2g/die) riducono viscosità e infiammazione. Idratazione 2.5-3.5 L/die obbligatoria. Evitare digiuno. No caffeina eccessiva o alcol.'},
  abuso_alcol:{kcal:'2000-2500 kcal/die (spesso malnutrito — renutrire gradualmente)',prot:'1.2-1.5 g/kg/die (rebuilding proteico)',note:'EASL 2018/ESPEN 2023. PRIORITÀ: tiamina EV/IM PRIMA di glucosio. Folati 5 mg/die. Zinco 220 mg/die. Magnesio se ipomagnesiemia. Vitamina B6, B12. Refeeding protocol se digiuno prolungato (rischio refeeding: monitorare fosforo, K, Mg). Astinenza = obiettivo principale. Follow-up epatico mensile.'},
  distrofia_muscolare:{kcal:'20-25 kcal/kg/die (ridotto per ipomobilità) | Corticosteroidi: ridurre 20-30%',prot:'1.0-1.5 g/kg/die (mantenere massa muscolare residua)',note:'TREAT-NMD 2021. Corticosteroidi cronici: dieta low-Na (<1500 mg/die), Ca 1200 mg/die, vitamina D 1000-4000 UI/die, basso IG. Disfagia: valutazione IDDSI, addensanti. Costipazione: 30g fibra/die, 2L acqua. Omega-3 effetto anti-infiammatorio. Obesità frequente da immobilizzazione. Monitoraggio BMI e BIA ogni 3 mesi.'},
  alimentazione_complementare:{kcal:'6-12 mesi: ~800-1000 kcal/die tot (latte + solidi); latte ancora 500-700 ml/die',prot:'6-12 mesi: ~11-14 g/die',note:'ESPGHAN 2022/OMS. Non prima di 4 mesi, ottimale ~6 mesi. Ferro: introdurre precocemente (carne, legumi, cereali arricchiti). Allergeni: introdurre precocemente e regolarmente (arachidi, uova, pesce, latte). Evitare: miele (<1 anno), sale, zucchero aggiunti, latte vaccino intero (<12m). Texture progressiva 4→5→6→7 (IDDSI).'},
  sindrome_premestruale:{kcal:'Standard per BMI — evitare restrizione calorica in fase luteale (peggiora craving)',prot:'Standard',note:'ACOG 2023. Magnesio 200-400 mg/die: riduce ritenzione e irritabilità. Calcio 1000-1200 mg/die: riduce sintomi umorali (-50%). Vitamina B6 50-100 mg/die: migliora umore. Ridurre sodio, caffeina, alcol nella fase luteale (14 gg prima mestruazione). Omega-3 2g/die: riduce dismenorrea.'},
  infertilita_nutrizione:{kcal:'Standard — raggiungere/mantenere BMI 20-25 (ottimale per fertilità)',prot:'1.0-1.2 g/kg/die da fonti miste',note:'ESHRE 2023. Folati 400-800 μg/die da almeno 3 mesi pre-concepimento. Vitamina D: correggere deficit (<30 ng/ml), target 40-60 ng/ml. Omega-3: migliora qualità oociti e spermatozoi. CoQ10 200-600 mg/die (riserva ovarica). Alcol zero in pre-concepimento. Dieta mediterranea come pattern base (+40% successo IVF, Gaskins 2021).'},
  ortoressia:{kcal:'Ripristinare fabbisogno normale: 1800-2200 kcal/die senza conteggio ossessivo',prot:'Standard — obiettivo è flessibilità, non ottimizzazione',note:'Bratman 2017/ESPEN 2023. Approccio riabilitativo graduale. Ridurre progressivamente liste di "cibi proibiti". Reintrodurre alimenti ansiogeni con supporto CBT. Pasti sociali come obiettivo terapeutico. Escludere cause organiche (celiachia, allergie reali) prima. Psicoterapia CBT obbligatoria in parallelo.'},
  microbiota_intestinale:{kcal:'Standard per età e peso — focus sulla qualità/diversità più che quantità',prot:'Standard',note:'Nature 2021/ESPEN 2023. Obiettivo: ≥30 tipi diversi di piante/settimana (studi APC Microbiome). Fibre prebiotiche: inulina, FOS, pectine, beta-glucani (≥25-30g/die totale). Fermentati: 2-6 porzioni/die (yogurt, kefir, kimchi, miso, tempeh). Evitare dolcificanti artificiali (alterano Lactobacillus/Bifidobacterium). Probiotici: ceppo-specifici per indicazione clinica.'},
  politrauma:{kcal:'TBI grave: 140% del REE nelle prime 2 settimane | Fase riabilitativa: 35-40 kcal/kg/die',prot:'1.5-2.5 g/kg/die (massimo in fase acuta)',note:'ESPEN 2018/BTF 2022. Nutrizione enterale entro 24-48h. TBI: DHA 2-4g/die per neuroprotection. Glicemia target 140-180 mg/dL (iper e ipoglicemia aumentano mortalità). Glutammina enterale 0.3-0.5 g/kg/die. Vitamina D 4000 UI, zinco per guarigione ossea. Progressione verso orale con valutazione logopedica post-extubazione.'},
  rachitismo_osteomalacia:{kcal:'Standard per età',prot:'Standard',note:'ENDO 2011/ISS 2022. Vitamina D3 terapeutica: 50.000 UI/settimana × 8 settimane, poi 1500-2000 UI/die mantenimento. Target 25(OH)D: 30-50 ng/ml. Calcio: 1000-1500 mg/die (adulti), 1200 mg/die (bambini). Magnesio necessario per metabolismo vitamina D. Esposizione solare 15-30 min/die. Monitorare PTH, Ca, fosforo, ALP.'},
  deficit_tiamina:{kcal:'Standard — garantire apporto calorico completo (mai glucosio prima di tiamina in Wernicke!)',prot:'Standard',note:'EFNS 2010/ESPEN 2022. EMERGENZA: tiamina EV 200-500 mg 3×/die × 3-5 gg, poi 100 mg/die po. RDA: 1.1-1.2 mg/die adulti. Fonti: maiale (0.9 mg/100g), cereali integrali, legumi, semi di girasole. Cottura riduce tiamina. Post-bariatrica: 100 mg/die vita. Post-alcol: mesi di supplementazione. Monitorare tiamina plasmatica + lattato.'},
  celiachia_bambini:{kcal:'Fabbisogno pediatrico per età (incremento per catch-up growth nei primi mesi di GFD)',prot:'1.0-1.5 g/kg/die (crescita)',note:'ESPGHAN 2020/SIGENP 2023. GFD rigorosa <20 ppm glutine. Alimenti sicuri: riso, mais, patate, grano saraceno, quinoa, amaranto, miglio, tapioca. Monitorare: ferro, folati, vitamina D, zinco (carenze all\'esordio). Anti-tTG IgA: ogni 6 mesi per 2 anni post-GFD, poi annuale. Crescita: curva auxologica ogni 3-6 mesi. Densità ossea: DXA a 12 mesi da diagnosi.'},
deficit_vitamina_a:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'OMS 2023. RDA Vitamina A: 700 µg RAE/die (F), 900 µg RAE/die (M). Supplementazione terapeutica: 200.000 UI retinolo per os, ripetuto a 24h e 4 settimane. Fonti: fegato, tuorlo, latte intero, arancioni e verdure a foglia verde. Liposolubile: assorbire con grassi. EVITARE ipervitaminosi (>3000 µg RAE/die cronici) — tossicità epatica, teratogenicità.'},
deficit_vitamina_c:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2013. RDA Vitamina C: 80-90 mg/die. Scorbuto: vitamina C 300-1000 mg/die per 30-60 giorni, poi mantenimento. Fonti: peperoni crudi (190mg/100g), kiwi (93mg), fragole (58mg), agrumi. Termolabile: preferire cruda o cottura breve. Fumo: +35 mg/die. Assorbimento ferro non-eme: abbinare sempre con vitamina C.'},
deficit_vitamina_e:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2015. RDA Vitamina E: 12 mg α-TE/die. Deficit quasi sempre da malassorbimento lipidico. Integratori: 200-400 mg/die α-tocoferolo. Fonti: germe di grano, oli di semi, mandorle, nocciole. Assunzione con grassi. Evitare supplementi >800 mg/die (effetto anticoagulante).'},
deficit_vitamina_k:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2017. RDA Vitamina K: 70 µg/die. K1 (verdure verdi), K2 (fermentati, natto). Antibiotici prolungati: rischio deficit — monitorare PT/INR. In warfarin: mantenere introito K1 STABILE non eliminare. Supplementazione K1 per os nei deficit da malassorbimento.'},
deficit_niacina:{kcal:'25-35 kcal/kg',prot:'1.2-1.5 g/kg',note:'WHO 2000. RDA Niacina: 16 mg NE/die (M), 14 mg NE/die (F). Pellagra: nicotinamide 100-300 mg/die per os fino a remissione. Fonti: carne, pesce, fegato, lievito di birra, arachidi. Mais non nixtamalizzato: niacina legata non biodisponibile. Alcolismo: causa principale in paesi sviluppati.'},
deficit_riboflavina:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2017. RDA Riboflavina: 1.6 mg/die (M), 1.3 mg/die (F). Supplementazione: 10-30 mg/die. Fonti: fegato (2.9mg/100g), latticini, uova. Fotosensibile: conservare latte in contenitori opachi. Spesso coesistente con deficit B6 e folati.'},
deficit_biotina:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2014. AI Biotina: 40 µg/die. Avidina (albume crudo) blocca assorbimento — cuocere sempre le uova. NP senza biotina: supplementare 0.1-0.3 mg/die. Biotinidasi deficiency: 5-20 mg/die. Antiepilettici: monitorare e supplementare 10-20 mg/die se necessario.'},
deficit_magnesio:{kcal:'25-35 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2015. RDA Mg: 300-350 mg/die. Target sierico: 0.8-1.0 mmol/L. Ipomagnesemia sintomatica <0.5 mmol/L: EV urgente. Supplementazione orale: ossido/citrato 300-400 mg/die. PPI e tiazidici: aumentano perdite renali. Diabete e alcolismo: cause frequenti. Ipopotassiemia refrattaria: spesso da ipomagnesemia — correggere Mg prima.'},
deficit_calcio:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2015. RDA Ca: 1000-1200 mg/die. Ipocalcemia acuta grave: gluconato di calcio EV. Ipoparatiroidismo: calcio 1-2 g/die + calcitriolo 0.25-0.5 µg/die. Vitamina D essenziale per assorbimento intestinale. Ossalati (spinaci) e fitati (cereali integrali) riducono assorbimento — diversificare fonti. Non assumere contemporaneamente a ferro.'},
deficit_rame:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'EFSA 2015. RDA Rame: 1.3-1.5 mg/die. Cupremia normale: 12-22 µmol/L. Supplementazione: cuprismo solfato 2 mg/die per os. Eccesso zinco >50mg/die → blocca assorbimento rame — ridurre zinco. Chirurgia bariatrica: monitorare ogni 6-12 mesi. Neuropatia da deficit rame simile a deficit B12 — escludere.'},
omocistinuria:{kcal:'25-35 kcal/kg',prot:'0.8-1.5 g/kg (quota naturale limitata)',note:'ESIEM 2022. B6-responsive: piridossina 100-1000 mg/die, folati, B12. Non-responsive: dieta bassa in metionina + formula senza metionina + betaina 3-6 g/die. Target omocisteina: <50 µmol/L (non-responsive), <30 (B6-resp). Tromboprofilassi. Densità ossea: DXA ogni 2-3 anni.'},
glicogenosi_iii:{kcal:'25-35 kcal/kg',prot:'1.5-2.0 g/kg (alta per protezione muscolare)',note:'ESIEM 2023. Cornstarch cruda 0.5-1 g/kg ogni 4-6h. Digiuno: mai >4-6h. Proteine elevate per massa muscolare. CHO complessi preferiti. No limite lipidi (diversamente da GSD I). Monitorare glicemia pre e post pasti. Lattato non elevato (diferisce da GSD I). Cardiomiopatia: ECG periodici.'},
glicogenosi_v:{kcal:'30-40 kcal/kg (aumentato)',prot:'1.2-1.7 g/kg',note:'Quinlivan 2010. Saccarosio 30-40g pre-esercizio (5-10 min prima). Fruttosio: non utile. CHO: 55-65% energia totale. Evitare esercizio anaerobico intenso (rabdomiolisi). Creatina 1-3 g/die in alcuni pazienti. Idratazione: fondamentale per prevenire mioglobinuria. Controllare CK dopo esercizio.'},
acidemia_propionica:{kcal:'100-120% RDA età',prot:'<1.0 g/kg naturale + formula specifica',note:'Baumgartner 2014 JIMD. Formula senza AA propiogenici. Carnitina 50-100 mg/kg/die. Biotina 10 mg/die. Proteine naturali: 0.3-0.8 g/kg/die (minima tolleranza). Emergenza: sospendere proteine 24-48h, glucosio EV. Propionato target: <200 µmol/L. Trapianto epatico in casi refrattari.'},
malattia_gaucher:{kcal:'25-30 kcal/kg',prot:'1.2-1.5 g/kg',note:'Gaucher Alliance 2022. Calcio 1000-1200 mg/die, vitamina D 1000-2000 UI/die per osteoporosi. Ferro: apporto adeguato (anemia), monitorare ferritina. TES (imiglucerasi/velaglucerasi): trattamento principale. Peso sano: evitare sovraccarico epatico-splenico. No sport di contatto con splenomegalia.'},
esofagite_eosinofila:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'AGREE 2022. SFED (6 food elimination): latte, grano, uova, soia, frutti di mare, noci/arachidi per 6-8 settimane. Step-up: eliminare 2 (latte+grano) poi sequenziale. Reintroduzione: un alimento ogni 6-8 settimane con biopsia. PPI 40-80 mg/die trial preventivo. Formula elementare in casi gravi (100% remissione).'},
dieta_chetogenica:{kcal:'25-35 kcal/kg (calcolare con dietista)',prot:'1.0-1.5 g/kg',note:'ILAE/Charlie Foundation 2022. Rapporto 4:1 (grassi:CHO+prot) o 3:1. CHO: <10-20g/die. Chetoni ematici target: 2-5 mmol/L β-idrossibutirrato. Supplementi obbligatori: multimineral, Ca, vit D, B-complex. Elettroliti: Na, K, Mg. Monitorare: lipidi sierici, valori renali, crescita (bambini). MCT-KD e MAD come varianti meno restrittive.'},
dieta_dash:{kcal:'1800-2200 kcal (adattare a peso)',prot:'0.8-1.0 g/kg',note:'NHLBI 2021. Sodio: max 2300 mg/die (obiettivo 1500 mg/die). Frutta+verdura: 8-10 porzioni/die. Latticini low-fat: 2-3 porzioni/die. Cereali integrali: 7-8 porzioni/die. Carni magre: ≤2 porzioni/die. Noci/semi: 4-5 porzioni/settimana. Zuccheri aggiunti: max 5 porzioni/settimana. Riduzione sistolica: 8-14 mmHg in ipertesi.'},
dieta_antiinfiammatoria:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'Calder 2017. Omega-3 (EPA+DHA): 2-4 g/die da pesce grasso o supplementi. Curcumina con piperina: biodisponibilità aumentata 2000%. Polifenoli da frutta colorata, tè verde, cacao >85%. Ridurre Omega-6 (oli di semi industriali). ELIMINARE: UPF, zuccheri raffinati, alcol. PCR come biomarker di monitoraggio.'},
prevenzione_oncologica:{kcal:'25-30 kcal/kg (normopeso)',prot:'0.8-1.0 g/kg',note:'WCRF/AICR 2018/2023. Pianta vs animale: 2/3 del piatto da vegetali. Carne rossa: max 350-500g/settimana cotta. Carne processata: ZERO. Alcol: ZERO (ogni dose è cancerogena IARC Gruppo 1). BMI 18.5-24.9. Attività fisica: 150 min/settimana. Fibre: 30g/die. Supplementi: NON raccomandati per prevenzione.'},
cachessia_oncologica:{kcal:'25-30 kcal/kg (peso attuale)',prot:'1.2-2.0 g/kg',note:'Fearon 2011/ESPEN 2021. EPA (acido eicosapentaenoico): 2-4 g/die. Proteine: 1.2-2.0 g/kg/die distribuite in tutti i pasti. ONS: 400-600 kcal aggiuntive/die. Pasti piccoli e frequenti (5-6/die). NON aspettarsi aumento peso in cachessia refrattaria. Consistenza adattata. Trattare nausea e mucositi che limitano l\'introito.'},
sindrome_lisi_tumorale:{kcal:'25-35 kcal/kg (adeguato)',prot:'0.8-1.2 g/kg',note:'Howard 2011/EMA 2023. EMERGENZA: gestione ospedaliera. Idratazione EV: 3000 ml/m²/die. Dieta: potassio <40 mEq/die; fosforo <800 mg/die; purine basse. Allopurinolo/rasburicase. No diuretici risparmiatori K. Monitoraggio: K, P, Ca, UA ogni 4-8h durante chemio. Dieta restrittiva solo nelle prime 48-72h di chemio ad alto rischio.'},
artrite_idiopatica_giovanile:{kcal:'100-110% RDA per età (crescita)',prot:'1.0-1.5 g/kg/die',note:'EULAR/ACR 2019. Calcio: 1000-1300 mg/die secondo età. Vitamina D: 600-1000 UI/die, supplementare se <30 ng/ml. Omega-3: EPA+DHA 2-3 g/die (piccolo effetto antiinfiammatorio). Acido folico 5mg/settimana con MTX. Monitorare ferritina, Hb per anemia da malattia cronica. Curva di crescita ogni 3-6 mesi.'},
sport_endurance:{kcal:'40-70 kcal/kg (volume dipendente)',prot:'1.2-1.7 g/kg',note:'ISSN 2021/ACSM 2022. CHO: 7-10 g/kg/die in allenamento intenso; 10-12 g/kg carbo-loading 36-48h pre-gara. Durante gara: 30-60g CHO/h (fino a 90g/h con glucosio+fruttosio in rapporto 2:1). Sodio: essenziale in gare >2h. Proteine post-allenamento: 0.3-0.4 g/kg entro 30 min. Creatine non utile. Caffè 3-6 mg/kg pre-gara.'},
sport_forza:{kcal:'30-50 kcal/kg (obiettivo dipendente)',prot:'1.6-2.2 g/kg (2.5-3.1 g/kg in ipocalorica)',note:'ISSN 2022/Phillips 2016. Proteine: distribuire 4 pasti da 0.4 g/kg. Leucina: 2-3g per pasto per attivare MPS. Creatina monoidrato: 3-5 g/die. CHO: 4-6 g/kg/die. Post-workout: CHO 1-1.2 g/kg + Prot 0.3-0.4 g/kg entro 30-60 min. Deficit per dimagrimento: -300-500 kcal/die. Surplus per massa: +300-500 kcal/die.'},
lipodistrofia:{kcal:'25-30 kcal/kg',prot:'1.0-1.2 g/kg',note:'Akinci 2022. TG target: <500 mg/dl. Omega-3 EPA+DHA 4-6 g/die riducono TG del 30-40%. Eliminare: alcol, zuccheri semplici, grassi saturi e trans. CHO: preferire complessi a basso IG. Distribuzione pasti: 5-6/die per evitare picchi glicemici. Insulino-resistenza severa: spesso necessaria insulina o metformina oltre alla dieta.'},
sindrome_gilbert:{kcal:'25-30 kcal/kg',prot:'1.0 g/kg',note:'Bosma 1995. Benigna — nessun trattamento specifico. Evitare digiuni >12-14h: aumentano bilirubina libera. Pasti regolari ogni 4-5h. Alcol: limitare fortemente. Farmaci: informare medico di Gilbert (irinotecano, nilotinib, atazanavir metabolizzati meno bene). Paracetamolo in dosi normali: sicuro. Nessuna restrizione dietetica permanente.'},
iperfosfatemia:{kcal:'25-30 kcal/kg',prot:'0.8-1.0 g/kg (limitare per ridurre carico P)',note:'KDIGO 2017. Fosforo target (dialisi): 3.5-5.5 mg/dl. Fosforo dieta: <800-1000 mg/die. ELIMINARE: additivi fosfato (PHOS-) in UPF, cola. Ridurre drasticamente: latticini, noci, semi. Preferire: albumi, riso, pasta bianca, verdure. Chelanti del fosforo: SEMPRE con i pasti — non pre o post. Dialisi adeguata: complementare alla dieta.'},
nutrizione_geriatrica_rsa:{kcal:'30-35 kcal/kg',prot:'1.2-1.5 g/kg',note:'ESPEN 2020/SINPE 2021. Screening: MNA-SF ogni 3 mesi. Disfagia: GUSS e VFSS, texture IDDSI. Vitamina D: 800-2000 UI/die (quasi universalmente carente). B12: monitorare e supplementare. ONS: 400-600 kcal 2x/die se MNA <12. Idratazione: 30 ml/kg/die, offrire ogni 2h. Densificanti proteici: aggiungere a tutti i pasti.'},
anemia_emolitica:{kcal:'25-35 kcal/kg',prot:'1.2-1.5 g/kg',note:'ASH 2018. Folati: 1-5 mg/die (eritropoiesi accelerata consuma folati). B12: monitorare e supplementare se carente. Vitamina E: 100-400 UI/die (protegge membrane eritrocitarie). Ferro: CAUTELA — l\'emolisi cronica causa sovraccarico di ferro. NON supplementare senza sideremia e ferritina. G6PD: eliminare fave, piselli freschi, farmaci ossidanti. Alcol: eliminare.'},
  allergia_soia:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die (sostituire soia con carni, pesce, uova, legumi)',note:'EAACI 2019. Eliminazione completa soia e derivati (tofu, tempeh, miso, latte di soia). Lecitina di soia (E322) spesso tollerata — valutare individualmente. Cross-reattività arachidi: test allergenico. Adrenalina auto-iniettabile se anafilassi.'},
  allergia_sedano:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EAACI 2019. Eliminare sedano, sedano rapa, semi di sedano. Dado da brodo industriale quasi sempre con sedano. Sindrome betulla-sedano-carota: cross-reattività apiaceae. Sedano rapa cotto: ancora allergenico (LTP termoresistente).'},
  allergia_senape:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'EAACI 2019. Eliminare senape in tutte le forme. Maionese industriale contiene quasi sempre senape. Curry in polvere spesso con senape. Cross-reattività colza. Soglia reattiva bassa — lettura etichette obbligatoria.'},
  allergia_lupino:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'EAACI 2019. Eliminare farina di lupino, semi tostati, pasta di lupino. ALTA cross-reattività arachidi (30-50%): test lupino obbligatorio in allergici arachidi. Crescente presenza in prodotti da forno biologici/vegani.'},
  allergia_solfiti:{kcal:'Normocalorica',prot:'1.0 g/kg/die',note:'FDA/EAACI 2019. Evitare vino, frutta secca commerciale, gamberi/crostacei, succhi industriali, cibi in scatola. E220-E228 = solfiti: evidenziati per legge UE. Asmatici: rischio broncospasmo — broncodilatatore sempre disponibile.'},
  diabete_lada:{kcal:'25-35 kcal/kg/die (peso ideale)',prot:'1.0-1.2 g/kg/die',note:'ADA/EASD 2023. Come diabete T1: basso IG, CHO costanti e distribuiti. Anti-GAD+/anti-IA2+: progressione verso insulino-dipendenza 5-10 anni. Monitorare C-peptide. HbA1c target <7%. Metformina possibile ma monitorare C-peptide.'},
  tumore_rene:{kcal:'25-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Idratazione ≥2L. Monitorare funzione renale residua (GFR dopo nefrectomia). In TKI (sunitinib): nausea, mucosite, ipertensione, ipotiroidismo. In immunoterapia: colite immuno-mediata possibile. Peso settimanale.'},
  tumore_tiroide:{kcal:'Normocalorica (aumentare post-chirurgia)',prot:'1.0-1.2 g/kg/die',note:'ETA/ATA 2021. LID pre-I131: iodio <50µg/die per 2-4 settimane. Post-tiroidectomia: Ca 1000-1500mg/die + Vit.D 800-2000 UI/die (ipoparatiroidismo). Soia: assumere distante da levotiroxina (≥2-4 ore). Alghe: vietate.'},
  tumore_ovaio:{kcal:'25-35 kcal/kg/die (30-40 se cachessia)',prot:'1.2-2.0 g/kg/die',note:'ESPEN 2021. Cachessia nel 60-80% dei casi avanzati. Ascite: pasti piccoli (6/die), ridurre volume liquidi se abbondante. Omega-3 EPA 2g/die anti-cachessia. In neutropenia: dieta a basso contenuto batterico. ONS se intake <60%.'},
  anemia_megaloblastica:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'BSH 2014. ATTENZIONE: non supplementare folati senza escludere deficit B12 (rischio danni neurologici irreversibili). Anemia perniciosa: B12 IM 1000µg/die. Vegani: B12 orale 1000µg/die. Metformina: monitorare B12 annualmente.'},
  morbo_crohn:{kcal:'25-35 kcal/kg/die (35-40 in cachessia)',prot:'1.2-1.5 g/kg/die',note:'ECCO/ESPEN 2023. Nutrizione enterale esclusiva: efficace come corticosteroidi (1 kcal/ml, 2000-3000 kcal/die per 6-8 settimane). CDED (dieta ad esclusione del Crohn): frumento, carne rossa, latticini grassi limitati. In stenosi: fibre insolubili ridotte. Monitorare Fe, B12, vitamina D, Zn.'},
  colite_ulcerosa:{kcal:'Normocalorica (25-30 kcal/kg/die)',prot:'1.2-1.5 g/kg/die',note:'ECCO/ESPEN 2023. In riacutizzazione: bassa fibra, basso residuo. In remissione: dieta mediterranea. Fe per anemia da perdita ematica. Acido folico se sulfasalazina (inibisce assorbimento folati). Omega-3 EPA/DHA come adiuvanti anti-infiammatori.'},
  ipotiroidismo:{kcal:'Normocalorica (ridotta se sovrappeso)',prot:'1.0-1.2 g/kg/die',note:'ETA/ATA 2021. Levotiroxina a digiuno (30-60 min ante-prandiale). Distanziare almeno 2-4 ore da: soia, calcio, ferro, colestiramina, PPI. Seleno 200µg/die (noci del Brasile: 1-2/die). Alghe: evitare (eccesso iodio). Vitamina D spesso carente.'},
  feocromocitoma:{kcal:'Normocalorica o ipocalorica post-op',prot:'1.0-1.2 g/kg/die',note:'ENSAT 2023. Pre-operatorio: sodio adeguato, idratazione. Evitare tiramina (fermentati, alcol, formaggi stagionati) se residuo tumorale. Post-op: rischio ipoglicemia reattiva — pasti frequenti, monitoraggio glicemico. Calcio e Mg se ipoaldosteronismo post-adrenalectomia.'},
  apnea_sonno:{kcal:'Deficit 500-750 kcal/die (se BMI >25)',prot:'1.2-1.5 g/kg/die',note:'AASM 2023. Perdita di peso 10% riduce AHI del 26%. Eliminare alcol (peggiora apnee). Pasti serali piccoli e leggeri. Vitamina D (spesso carente e correlata alla severità). Omega-3 anti-infiammatori. Magnesio per qualità del sonno.'},
  tumore_vescica:{kcal:'25-35 kcal/kg/die',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Post-cistectomia radicale con ileo-condotto: monitorare B12 ogni anno e supplementare (B12 IM profilattico). In chemioterapia sistemica: gestire nausea (pasti piccoli, cibi freddi, zenzero). Idratazione ≥2.5L/die. Omega-3 EPA/DHA anti-cachessia.'},
  tumore_esofago:{kcal:'30-40 kcal/kg/die (malnutrizione severa frequente)',prot:'1.5-2.0 g/kg/die',note:'ESPEN 2021. Disfagia: adattare consistenza (IDDSI Framework). Nutrizione enterale nasodigiunale pre-operatoria. Post-esofagectomia: 6-8 piccoli pasti/die, decubito semieretto 2h dopo pasto (dumping, reflusso). ONS iperproteici. Vitamina D, B12, Mg spesso carenti.'},
  tumore_endometrio:{kcal:'25-30 kcal/kg/die (ipocalorica se obesa)',prot:'1.2-1.5 g/kg/die',note:'ESPEN 2021. Obesità presente nel 40-50%: calo ponderale migliora outcomes e risposta terapeutica. Post-radioterapia pelvica: diarrea e proctite — dieta a bassa fibra, basso lattosio. Vitamina D e Ca se inibitori aromatasi (rischio osteoporosi). Acido folico in chemioterapia.'},
  policitemia_vera:{kcal:'Ipocalorica se BMI>25 (deficit 500 kcal/die)',prot:'1.0-1.2 g/kg/die',note:'ELN 2021. Idratazione ≥2L/die (riduce viscosità ematica). Ferro: NON integrare (stimola eritropoiesi patologica — attenzione a ridurre alimenti ricchissimi di ferro). Alcol: evitare. Fibre abbondanti. Omega-3 antitrombotico. Vitamina K stabile se in anticoagulazione.'},
  arfid:{kcal:'Adeguata alla crescita e all\'età (spesso carente)',prot:'1.0-1.2 g/kg/die (aumentare se crescita insufficiente)',note:'DSM-5 2013 / NICE 2017. Food chaining: introduzione graduale di varianti accettate del cibo tollerato. ONS se intake insufficiente per la crescita. Monitorare: vitamina D, Fe, Zn, B12, Ca. Approccio multidisciplinare. Mai forzare o punire riguardo al cibo.'},
  pots:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'ESC 2022. Sale extra 5-10g NaCl/die (espande volume ematico). Liquidi 2.5-3.5L/die. Pasti piccoli e frequenti (evitare pooling splacnico post-prandiale). Caffeina utile (10mg/kg/die). Alcol: evitare. Compressione arti inferiori. Attività fisica graduale in posizione orizzontale.'},
  neuropatia_periferica:{kcal:'Normocalorica o adattata alla causa',prot:'1.0-1.2 g/kg/die',note:'EFNS 2020. Neuropatia diabetica: controllo glicemico HbA1c <7%, vitamina D, omega-3. Da deficit B12: supplementazione orale o IM (1000µg/die). Alcolica: tiamina 100mg/die + multivitaminico. Acido alfa-lipoico 600mg/die (evidenza per neuropatia diabetica). Glutammina in neuropatia da chemio.'},
  epatite_b_cronica:{kcal:'Normocalorica (30-35 se cirrosi)',prot:'1.2-1.5 g/kg/die (1.0 se encefalopatia)',note:'EASL 2023. Alcol: astinenza assoluta. Peso normale (MASLD co-esistente peggiora prognosi). Caffeina 2-3 tazze/die: riduce fibrosi e HCC. Vitamina D (monitorare e supplementare se <30 ng/ml). Zinco spesso carente. Evitare cibi crudi se cirrosi (rischio Listeria, Salmonella).'},
  epatite_c_cronica:{kcal:'Normocalorica (ipocalorica se BMI>25)',prot:'1.2-1.5 g/kg/die',note:'EASL 2024. DAA: nessuna restrizione alimentare significativa (evitare pompelmo con alcuni DAA). Alcol: evitare durante terapia e dopo (accelera fibrosi residua). Post-SVR: monitorare MASLD e insulino-resistenza. Caffeina: riduce fibrosi. Vitamina D e ferro spesso alterati.'},
  intolleranza_sorbitolo:{kcal:'Normocalorica',prot:'1.0-1.2 g/kg/die',note:'SGAMN 2018. Eliminare sorbitolo e polioli: frutta a nocciolo (prugne, pesche, albicocche, ciliegie), mele, pere, funghi. Leggere etichette: E420 (sorbitolo), E421 (mannitolo), E953 (isomalto), E965 (maltitolo), E966 (lactitolo), E967 (xilitolo). Spesso parte del protocollo FODMAP.'}
};
